  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t1, 11, 'story', 'mcq', 'ARIA says: "What is 0 OR 0?"', '["0","1","2","Depends"]', '0', 'OR only gives 1 if at least one input is 1. Both are 0 here, so the result is 0.', true),
  (t1, 12, 'story', 'mcq', 'ARIA''s magic gate flips every answer: FALSE becomes TRUE and TRUE becomes FALSE. What gate is this?', '["AND gate","OR gate","NOT gate","XOR gate"]', 'NOT gate', 'The NOT gate is an inverter — it flips the input value to its opposite.', true),
  (t1, 13, 'story', 'mcq', 'ARIA says two friends can enter the clubhouse only if BOTH know the secret password. Which gate matches this rule?', '["OR gate","AND gate","NOT gate","NAND gate"]', 'AND gate', 'AND requires ALL inputs to be TRUE — both friends must know the password.', true),
  (t1, 14, 'story', 'mcq', 'A NAND gate is like an AND gate with a surprise twist. What does NAND do?', '["Same as AND","Opposite of AND","Same as OR","Opposite of OR"]', 'Opposite of AND', 'NAND = NOT AND. It gives the flipped result of AND — so 1 AND 1 would give 0.', true),
  (t1, 15, 'story', 'mcq', 'ARIA has a light that turns on when EITHER button A OR button B is pressed, but NOT both at the same time. Which gate is this?', '["AND gate","OR gate","XOR gate","NOR gate"]', 'XOR gate', 'XOR (Exclusive OR) is TRUE only when inputs are DIFFERENT — one on, one off.', true),
  (t1, 16, 'story', 'mcq', 'In robot-land, TRUE equals which number?', '["0","1","2","10"]', '1', 'In Boolean logic, TRUE is represented by 1 and FALSE by 0.', true),
  (t1, 17, 'story', 'mcq', 'ARIA draws a table showing every possible TRUE/FALSE combination for a gate. What is this table called?', '["A recipe","A truth table","A score sheet","A map"]', 'A truth table', 'A truth table lists all possible input combinations and the resulting output for a logic gate.', true),
  (t1, 18, 'story', 'mcq', 'A NOR gate outputs TRUE only when:', '["Both inputs are TRUE","At least one input is TRUE","Both inputs are FALSE","One input is TRUE"]', 'Both inputs are FALSE', 'NOR = NOT OR. It only gives TRUE when the OR result would be FALSE — meaning both inputs must be 0.', true),
  (t1, 19, 'story', 'mcq', 'ARIA says: "What is NOT 0?"', '["0","1","2","NULL"]', '1', 'NOT flips the value. NOT 0 = 1, just like NOT FALSE = TRUE.', true),
  (t1, 20, 'story', 'mcq', 'ARIA''s door lock uses an OR gate. The door opens if key A OR key B is used. Key B is used. Does the door open?', '["No","Yes","Only if key A is also used","Cannot tell"]', 'Yes', 'OR only needs ONE input to be TRUE. Key B being used is enough to open the door.', true),
  (t1, 21, 'story', 'mcq', 'George Boole invented a special kind of maths with only two values. What are those two values?', '["Big and Small","True and False","Hot and Cold","Fast and Slow"]', 'True and False', 'Boolean algebra, invented by George Boole, works with only two values: TRUE (1) and FALSE (0).', true),
  (t1, 22, 'story', 'mcq', 'ARIA has three AND gates in a row. The first two outputs feed into the third. If any single input is FALSE, what is the final output?', '["TRUE","FALSE","Maybe","Depends on position"]', 'FALSE', 'AND requires ALL inputs to be TRUE. One FALSE anywhere in a chain of ANDs makes the whole result FALSE.', true),
  (t1, 23, 'story', 'mcq', 'An XOR gate has inputs 1 and 1. What is the output?', '["0","1","2","Undefined"]', '0', 'XOR gives 1 only when inputs are DIFFERENT. When both are 1 (same), the output is 0.', true),
  (t1, 24, 'story', 'mcq', 'ARIA says: "My robot arms move only when the power is ON and the safety switch is OFF. Which gates do I need?"', '["Two OR gates","AND gate + NOT gate","Two NOT gates","One XOR gate"]', 'AND gate + NOT gate', 'We need NOT to flip the safety switch signal, then AND to combine power ON with safety OFF.', true),
  (t1, 25, 'story', 'mcq', 'How many inputs does a NOT gate have?', '["0","1","2","3"]', '1', 'A NOT gate has exactly one input and one output — it simply flips that single value.', true),
  (t1, 26, 'story', 'mcq', 'ARIA says: "0 AND 1 equals...?"', '["0","1","2","0 or 1"]', '0', 'AND needs BOTH inputs to be 1. Since one input is 0, the result is 0.', true),
  (t1, 27, 'story', 'mcq', 'Which gate would ARIA use to check if exactly one of two robots is dancing (not both, not neither)?', '["AND gate","OR gate","XOR gate","NOR gate"]', 'XOR gate', 'XOR is TRUE only when inputs differ — exactly one TRUE, one FALSE.', true),
  (t1, 28, 'story', 'mcq', 'ARIA builds a circuit. The output is always 0 no matter what the input is. Which gate could do this?', '["AND gate with one input always 0","OR gate","NOT gate","XOR gate with both inputs same"]', 'AND gate with one input always 0', 'If one input to an AND gate is always 0, the output will always be 0 regardless of the other input.', true),
  (t1, 29, 'story', 'mcq', 'ARIA says: "NOT(NOT(TRUE)) equals...?"', '["FALSE","TRUE","NULL","0"]', 'TRUE', 'Applying NOT twice cancels out — it''s like flipping a switch twice, returning to the original value.', true),
  (t1, 30, 'story', 'mcq', 'An OR gate with inputs 0 and 0 outputs...?', '["1","0","Depends","2"]', '0', 'OR outputs 1 only if at least one input is 1. Both inputs are 0, so the output is 0.', true),
  (t1, 31, 'story', 'mcq', 'ARIA''s NAND gate has inputs 0 and 0. What is the output?', '["0","1","2","Error"]', '1', 'NAND is NOT AND. AND(0,0)=0, then NOT(0)=1. NAND outputs 1 for all inputs except both-1.', true),
  (t1, 32, 'story', 'mcq', 'Which gate is the "grumpy" version of OR — it only likes when BOTH inputs are 0?', '["AND","NAND","NOR","XOR"]', 'NOR', 'NOR (NOT OR) outputs 1 only when all inputs are 0. It is like a strict guard that hates any activity.', true),
  (t1, 33, 'story', 'mcq', 'ARIA wants to build a gate that ALWAYS outputs the opposite of what she puts in. She needs:', '["AND gate","OR gate","NOT gate","XOR gate"]', 'NOT gate', 'The NOT gate always inverts its single input — TRUE becomes FALSE, FALSE becomes TRUE.', true),
  (t1, 34, 'story', 'mcq', 'How many different outputs can a single Boolean variable have?', '["1","2","4","Infinite"]', '2', 'A Boolean variable can only be TRUE (1) or FALSE (0) — exactly two possible values.', true),
  (t1, 35, 'story', 'mcq', 'ARIA''s XOR gate has inputs 0 and 1. What is the output?', '["0","1","2","Undefined"]', '1', 'XOR gives 1 when inputs are DIFFERENT. 0 and 1 are different, so the output is 1.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t1, 11, 'levels', 'mcq', 'De Morgan''s Law states that NOT(A AND B) equals:', '["NOT A AND NOT B","NOT A OR NOT B","A OR B","NOT(A OR B)"]', 'NOT A OR NOT B', 'De Morgan''s first law: NOT(A AND B) = NOT A OR NOT B. The AND flips to OR when NOT is distributed.', true),
  (t1, 12, 'levels', 'mcq', 'Apply De Morgan''s Law to NOT(A OR B):', '["NOT A OR NOT B","NOT A AND NOT B","A AND B","NOT A AND B"]', 'NOT A AND NOT B', 'De Morgan''s second law: NOT(A OR B) = NOT A AND NOT B. The OR flips to AND when NOT is distributed.', true),
  (t1, 13, 'levels', 'mcq', 'Which Boolean law states A OR (A AND B) = A?', '["Idempotent Law","Absorption Law","Complement Law","Distributive Law"]', 'Absorption Law', 'The Absorption Law: A OR (A AND B) = A. The longer term is absorbed by the simpler one.', true),
  (t1, 14, 'levels', 'mcq', 'Simplify: A AND 0', '["A","0","1","NOT A"]', '0', 'Identity/Annihilation Law: anything ANDed with 0 equals 0, since 0 can never be overridden in AND.', true),
  (t1, 15, 'levels', 'mcq', 'A NAND gate is described as "universal" because:', '["It is used in every computer","All other logic gates can be built from NAND gates alone","It has the most inputs","It is the fastest gate"]', 'All other logic gates can be built from NAND gates alone', 'NAND is functionally complete — AND, OR, NOT, and any combination can be constructed using only NAND gates.', true),
  (t1, 16, 'levels', 'mcq', 'Simplify: A OR 1', '["A","0","1","NOT A"]', '1', 'Annihilation Law: anything ORed with 1 equals 1, because 1 always wins in OR.', true),
  (t1, 17, 'levels', 'mcq', 'How many rows does a truth table need for a 3-input logic circuit?', '["3","6","8","16"]', '8', 'With 3 inputs each having 2 states, there are 2³ = 8 possible input combinations.', true),
  (t1, 18, 'levels', 'mcq', 'Which law allows: A AND (B OR C) = (A AND B) OR (A AND C)?', '["Commutative Law","Associative Law","Distributive Law","Absorption Law"]', 'Distributive Law', 'The Distributive Law allows AND to be distributed over OR, similar to multiplication over addition.', true),
  (t1, 19, 'levels', 'mcq', 'A half adder computes the Sum of two bits using which gate?', '["AND gate","OR gate","XOR gate","NAND gate"]', 'XOR gate', 'XOR produces 1 when inputs differ, which matches binary addition where 1+1 wraps around to 0 with a carry.', true),
  (t1, 20, 'levels', 'mcq', 'Simplify: NOT(NOT A)', '["0","1","A","NOT A"]', 'A', 'Double Negation Law: applying NOT twice returns the original value. NOT(NOT A) = A.', true),
  (t1, 21, 'levels', 'mcq', 'Which law states A AND A = A?', '["Complement Law","Idempotent Law","Identity Law","Absorption Law"]', 'Idempotent Law', 'Idempotent Law: A AND A = A and A OR A = A. Repeating the same value changes nothing.', true),
  (t1, 22, 'levels', 'mcq', 'What is the output of an XOR gate when both inputs are 1?', '["0","1","Undefined","2"]', '0', 'XOR outputs 1 only when inputs differ. When both are 1 (same), the output is 0.', true),
  (t1, 23, 'levels', 'mcq', 'NOR is the universal gate equivalent of NAND. Which statement is TRUE?', '["NOR can only build OR gates","Any logic function can be built using only NOR gates","NOR is faster than NAND","NOR requires three inputs"]', 'Any logic function can be built using only NOR gates', 'Like NAND, NOR is also functionally complete — any Boolean function can be implemented with NOR gates only.', true),
  (t1, 24, 'levels', 'mcq', 'Evaluate: (A AND B) OR (NOT A AND B) when A=0, B=1', '["0","1","A","B"]', '1', 'Substituting: (0 AND 1) OR (NOT 0 AND 1) = 0 OR (1 AND 1) = 0 OR 1 = 1.', true),
  (t1, 25, 'levels', 'mcq', 'What does the Complement Law state about A AND NOT A?', '["It equals A","It equals 1","It equals 0","It equals NOT A"]', 'It equals 0', 'Complement Law: A AND NOT A = 0. A variable ANDed with its inverse is always FALSE.', true),
  (t1, 26, 'levels', 'mcq', 'Which expression is a sum-of-products (SOP) form?', '["(A+B)(C+D)","AB + CD","NOT(A+B)","A(B+CD)"]', 'AB + CD', 'SOP (Sum of Products) is a Boolean expression that is an OR of AND terms, like AB + CD.', true),
  (t1, 27, 'levels', 'mcq', 'The Associative Law for OR states:', '["A OR (B OR C) = (A OR B) OR C","A OR B = B OR A","A OR (B AND C) = (A OR B) AND C","A OR A = A"]', 'A OR (B OR C) = (A OR B) OR C', 'The Associative Law says grouping does not matter — you can regroup OR or AND operations freely.', true),
  (t1, 28, 'levels', 'mcq', 'In a truth table, how is FALSE typically represented?', '["F","No","0","Both 0 and F depending on context"]', '0', 'In standard Boolean/digital notation, FALSE is represented as 0 and TRUE as 1.', true),
  (t1, 29, 'levels', 'mcq', 'Simplify: A OR (NOT A AND B)', '["B","A OR B","A AND B","NOT A"]', 'A OR B', 'Using the Absorption variant: A OR (NOT A AND B) = A OR B. This is a standard Boolean simplification.', true),
  (t1, 30, 'levels', 'mcq', 'What is the Carry output of a half adder implemented with which gate?', '["XOR","OR","AND","NAND"]', 'AND', 'In a half adder, the Carry bit is 1 only when both inputs are 1 — exactly what an AND gate computes.', true),
  (t1, 31, 'levels', 'mcq', 'Which Boolean identity is known as the Identity Law for AND?', '["A AND 0 = 0","A AND 1 = A","A AND A = A","A AND NOT A = 0"]', 'A AND 1 = A', 'Identity Law: AND with 1 leaves the value unchanged (A AND 1 = A), just like multiplying by 1.', true),
  (t1, 32, 'levels', 'mcq', 'Simplify: A AND (A OR B)', '["A OR B","A AND B","A","B"]', 'A', 'Absorption Law: A AND (A OR B) = A. The more complex term is absorbed by A.', true),
  (t1, 33, 'levels', 'mcq', 'The Commutative Law for Boolean AND states:', '["A AND B = A OR B","A AND B = B AND A","A AND A = A","NOT(A AND B) = NOT A OR NOT B"]', 'A AND B = B AND A', 'Commutative Law: the order of operands does not change the result in AND or OR operations.', true),
  (t1, 34, 'levels', 'mcq', 'Evaluate: NOT(1 AND 0)', '["0","1","NOT 1","Undefined"]', '1', 'First: 1 AND 0 = 0. Then NOT(0) = 1. NAND(1,0) = 1.', true),
  (t1, 35, 'levels', 'mcq', 'A Boolean expression that is always FALSE is called a:', '["Tautology","Contradiction","Minterm","Maxterm"]', 'Contradiction', 'A contradiction (or unsatisfiable expression) is always FALSE for every possible input combination.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t1, 11, 'sandbox', 'mcq', 'In Python, what does `5 & 3` evaluate to?', '["1","7","2","15"]', '1', 'Bitwise AND: 5 = 0101, 3 = 0011. AND gives 0001 = 1. Each bit is ANDed independently.', true),
  (t1, 12, 'sandbox', 'mcq', 'What is `5 | 3` in Python (bitwise OR)?', '["1","7","2","15"]', '7', 'Bitwise OR: 5 = 0101, 3 = 0011. OR gives 0111 = 7.', true),
  (t1, 13, 'sandbox', 'mcq', 'In Karnaugh map minimization, adjacent cells differ by how many bits?', '["0","1","2","4"]', '1', 'Adjacent K-map cells differ by exactly one bit (Gray code ordering), enabling valid grouping and simplification.', true),
  (t1, 14, 'sandbox', 'mcq', 'Convert -5 to 8-bit two''s complement:', '["10000101","11111011","11111010","10000100"]', '11111011', 'Two''s complement: flip bits of 5 (00000101→11111010) then add 1 = 11111011.', true),
  (t1, 15, 'sandbox', 'mcq', 'Which K-map group size is valid for simplification?', '["3","5","6","4"]', '4', 'Valid K-map groups must be powers of 2: 1, 2, 4, 8, 16. Groups of 3, 5, or 6 are not allowed.', true),
  (t1, 16, 'sandbox', 'mcq', 'Minimise F = A''B''C + A''BC + AB''C + ABC using a K-map:', '["C","A+C","B+C","AC"]', 'C', 'All four minterms contain C=1 regardless of A and B. The K-map groups all four into just C.', true),
  (t1, 17, 'sandbox', 'mcq', 'What is the SOP (Sum of Products) canonical form also called?', '["Maxterm expansion","Minterm expansion","POS form","Reduced form"]', 'Minterm expansion', 'SOP canonical form is also called minterm expansion — each product term is a minterm covering one row.', true),
  (t1, 18, 'sandbox', 'mcq', 'In JavaScript, `!!(0)` evaluates to:', '["true","false","0","undefined"]', 'false', 'The `!!` double-negation coerces to boolean. 0 is falsy in JS, so !!0 = false.', true),
  (t1, 19, 'sandbox', 'mcq', 'What does `~5` produce in Python?', '["-6","-5","4","10"]', '-6', 'Python bitwise NOT (~n) = -(n+1). ~5 = -(5+1) = -6. This is due to two''s complement representation.', true),
  (t1, 20, 'sandbox', 'mcq', 'XOR can be used to swap two variables without a temporary. If a=5, b=3, after `a^=b; b^=a; a^=b`, what are a and b?', '["a=5,b=3","a=3,b=5","a=6,b=2","a=8,b=8"]', 'a=3,b=5', 'XOR swap: a becomes a^b=6, then b becomes b^a(new)=3^6=5, then a becomes a(new)^b(new)=6^5=3.', true),
  (t1, 21, 'sandbox', 'mcq', 'How many prime implicants does F = AB + A''B have?', '["1","2","3","4"]', '2', 'AB and A''B are both prime implicants — neither can be further combined since they differ in A. The result simplifies to B.', true),
  (t1, 22, 'sandbox', 'mcq', 'In a POS (Product of Sums) expression, each sum term corresponds to a:', '["Minterm","Maxterm","Prime implicant","Don''t-care"]', 'Maxterm', 'POS uses maxterms — sum terms that correspond to rows where the function output is 0.', true),
  (t1, 23, 'sandbox', 'mcq', 'Which bitwise operation isolates the lowest set bit of integer n?', '["n & (n-1)","n | (n-1)","n & (-n)","n ^ (n-1)"]', 'n & (-n)', 'n & (-n) isolates the lowest set bit. -n in two''s complement flips bits and adds 1, leaving only the lowest 1-bit.', true),
  (t1, 24, 'sandbox', 'mcq', 'Quine-McCluskey method is an alternative to K-maps. Its main advantage is:', '["Faster for 2-variable functions","Suitable for computer automation with many variables","Produces POS forms only","Requires no truth table"]', 'Suitable for computer automation with many variables', 'Quine-McCluskey is a tabular method that can be automated for functions with many variables where K-maps become impractical.', true),
  (t1, 25, 'sandbox', 'mcq', 'What is the result of `0xFF & 0x0F` in hex?', '["0xFF","0x0F","0xF0","0x00"]', '0x0F', 'AND masks: 11111111 & 00001111 = 00001111 = 0x0F. This is a common bit-masking technique.', true),
  (t1, 26, 'sandbox', 'mcq', 'A "don''t-care" condition in a K-map can be treated as:', '["Always 0","Always 1","Either 0 or 1 to maximize simplification","Must be left blank"]', 'Either 0 or 1 to maximize simplification', 'Don''t-care terms (marked X) can be assigned 0 or 1 to form larger, simpler K-map groups.', true),
  (t1, 27, 'sandbox', 'mcq', 'In two''s complement, the range of values for an 8-bit signed integer is:', '["-127 to 127","-128 to 127","-128 to 128","0 to 255"]', '-128 to 127', 'An 8-bit two''s complement integer ranges from -2^7 = -128 to 2^7 - 1 = 127.', true),
  (t1, 28, 'sandbox', 'mcq', 'Which Python expression checks if bit 3 of variable n is set?', '["n & 8","n | 8","n ^ 8","n >> 3"]', 'n & 8', 'Bit 3 has value 2^3 = 8. ANDing with 8 isolates that bit; a non-zero result means it is set.', true),
  (t1, 29, 'sandbox', 'mcq', 'Simplify using Boolean algebra: A''B + AB'' + AB', '["A + B","A''+ B''","A XOR B","A AND B"]', 'A + B', 'Group AB'' + AB = A, and A''B + AB = B. Combined: A + B. Alternatively, the minterms cover all except A=0,B=0.', true),
  (t1, 30, 'sandbox', 'mcq', 'The operation `n << 1` in most languages is equivalent to:', '["n - 1","n * 2","n / 2","n + 1"]', 'n * 2', 'Left-shifting by 1 bit doubles the value, equivalent to multiplying by 2 (for non-overflow cases).', true),
  (t1, 31, 'sandbox', 'mcq', 'To clear bit k of integer n (set it to 0), which operation is used?', '["n | (1 << k)","n & ~(1 << k)","n ^ (1 << k)","n >> k"]', 'n & ~(1 << k)', 'Create a mask with bit k as 1, invert it (~), then AND to clear that bit while keeping all others unchanged.', true),
  (t1, 32, 'sandbox', 'mcq', 'What is the minimum number of NAND gates needed to implement a NOT gate?', '["1","2","3","4"]', '1', 'A single NAND gate with both inputs tied together acts as a NOT gate: NAND(A,A) = NOT A.', true),
  (t1, 33, 'sandbox', 'mcq', 'In a 4-variable K-map, the maximum group size that simplifies to 0 literals (constant) is:', '["4","8","16","2"]', '16', 'A group of 16 (all cells) means the function equals 1 for all inputs — a tautology with 0 variables.', true),
  (t1, 34, 'sandbox', 'mcq', 'What does `x ^ x` always equal for any integer x?', '["x","1","0","2x"]', '0', 'XOR of any value with itself is always 0 — every bit cancels with its identical counterpart.', true),
  (t1, 35, 'sandbox', 'mcq', 'Which expression uses De Morgan''s Law to implement NOR using only AND and NOT gates?', '["NOT(A AND B)","NOT A AND NOT B","NOT A OR NOT B","NOT(A OR B)"]', 'NOT A AND NOT B', 'NOR(A,B) = NOT(A OR B). By De Morgan''s: NOT(A OR B) = NOT A AND NOT B, implementable with NOTs and AND.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t2, 11, 'story', 'mcq', 'ARIA says: "An algorithm is like a recipe. What is the MOST important rule for a recipe to work?"', '["It must be long","The steps must be in the right order","It must use hard ingredients","It must be written in a book"]', 'The steps must be in the right order', 'Algorithms must have ordered steps — mixing them up changes the result, just like adding eggs before flour changes a cake!', true),
  (t2, 12, 'story', 'mcq', 'ARIA wants to brush her teeth. Which step should come LAST?', '["Put toothpaste on the brush","Rinse your mouth","Brush your teeth","Pick up the toothbrush"]', 'Rinse your mouth', 'Algorithms have a sequence — rinsing happens after brushing, not before.', true),
  (t2, 13, 'story', 'mcq', 'In an algorithm, a step that repeats many times (like stirring 10 times) is called a:', '["Condition","Loop","Decision","Variable"]', 'Loop', 'A loop repeats a set of instructions a number of times or until a condition is met.', true),
  (t2, 14, 'story', 'mcq', 'ARIA''s robot follows instructions one by one. If a step says "if it is raining, take an umbrella", this is a:', '["Loop","Sequence","Decision/condition","Bug"]', 'Decision/condition', 'A decision (or conditional) checks a condition and takes different actions depending on whether it is true or false.', true),
  (t2, 15, 'story', 'mcq', 'ARIA''s algorithm has a mistake and gives the wrong answer. What is this mistake called?', '["A feature","A bug","A loop","A shortcut"]', 'A bug', 'A bug is an error in an algorithm or program that causes it to behave incorrectly.', true),
  (t2, 16, 'story', 'mcq', 'ARIA wants to find her lost sock. She checks one drawer at a time until she finds it. This is called:', '["Sorting","Searching","Looping","Debugging"]', 'Searching', 'Searching is the process of looking through items one by one (or in a pattern) to find a target.', true),
  (t2, 17, 'story', 'mcq', 'Why must an algorithm eventually stop?', '["Computers get bored","Algorithms that run forever are not useful and waste power","Stops are optional","Algorithms never stop"]', 'Algorithms that run forever are not useful and waste power', 'A valid algorithm must terminate — it needs to produce a result and finish within a finite number of steps.', true),
  (t2, 18, 'story', 'mcq', 'ARIA sorts her toy cars from smallest to biggest. She is performing:', '["Searching","Sorting","Looping","Deciding"]', 'Sorting', 'Sorting is the process of arranging items in a particular order (e.g., size, alphabetical, numerical).', true),
  (t2, 19, 'story', 'mcq', 'ARIA''s robot picks up red balls and puts blue balls back. This "check the colour" step is an example of:', '["A loop","A condition","A sort","A variable"]', 'A condition', 'Conditions (if-statements) let an algorithm make decisions based on whether something is true or false.', true),
  (t2, 20, 'story', 'mcq', 'Which word best describes an algorithm that gives the CORRECT answer every time?', '["Fast","Correct","Short","Popular"]', 'Correct', 'Correctness is the most important property of an algorithm — it must solve the problem it was designed for.', true),
  (t2, 21, 'story', 'mcq', 'ARIA has 100 toy blocks to count. She counts them one at a time. If there are MORE blocks, her algorithm takes:', '["Less time","The same time","More time","No time"]', 'More time', 'More items to process means more steps needed — the time an algorithm takes grows with the size of the input.', true),
  (t2, 22, 'story', 'mcq', 'ARIA draws pictures of each step in her algorithm using boxes and arrows. This drawing is called a:', '["Blueprint","Flowchart","Map","Sketch"]', 'Flowchart', 'A flowchart is a diagram that shows the steps of an algorithm using shapes (boxes, diamonds) connected by arrows.', true),
  (t2, 23, 'story', 'mcq', 'In a flowchart, what shape is usually used for a decision (yes/no question)?', '["Rectangle","Circle","Diamond","Triangle"]', 'Diamond', 'Diamonds represent decisions in flowcharts — they have two paths: one for YES and one for NO.', true),
  (t2, 24, 'story', 'mcq', 'ARIA says: "I check if a number is bigger than 10 and print it if so. This is a..."', '["Loop","Conditional statement","Variable","Function"]', 'Conditional statement', 'A conditional (if-statement) executes code only when a certain condition is true.', true),
  (t2, 25, 'story', 'mcq', 'What happens if ARIA''s loop never stops?', '["The program runs faster","The program gets stuck forever","The program jumps to the next step","Nothing changes"]', 'The program gets stuck forever', 'An infinite loop — one without a stopping condition — causes a program to run endlessly without finishing.', true),
  (t2, 26, 'story', 'mcq', 'ARIA wants to greet every student in a class of 30. How should she do it?', '["Write 30 separate greeting steps","Use a loop that runs 30 times","Skip some students","Use a decision"]', 'Use a loop that runs 30 times', 'Loops are perfect for repeating the same action many times — much more efficient than writing each step separately.', true),
  (t2, 27, 'story', 'mcq', 'Decomposition means breaking a BIG problem into:', '["One big step","Smaller easier pieces","Random pieces","Harder pieces"]', 'Smaller easier pieces', 'Decomposition is a key computational thinking skill — breaking complex problems into smaller, manageable sub-problems.', true),
  (t2, 28, 'story', 'mcq', 'ARIA''s algorithm finds the biggest number in a list. After checking all numbers, it should:', '["Start over","Report the biggest number found","Delete the list","Stop without answering"]', 'Report the biggest number found', 'An algorithm must produce an output — the answer or result of the computation.', true),
  (t2, 29, 'story', 'mcq', 'What is an INPUT to an algorithm?', '["The answer","The steps","The information you give it to work with","The computer"]', 'The information you give it to work with', 'An input is the data provided to an algorithm so it can process and produce a result.', true),
  (t2, 30, 'story', 'mcq', 'ARIA notices her sorting algorithm is slow with 1,000 toys but fast with 10 toys. This tells her the algorithm''s speed depends on:', '["The colour of the toys","The size of the input","The room temperature","The time of day"]', 'The size of the input', 'Algorithm efficiency often depends on input size — larger inputs can take much longer to process.', true),
  (t2, 31, 'story', 'mcq', 'ARIA looks for her name in a list sorted A-Z. She opens the MIDDLE of the list first. This smart strategy is called:', '["Linear search","Binary search","Bubble sort","Loop search"]', 'Binary search', 'Binary search starts in the middle and halves the search space each time — much faster than checking every item.', true),
  (t2, 32, 'story', 'mcq', 'Which of these is NOT a property a good algorithm must have?', '["Correct","Finite","Uses the internet","Clear steps"]', 'Uses the internet', 'Algorithms must be correct, finite (terminate), and have clear steps. They do not need internet access.', true),
  (t2, 33, 'story', 'mcq', 'ARIA writes instructions for making a sandwich. Another robot follows them and makes a perfect sandwich. This means the algorithm is:', '["Fun","Correct and clear","Only for ARIA","Secret"]', 'Correct and clear', 'A good algorithm can be followed by anyone (or any machine) and still produce the correct result.', true),
  (t2, 34, 'story', 'mcq', 'Pattern recognition means:', '["Making up new patterns","Finding similarities and patterns in problems to reuse solutions","Drawing patterns","Ignoring problems"]', 'Finding similarities and patterns in problems to reuse solutions', 'Pattern recognition is a computational thinking skill — spotting similarities lets you reuse known solutions.', true),
  (t2, 35, 'story', 'mcq', 'ARIA''s algorithm prints numbers 1, 2, 3... and never stops. What type of loop does it have?', '["A finite loop","An infinite loop","A conditional loop","A search loop"]', 'An infinite loop', 'An infinite loop has no terminating condition, so it runs forever without producing a final result.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t2, 11, 'levels', 'mcq', 'What does O(1) time complexity mean?', '["The algorithm takes 1 second","The algorithm''s runtime does not depend on input size","The algorithm uses 1 unit of memory","The algorithm has 1 loop"]', 'The algorithm''s runtime does not depend on input size', 'O(1) means constant time — the algorithm takes the same amount of time regardless of how large the input is.', true),
  (t2, 12, 'levels', 'mcq', 'Bubble sort compares adjacent elements and swaps them if out of order. What is its worst-case time complexity?', '["O(n)","O(n log n)","O(n²)","O(log n)"]', 'O(n²)', 'Bubble sort has O(n²) worst-case because for n elements it may need up to n passes of n comparisons each.', true),
  (t2, 13, 'levels', 'mcq', 'Binary search requires the list to be:', '["Random","Sorted","Short","Unique"]', 'Sorted', 'Binary search works by repeatedly halving the search space, which only works correctly on sorted data.', true),
  (t2, 14, 'levels', 'mcq', 'What is the time complexity of binary search?', '["O(1)","O(n)","O(log n)","O(n²)"]', 'O(log n)', 'Binary search halves the problem size each step, giving O(log n) — much faster than linear search for large inputs.', true),
  (t2, 15, 'levels', 'mcq', 'In pseudocode, what does "WHILE condition DO ... END WHILE" represent?', '["A one-time action","A decision","A loop that repeats while the condition is true","A function call"]', 'A loop that repeats while the condition is true', 'A WHILE loop continues executing its body as long as the condition remains true.', true),
  (t2, 16, 'levels', 'mcq', 'Merge sort uses which algorithmic strategy?', '["Greedy","Divide and conquer","Brute force","Dynamic programming"]', 'Divide and conquer', 'Merge sort divides the array in half recursively, sorts each half, then merges them — a classic divide and conquer approach.', true),
  (t2, 17, 'levels', 'mcq', 'Selection sort works by repeatedly:', '["Swapping adjacent elements","Finding the minimum and placing it at the front","Inserting each element in its correct position","Merging sorted halves"]', 'Finding the minimum and placing it at the front', 'Selection sort scans for the smallest unsorted element and swaps it to the correct position in each pass.', true),
  (t2, 18, 'levels', 'mcq', 'What is the best-case time complexity of insertion sort?', '["O(n²)","O(n log n)","O(n)","O(1)"]', 'O(n)', 'Insertion sort is O(n) on an already-sorted list — it only needs one comparison per element.', true),
  (t2, 19, 'levels', 'mcq', 'What is a flowchart diamond shape used to represent?', '["Start/end","A process step","A decision","Data input/output"]', 'A decision', 'Diamonds in flowcharts represent decisions — branching points where the flow splits based on a yes/no condition.', true),
  (t2, 20, 'levels', 'mcq', 'Which time complexity grows slowest as input size increases?', '["O(n²)","O(n)","O(log n)","O(n log n)"]', 'O(log n)', 'O(log n) grows very slowly — doubling the input only adds one extra step, making it very efficient for large inputs.', true),
  (t2, 21, 'levels', 'mcq', 'Quick sort''s worst-case time complexity occurs when:', '["The pivot is always the median","The array is random","The pivot is always the smallest or largest element","The array has duplicates"]', 'The pivot is always the smallest or largest element', 'Poor pivot choice (always min/max) causes O(n²) degradation because partitioning becomes unbalanced.', true),
  (t2, 22, 'levels', 'mcq', 'In Big-O notation, O(n log n) is the time complexity of which algorithm?', '["Bubble sort","Insertion sort","Merge sort","Linear search"]', 'Merge sort', 'Merge sort consistently runs in O(n log n) — it divides log n times and merges n elements at each level.', true),
  (t2, 23, 'levels', 'mcq', 'An algorithm with O(n²) and an algorithm with O(n log n) both solve the same problem. For large n, which is preferred?', '["O(n²) because it is simpler","O(n log n) because it is faster","They are the same","Depends on the language"]', 'O(n log n) because it is faster', 'For large n, O(n log n) grows much more slowly than O(n²), making it significantly faster in practice.', true),
  (t2, 24, 'levels', 'mcq', 'What does "abstraction" mean in computational thinking?', '["Writing detailed code","Hiding unnecessary details and focusing on the important parts","Making things look nice","Using loops"]', 'Hiding unnecessary details and focusing on the important parts', 'Abstraction simplifies complex systems by hiding irrelevant detail and exposing only what matters.', true),
  (t2, 25, 'levels', 'mcq', 'A linear search algorithm checks each element in order. Its average-case time complexity is:', '["O(1)","O(log n)","O(n)","O(n²)"]', 'O(n)', 'Linear search checks elements one by one. On average it checks n/2 elements, which simplifies to O(n).', true),
  (t2, 26, 'levels', 'mcq', 'What is the difference between an algorithm and a program?', '["They are identical","An algorithm is a step-by-step solution; a program is its implementation in code","A program is abstract; an algorithm is concrete","Programs run faster than algorithms"]', 'An algorithm is a step-by-step solution; a program is its implementation in code', 'Algorithms are language-independent logical solutions; programs are specific implementations in a programming language.', true),
  (t2, 27, 'levels', 'mcq', 'Insertion sort inserts each element into:', '["A new array","Its correct position in the already-sorted portion","The end of the list","A random position"]', 'Its correct position in the already-sorted portion', 'Insertion sort builds a sorted section from left to right, inserting each new element in its proper place.', true),
  (t2, 28, 'levels', 'mcq', 'What is the space complexity of an algorithm that uses a fixed amount of extra memory regardless of input size?', '["O(n)","O(log n)","O(1)","O(n²)"]', 'O(1)', 'O(1) space complexity means the extra memory used does not grow with input size — it is constant.', true),
  (t2, 29, 'levels', 'mcq', 'Which sorting algorithm is NOT a comparison-based sort?', '["Bubble sort","Merge sort","Counting sort","Quick sort"]', 'Counting sort', 'Counting sort works by counting occurrences of each value rather than comparing elements — it is not comparison-based.', true),
  (t2, 30, 'levels', 'mcq', 'A function that calls itself is called:', '["A loop","A recursive function","A condition","An iterator"]', 'A recursive function', 'Recursion occurs when a function calls itself with a smaller input, solving the problem step by step.', true),
  (t2, 31, 'levels', 'mcq', 'What must every recursive function have to avoid running forever?', '["A return value","A base case","A loop","Multiple parameters"]', 'A base case', 'A base case is the stopping condition in recursion — without it, the function calls itself infinitely.', true),
  (t2, 32, 'levels', 'mcq', 'In Big-O notation, constants are dropped. Why is O(2n) written as O(n)?', '["Because 2 is a small number","Because Big-O describes growth rate, and constants do not affect how it scales","Because n is always large","It is a mistake"]', 'Because Big-O describes growth rate, and constants do not affect how it scales', 'Big-O captures the rate of growth for large inputs. A constant factor does not change the fundamental scaling behaviour.', true),
  (t2, 33, 'levels', 'mcq', 'Which algorithmic approach tries all possible solutions and picks the best?', '["Greedy","Divide and conquer","Brute force","Dynamic programming"]', 'Brute force', 'Brute force exhaustively tries every possible solution — guaranteed to find the best but often slow for large inputs.', true),
  (t2, 34, 'levels', 'mcq', 'What does the "efficiency" of an algorithm primarily describe?', '["How easy it is to read","How much time and/or memory it uses relative to input size","How short the code is","How many functions it uses"]', 'How much time and/or memory it uses relative to input size', 'Efficiency measures how an algorithm''s time and space requirements scale as the input size grows.', true),
  (t2, 35, 'levels', 'mcq', 'An algorithm that runs in O(n!) time is considered:', '["Very efficient","Acceptable for large inputs","Extremely inefficient (factorial growth)","The same as O(n²)"]', 'Extremely inefficient (factorial growth)', 'O(n!) grows faster than exponential — even for n=20, n! is over 2 quintillion, making it impractical for large inputs.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t2, 11, 'sandbox', 'mcq', 'What is the recurrence relation for merge sort?', '["T(n) = T(n-1) + O(1)","T(n) = 2T(n/2) + O(n)","T(n) = T(n/2) + O(1)","T(n) = n·T(n-1)"]', 'T(n) = 2T(n/2) + O(n)', 'Merge sort splits into 2 halves (2T(n/2)) and merges in linear time (O(n)), giving T(n) = 2T(n/2) + O(n).', true),
  (t2, 12, 'sandbox', 'mcq', 'Memoization is a technique used to optimize recursion by:', '["Increasing recursion depth","Storing results of expensive function calls and returning cached results","Using iteration instead","Reducing function parameters"]', 'Storing results of expensive function calls and returning cached results', 'Memoization caches sub-problem results, avoiding redundant recomputation — it converts exponential recursive algorithms to polynomial ones.', true),
  (t2, 13, 'sandbox', 'mcq', 'Dynamic programming (DP) differs from divide-and-conquer because DP:', '["Uses recursion","Splits problems into independent sub-problems","Solves overlapping sub-problems and stores results","Is always faster"]', 'Solves overlapping sub-problems and stores results', 'DP handles overlapping sub-problems by storing (memoizing/tabulating) results, avoiding repeated computation.', true),
  (t2, 14, 'sandbox', 'mcq', 'What is the time complexity of computing Fibonacci(n) using naive recursion?', '["O(n)","O(n²)","O(2^n)","O(log n)"]', 'O(2^n)', 'Naive Fibonacci branches into two calls at each step, creating an exponential tree of O(2^n) total calls.', true),
  (t2, 15, 'sandbox', 'mcq', 'After applying memoization, the Fibonacci time complexity becomes:', '["O(2^n)","O(n log n)","O(n)","O(log n)"]', 'O(n)', 'With memoization, each Fibonacci value is computed once and cached, reducing total calls to O(n).', true),
  (t2, 16, 'sandbox', 'mcq', 'A greedy algorithm makes choices that are locally optimal at each step. What is its key limitation?', '["It is always slow","It may not find the globally optimal solution","It requires sorting","It cannot handle large inputs"]', 'It may not find the globally optimal solution', 'Greedy algorithms commit to local optima and cannot backtrack, so they may miss the global optimum in some problems.', true),
  (t2, 17, 'sandbox', 'mcq', 'The Master Theorem applies to recurrences of the form T(n) = aT(n/b) + f(n). For merge sort (a=2, b=2, f(n)=n), the solution is:', '["O(n)","O(n log n)","O(n²)","O(log n)"]', 'O(n log n)', 'In merge sort, a=2, b=2, and f(n)=n=n^(log_2 2). This is Case 2 of the Master Theorem, giving O(n log n).', true),
  (t2, 18, 'sandbox', 'mcq', 'What is a tail-recursive function?', '["A function with multiple base cases","A function where the recursive call is the last operation","A function that never terminates","A function with no parameters"]', 'A function where the recursive call is the last operation', 'Tail recursion allows compilers to optimize the call into a loop, avoiding stack overflow — the recursive call is the final action.', true),
  (t2, 19, 'sandbox', 'mcq', 'Which problem is solved optimally by a greedy algorithm?', '["0/1 Knapsack","Travelling Salesman","Activity Selection","Longest Common Subsequence"]', 'Activity Selection', 'The Activity Selection problem (picking maximum non-overlapping intervals) is solved optimally by greedy — always pick the earliest finishing activity.', true),
  (t2, 20, 'sandbox', 'mcq', 'The space complexity of recursive DFS on a graph with n nodes and depth d is:', '["O(n)","O(d)","O(n+d)","O(1)"]', 'O(d)', 'Recursive DFS uses O(d) stack space where d is the maximum recursion depth (the deepest path explored).', true),
  (t2, 21, 'sandbox', 'mcq', 'Amortized analysis is used to:', '["Measure worst-case per-operation cost only","Measure average cost per operation over a sequence of operations","Measure memory usage","Compare two different algorithms"]', 'Measure average cost per operation over a sequence of operations', 'Amortized analysis gives the average cost per operation across a sequence, smoothing out occasional expensive operations.', true),
  (t2, 22, 'sandbox', 'mcq', 'What distinguishes NP problems from P problems?', '["NP problems have no solutions","P problems can be solved in polynomial time; NP solutions can only be VERIFIED in polynomial time","NP problems are impossible","P problems require exponential time"]', 'P problems can be solved in polynomial time; NP solutions can only be VERIFIED in polynomial time', 'P = solvable in polynomial time. NP = verifiable in polynomial time. Whether P=NP is an unsolved problem.', true),
  (t2, 23, 'sandbox', 'mcq', 'Dijkstra''s shortest path algorithm is an example of:', '["Dynamic programming","Brute force","Greedy algorithm","Divide and conquer"]', 'Greedy algorithm', 'Dijkstra greedily picks the unvisited node with the smallest known distance at each step.', true),
  (t2, 24, 'sandbox', 'mcq', 'The space-time tradeoff in algorithms means:', '["Faster algorithms always use less memory","You can often use more memory to reduce time, or vice versa","Space and time are independent","Neither can be optimized"]', 'You can often use more memory to reduce time, or vice versa', 'Caching/memoization trades memory for speed. Recomputing trades time for memory. This is the classic space-time tradeoff.', true),
  (t2, 25, 'sandbox', 'mcq', 'Which sorting algorithm is stable (preserves original order of equal elements)?', '["Quick sort (standard)","Heap sort","Merge sort","Selection sort"]', 'Merge sort', 'Merge sort is a stable sort — equal elements maintain their relative order from the original input.', true),
  (t2, 26, 'sandbox', 'mcq', 'The Bellman-Ford algorithm handles negative edge weights. Its time complexity is:', '["O(V + E)","O(V log V)","O(VE)","O(V²)"]', 'O(VE)', 'Bellman-Ford relaxes all E edges V-1 times, giving O(VE) time complexity.', true),
  (t2, 27, 'sandbox', 'mcq', 'What is the key invariant maintained by binary search?', '["The target is always at index 0","The target, if it exists, is always within the current [low, high] range","The array is sorted at each step","The mid element is always the target"]', 'The target, if it exists, is always within the current [low, high] range', 'Binary search maintains the loop invariant that the target is always within [low, high], shrinking until found or empty.', true),
  (t2, 28, 'sandbox', 'mcq', 'Counting sort has time complexity O(n + k) where k is:', '["The number of comparisons","The range of input values","The number of recursive calls","The array length"]', 'The range of input values', 'Counting sort creates a count array of size k (the value range) and fills it in O(n), giving O(n+k) total.', true),
  (t2, 29, 'sandbox', 'mcq', 'In Python, what is the time complexity of `list.append(x)`?', '["O(n)","O(log n)","O(1) amortized","O(n²)"]', 'O(1) amortized', 'Python lists use dynamic arrays. Most appends are O(1), but occasional resizing is O(n). Amortized over many operations: O(1).', true),
  (t2, 30, 'sandbox', 'mcq', 'What does "in-place" sorting mean?', '["Sorting without moving elements","Sorting using O(1) extra space","Sorting only integers","Sorting in reverse"]', 'Sorting using O(1) extra space', 'In-place algorithms rearrange elements within the original array using only constant extra memory.', true),
  (t2, 31, 'sandbox', 'mcq', 'Floyd''s cycle detection algorithm (tortoise and hare) uses two pointers moving at different speeds. Its space complexity is:', '["O(n)","O(log n)","O(1)","O(n²)"]', 'O(1)', 'Floyd''s algorithm uses only two pointers regardless of input size — O(1) space, elegant and memory efficient.', true),
  (t2, 32, 'sandbox', 'mcq', 'Which data structure does iterative DFS use instead of the call stack?', '["Queue","Priority queue","Stack","Linked list"]', 'Stack', 'Iterative DFS replaces the recursive call stack with an explicit stack data structure.', true),
  (t2, 33, 'sandbox', 'mcq', 'The subset sum problem asking if any subset sums to target T can be solved with DP in:', '["O(n)","O(nT)","O(n²)","O(2^n) only"]', 'O(nT)', 'The DP table is n × T where each cell is computed in O(1), giving O(nT) overall — pseudo-polynomial time.', true),
  (t2, 34, 'sandbox', 'mcq', 'A "stable" sort is important when:', '["Sorting numbers","Sorting elements that have secondary attributes that must preserve relative order","Sorting in reverse","The array is already sorted"]', 'Sorting elements that have secondary attributes that must preserve relative order', 'Stability matters when equal keys carry meaningful secondary data — e.g., sorting records first by date, then by name.', true),
  (t2, 35, 'sandbox', 'mcq', 'Radix sort sorts integers digit by digit. Its time complexity is O(nk) where k is:', '["Number of unique values","Number of digits in the largest number","Square root of n","Log of n"]', 'Number of digits in the largest number', 'Radix sort processes k digit positions, each pass taking O(n), giving O(nk) overall.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t3, 11, 'story', 'mcq', 'ARIA has a row of numbered boxes. She stores one toy in each box. This is like a:', '["Stack","Queue","Array","Tree"]', 'Array', 'An array is a numbered collection of items stored in order, just like numbered boxes.', true),
  (t3, 12, 'story', 'mcq', 'ARIA stacks pancakes. She always eats from the TOP. What data structure is this?', '["Queue","Array","Stack","Tree"]', 'Stack', 'A stack follows LIFO (Last In, First Out) — the last item added is the first one removed, like a pancake stack.', true),
  (t3, 13, 'story', 'mcq', 'Children line up for lunch. The FIRST child to line up gets served FIRST. This is a:', '["Stack","Array","Queue","Tree"]', 'Queue', 'A queue follows FIFO (First In, First Out) — the first item added is the first one removed, like a real queue.', true),
  (t3, 14, 'story', 'mcq', 'ARIA draws her family tree. She is at the bottom and her grandparents are at the top. What structure is this?', '["Stack","Queue","Array","Tree"]', 'Tree', 'A tree is a hierarchical structure with a root and branches, just like a family tree.', true),
  (t3, 15, 'story', 'mcq', 'In ARIA''s numbered box collection (array), box #3 holds her favourite toy. How does she find it?', '["She searches every box","She goes directly to box #3","She empties all boxes first","She guesses"]', 'She goes directly to box #3', 'Arrays allow direct access by index — you can jump straight to any position without searching through others.', true),
  (t3, 16, 'story', 'mcq', 'ARIA adds a book to the TOP of her stack. This action is called:', '["Pop","Enqueue","Push","Insert"]', 'Push', 'Push is the operation that adds an element to the top of a stack.', true),
  (t3, 17, 'story', 'mcq', 'ARIA removes the TOP book from her stack. This is called:', '["Push","Pop","Dequeue","Delete"]', 'Pop', 'Pop removes and returns the top element of a stack.', true),
  (t3, 18, 'story', 'mcq', 'ARIA joins the back of the lunch queue. This action is called:', '["Push","Pop","Enqueue","Dequeue"]', 'Enqueue', 'Enqueue adds an element to the back (rear) of a queue.', true),
  (t3, 19, 'story', 'mcq', 'The student at the FRONT of the queue gets served and leaves. This is called:', '["Push","Pop","Enqueue","Dequeue"]', 'Dequeue', 'Dequeue removes and returns the front element of a queue.', true),
  (t3, 20, 'story', 'mcq', 'In a tree, the very top node with no parent is called the:', '["Leaf","Branch","Root","Node"]', 'Root', 'The root is the topmost node in a tree — it has no parent and all other nodes descend from it.', true),
  (t3, 21, 'story', 'mcq', 'In a tree, nodes that have NO children are called:', '["Roots","Parents","Leaves","Branches"]', 'Leaves', 'Leaf nodes are at the bottom of the tree — they have no children of their own.', true),
  (t3, 22, 'story', 'mcq', 'ARIA has a list of robot names connected like a chain: each name points to the next. This is a:', '["Array","Stack","Linked list","Queue"]', 'Linked list', 'A linked list is a chain of nodes where each node points to the next, unlike an array''s direct indexing.', true),
  (t3, 23, 'story', 'mcq', 'ARIA wants to undo her last drawing action. Which data structure helps?', '["Queue","Stack","Tree","Array"]', 'Stack', 'Undo features use stacks — each action is pushed on, and undoing pops the most recent action off.', true),
  (t3, 24, 'story', 'mcq', 'ARIA''s printer receives many jobs. It prints them in the order received. Which structure manages this?', '["Stack","Tree","Queue","Array"]', 'Queue', 'A print queue uses FIFO — jobs are printed in the order they arrive, which is fair and predictable.', true),
  (t3, 25, 'story', 'mcq', 'How does ARIA find item at index 0 in an array?', '["She counts from the end","She goes straight to the first position","She uses a loop","She sorts first"]', 'She goes straight to the first position', 'Arrays are zero-indexed in most languages — index 0 is the first element, accessed in constant time.', true),
  (t3, 26, 'story', 'mcq', 'ARIA checks if her stack is empty before popping. Why is this important?', '["Popping from empty stack causes an error","It makes popping faster","It adds items to the stack","It is not important"]', 'Popping from empty stack causes an error', 'Popping from an empty stack causes a stack underflow error — always check before removing items.', true),
  (t3, 27, 'story', 'mcq', 'A binary tree node can have at most how many children?', '["1","2","3","Unlimited"]', '2', 'Binary trees have at most 2 children per node — a left child and a right child.', true),
  (t3, 28, 'story', 'mcq', 'ARIA has a dictionary. She looks up "robot" and finds its meaning instantly. This fast lookup uses a:', '["Array","Stack","Hash table","Queue"]', 'Hash table', 'Hash tables (like dictionaries) use a hash function to find values almost instantly, regardless of size.', true),
  (t3, 29, 'story', 'mcq', 'Which data structure would ARIA use to store website history so she can press BACK to go to the previous page?', '["Queue","Stack","Array","Linked list"]', 'Stack', 'Browser back buttons use a stack — each visited page is pushed on, and pressing back pops to the previous page.', true),
  (t3, 30, 'story', 'mcq', 'ARIA''s array has 5 items. What is the index of the LAST item?', '["5","4","6","0"]', '4', 'Arrays are zero-indexed. The last item in an array of 5 elements is at index 4 (0, 1, 2, 3, 4).', true),
  (t3, 31, 'story', 'mcq', 'Which structure is best for keeping items in sorted order for easy searching?', '["Queue","Stack","Binary Search Tree","Random array"]', 'Binary Search Tree', 'A Binary Search Tree keeps smaller items left and larger items right, making searching very efficient.', true),
  (t3, 32, 'story', 'mcq', 'ARIA wants to know how deep her tree is (from root to deepest leaf). This depth is called the:', '["Width","Height","Length","Size"]', 'Height', 'The height of a tree is the number of edges on the longest path from root to a leaf node.', true),
  (t3, 33, 'story', 'mcq', 'In a linked list, each item (node) contains the data AND:', '["A colour","A pointer to the next node","Its index number","Its size"]', 'A pointer to the next node', 'Each linked list node stores its data and a reference (pointer) to the next node in the chain.', true),
  (t3, 34, 'story', 'mcq', 'ARIA''s stack has items A, B, C (C on top). She pops twice. What is left?', '["A","B","C","Nothing"]', 'A', 'Pop removes the top item. First pop removes C, second removes B. Only A remains.', true),
  (t3, 35, 'story', 'mcq', 'A graph is like a map where cities are connected by roads. Each city is a:', '["Edge","Node/vertex","Root","Leaf"]', 'Node/vertex', 'In a graph, nodes (vertices) represent entities (like cities), and edges represent connections (like roads).', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t3, 11, 'levels', 'mcq', 'What is the time complexity of accessing an element in an array by index?', '["O(n)","O(log n)","O(1)","O(n²)"]', 'O(1)', 'Arrays store elements in contiguous memory, so any element can be accessed directly by index in constant time.', true),
  (t3, 12, 'levels', 'mcq', 'What is the main advantage of a linked list over an array?', '["Faster random access","Efficient insertion and deletion without shifting elements","Less memory usage","Better cache performance"]', 'Efficient insertion and deletion without shifting elements', 'Linked list insertions/deletions only require updating pointers, while arrays require shifting all subsequent elements.', true),
  (t3, 13, 'levels', 'mcq', 'In a stack, which principle governs element access?', '["FIFO","LIFO","Random access","Priority-based"]', 'LIFO', 'Stack follows Last In, First Out — the most recently added element is the first to be removed.', true),
  (t3, 14, 'levels', 'mcq', 'A queue follows which access principle?', '["LIFO","Random","FIFO","Priority"]', 'FIFO', 'Queue follows First In, First Out — elements are added at the rear and removed from the front.', true),
  (t3, 15, 'levels', 'mcq', 'In a Binary Search Tree (BST), where are values smaller than the root stored?', '["In the right subtree","In the left subtree","At the root","In a separate tree"]', 'In the left subtree', 'BST property: all values in the left subtree are less than the root, all in the right are greater.', true),
  (t3, 16, 'levels', 'mcq', 'What is the worst-case time complexity of searching in a balanced BST?', '["O(1)","O(n)","O(log n)","O(n²)"]', 'O(log n)', 'In a balanced BST, each comparison eliminates half the remaining nodes, giving O(log n) search time.', true),
  (t3, 17, 'levels', 'mcq', 'What is the worst-case time complexity of searching in an unbalanced BST (like a linear chain)?', '["O(log n)","O(n)","O(1)","O(n log n)"]', 'O(n)', 'An unbalanced BST degrades to a linked list. In the worst case (sorted input), search takes O(n).', true),
  (t3, 18, 'levels', 'mcq', 'A hash table achieves average-case O(1) lookup. What is the main problem that can degrade this?', '["Large data sizes","Hash collisions","Too many keys","Sorted input"]', 'Hash collisions', 'Hash collisions occur when two keys map to the same index, requiring collision resolution and potentially degrading to O(n).', true),
  (t3, 19, 'levels', 'mcq', 'Which traversal visits a BST in ascending sorted order?', '["Pre-order","Post-order","In-order","Level-order"]', 'In-order', 'In-order traversal (left, root, right) of a BST visits nodes in ascending sorted order.', true),
  (t3, 20, 'levels', 'mcq', 'What is a heap data structure?', '["A sorted array","A complete binary tree where parent is always larger (max-heap) or smaller (min-heap) than children","A type of hash table","A balanced BST"]', 'A complete binary tree where parent is always larger (max-heap) or smaller (min-heap) than children', 'A heap is a complete binary tree satisfying the heap property: max-heap parents are always >= children.', true),
  (t3, 21, 'levels', 'mcq', 'What is the time complexity of inserting into a max-heap?', '["O(1)","O(n)","O(log n)","O(n log n)"]', 'O(log n)', 'Heap insertion adds at the bottom and bubbles up to restore the heap property — taking at most O(log n) steps.', true),
  (t3, 22, 'levels', 'mcq', 'What does a doubly linked list have that a singly linked list does not?', '["A head pointer","Pointers to both next AND previous nodes","Random access","Sorted elements"]', 'Pointers to both next AND previous nodes', 'Doubly linked list nodes have two pointers: one to the next node and one to the previous, enabling bidirectional traversal.', true),
  (t3, 23, 'levels', 'mcq', 'Which data structure is used by BFS (Breadth-First Search)?', '["Stack","Queue","Heap","Array"]', 'Queue', 'BFS explores nodes level by level, using a queue to process nodes in the order they are discovered.', true),
  (t3, 24, 'levels', 'mcq', 'Which data structure is used by DFS (Depth-First Search) in its iterative form?', '["Queue","Heap","Stack","Linked list"]', 'Stack', 'Iterative DFS uses a stack to explore as deep as possible before backtracking.', true),
  (t3, 25, 'levels', 'mcq', 'An adjacency list representation of a graph is preferred over an adjacency matrix when:', '["The graph is dense","The graph is sparse (few edges)","Speed is not important","The graph is undirected"]', 'The graph is sparse (few edges)', 'Adjacency lists use O(V+E) space — efficient for sparse graphs. Adjacency matrices use O(V²) regardless of edges.', true),
  (t3, 26, 'levels', 'mcq', 'What is the time complexity of push and pop operations on a stack?', '["O(n)","O(log n)","O(1)","O(n²)"]', 'O(1)', 'Stack push and pop only access the top element — no searching or shifting needed, giving O(1) operations.', true),
  (t3, 27, 'levels', 'mcq', 'A priority queue always removes which element first?', '["The most recently added","The element with highest (or lowest) priority","The element at index 0","A random element"]', 'The element with highest (or lowest) priority', 'A priority queue removes the element with the highest (or lowest, depending on configuration) priority first.', true),
  (t3, 28, 'levels', 'mcq', 'What is "chaining" in hash table collision resolution?', '["Doubling the table size","Storing multiple elements at the same index using a linked list","Using a second hash function","Sorting all elements"]', 'Storing multiple elements at the same index using a linked list', 'Chaining resolves collisions by maintaining a linked list at each hash table bucket, storing all colliding elements there.', true),
  (t3, 29, 'levels', 'mcq', 'How many edges does a tree with n nodes have?', '["n","n+1","n-1","n²"]', 'n-1', 'A tree with n nodes has exactly n-1 edges — adding an edge would create a cycle, and removing would disconnect it.', true),
  (t3, 30, 'levels', 'mcq', 'What is a circular queue (ring buffer)?', '["A queue stored in a circle shape","A fixed-size queue where the end wraps around to the beginning","A queue with no limit","A stack disguised as a queue"]', 'A fixed-size queue where the end wraps around to the beginning', 'A circular queue reuses the space after dequeuing by wrapping the rear pointer around to the start of the array.', true),
  (t3, 31, 'levels', 'mcq', 'Pre-order tree traversal visits nodes in which order?', '["Left, Root, Right","Left, Right, Root","Root, Left, Right","Right, Root, Left"]', 'Root, Left, Right', 'Pre-order traversal: visit the root first, then recursively traverse the left subtree, then the right subtree.', true),
  (t3, 32, 'levels', 'mcq', 'What is the load factor of a hash table?', '["Number of elements divided by table size","Table size divided by number of elements","Number of collisions","Maximum chain length"]', 'Number of elements divided by table size', 'Load factor = n/m (elements/slots). As it increases, collision probability rises and performance degrades.', true),
  (t3, 33, 'levels', 'mcq', 'In a max-heap, what is always true about the root node?', '["It holds the smallest value","It holds the largest value","It has exactly two children","It is always a leaf"]', 'It holds the largest value', 'In a max-heap, the root is the maximum element — the heap property guarantees every parent >= its children.', true),
  (t3, 34, 'levels', 'mcq', 'Which graph representation uses O(V²) space?', '["Adjacency list","Adjacency matrix","Edge list","Incidence matrix"]', 'Adjacency matrix', 'An adjacency matrix is a V×V grid storing 0/1 for each possible edge, using O(V²) space regardless of actual edge count.', true),
  (t3, 35, 'levels', 'mcq', 'Post-order traversal visits the root:', '["First","Second","Last","Only if it has no children"]', 'Last', 'Post-order traversal is: left subtree, right subtree, then root — the root is visited last.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t3, 11, 'sandbox', 'mcq', 'In Python, what is the time complexity of `dict[key]` lookup on average?', '["O(n)","O(log n)","O(1)","O(n²)"]', 'O(1)', 'Python dicts are hash tables. Average-case lookup is O(1) due to direct hash-indexed access.', true),
  (t3, 12, 'sandbox', 'mcq', 'Which hash collision strategy uses a second hash function to find the next available slot?', '["Chaining","Linear probing","Quadratic probing","Double hashing"]', 'Double hashing', 'Double hashing uses a second hash function to compute the step size when a collision occurs, reducing clustering.', true),
  (t3, 13, 'sandbox', 'mcq', 'In Python, `collections.deque` is preferred over a list for queue operations because:', '["It uses less memory","append and popleft are both O(1) vs list popleft being O(n)","It is thread-safe by default","It supports random access"]', 'append and popleft are both O(1) vs list popleft being O(n)', 'deque provides O(1) operations at both ends. List.pop(0) is O(n) because all elements shift.', true),
  (t3, 14, 'sandbox', 'mcq', 'What does the `heapq` module in Python implement by default?', '["Max-heap","Min-heap","Sorted list","Binary search tree"]', 'Min-heap', 'Python''s heapq module implements a min-heap — the smallest element is always at index 0.', true),
  (t3, 15, 'sandbox', 'mcq', 'For an AVL tree to remain balanced after insertion, what operation may be needed?', '["Re-hashing","Rotation","Sorting","Rebuilding from scratch"]', 'Rotation', 'AVL trees maintain balance using rotations (single or double) after insertions that violate the balance factor constraint.', true),
  (t3, 16, 'sandbox', 'mcq', 'What is the balance factor of a node in an AVL tree?', '["Height of left subtree","Height difference between left and right subtrees","Number of children","Depth from root"]', 'Height difference between left and right subtrees', 'Balance factor = height(left) - height(right). AVL trees require this to be -1, 0, or +1 at every node.', true),
  (t3, 17, 'sandbox', 'mcq', 'Trie (prefix tree) is most efficiently used for:', '["Sorting numbers","Autocomplete and prefix search on strings","Graph shortest path","Matrix operations"]', 'Autocomplete and prefix search on strings', 'Tries store strings character by character, enabling O(L) prefix searches where L is the string length.', true),
  (t3, 18, 'sandbox', 'mcq', 'What is the time complexity of deleting the maximum from a max-heap of size n?', '["O(1)","O(n)","O(log n)","O(n log n)"]', 'O(log n)', 'Heap deletion swaps root with last element, removes it, then sifts down to restore heap property — O(log n).', true),
  (t3, 19, 'sandbox', 'mcq', 'In a Red-Black tree, what colour is the root always?', '["Red","Black","Either","Depends on insertions"]', 'Black', 'Red-Black tree rule: the root must always be black. This is one of the five Red-Black tree invariants.', true),
  (t3, 20, 'sandbox', 'mcq', 'Which traversal of a BST would you use to delete the tree without memory leaks in C?', '["Pre-order","In-order","Post-order","Level-order"]', 'Post-order', 'Post-order visits children before the parent — this ensures children are freed before their parent node is deleted.', true),
  (t3, 21, 'sandbox', 'mcq', 'The Union-Find (Disjoint Set Union) data structure with path compression and union by rank has nearly O(1) operations. What is the actual complexity per operation?', '["O(1)","O(log n)","O(α(n)) where α is inverse Ackermann","O(n)"]', 'O(α(n)) where α is inverse Ackermann', 'With both optimizations, DSU operations are O(α(n)), the inverse Ackermann function, which is practically O(1).', true),
  (t3, 22, 'sandbox', 'mcq', 'What is a B-tree primarily used for?', '["In-memory sorting","Database indexing on disk","Network routing","String matching"]', 'Database indexing on disk', 'B-trees are balanced multi-way trees optimized for disk I/O — they minimize disk accesses in database indexing.', true),
  (t3, 23, 'sandbox', 'mcq', 'In open addressing (linear probing), what problem arises as the load factor increases?', '["More collisions only","Primary clustering — long runs of filled slots slow down insertions and lookups","Memory overflow","Key duplication"]', 'Primary clustering — long runs of filled slots slow down insertions and lookups', 'Linear probing causes primary clustering: collisions create growing chains of consecutive filled slots, degrading performance.', true),
  (t3, 24, 'sandbox', 'mcq', 'What is the time complexity of building a heap from an unsorted array of n elements?', '["O(n log n)","O(n²)","O(n)","O(log n)"]', 'O(n)', 'Heapify-down on all non-leaf nodes builds a heap in O(n) — the mathematical sum of work converges to linear.', true),
  (t3, 25, 'sandbox', 'mcq', 'A skip list provides O(log n) average search. How does it achieve this?', '["Using a hash function","By maintaining multiple levels of linked lists with decreasing element density","By sorting on insert","Using binary search on an array"]', 'By maintaining multiple levels of linked lists with decreasing element density', 'Skip lists have multiple lanes — upper lanes skip many elements, lower lanes have all elements, enabling O(log n) search probabilistically.', true),
  (t3, 26, 'sandbox', 'mcq', 'In Python, `list[-1]` accesses which element?', '["Raises an error","The first element","The last element","A random element"]', 'The last element', 'Python supports negative indexing. -1 refers to the last element, -2 to second-last, etc.', true),
  (t3, 27, 'sandbox', 'mcq', 'Segment trees support range queries (like sum/min over [l,r]) in what time?', '["O(n)","O(1)","O(log n)","O(n log n)"]', 'O(log n)', 'Segment trees answer range queries in O(log n) by splitting the range into O(log n) precomputed segments.', true),
  (t3, 28, 'sandbox', 'mcq', 'What is the height of a complete binary tree with n nodes?', '["n","n/2","floor(log2(n))","n-1"]', 'floor(log2(n))', 'A complete binary tree fills levels top to bottom. The height is ⌊log₂(n)⌋ — each level doubles the node count.', true),
  (t3, 29, 'sandbox', 'mcq', 'In graph algorithms, what does "topological sort" produce?', '["Nodes sorted by value","A linear ordering of vertices such that for every edge u→v, u comes before v","Shortest paths from a source","Minimum spanning tree"]', 'A linear ordering of vertices such that for every edge u→v, u comes before v', 'Topological sort orders DAG nodes so all directed edges point forward — useful for dependency resolution.', true),
  (t3, 30, 'sandbox', 'mcq', 'Fenwick tree (Binary Indexed Tree) efficiently supports:', '["Only range minimum queries","Prefix sum queries and point updates in O(log n)","Sorting in O(n)","Balanced BST operations"]', 'Prefix sum queries and point updates in O(log n)', 'Fenwick trees support prefix sums and point updates in O(log n), with lower constant factors than segment trees.', true),
  (t3, 31, 'sandbox', 'mcq', 'What is a "sentinel node" in linked list implementations?', '["A node marking the end","A dummy node at head/tail to simplify boundary condition handling","The largest node","A node with null data"]', 'A dummy node at head/tail to simplify boundary condition handling', 'Sentinel nodes eliminate special cases for empty lists and boundary conditions, simplifying insertion/deletion code.', true),
  (t3, 32, 'sandbox', 'mcq', 'The LRU Cache eviction policy can be implemented in O(1) for all operations using:', '["Array + binary search","Hash map + doubly linked list","Two stacks","Priority queue"]', 'Hash map + doubly linked list', 'Hash map provides O(1) key lookup; doubly linked list allows O(1) node move-to-front and tail eviction.', true),
  (t3, 33, 'sandbox', 'mcq', 'In Kruskal''s minimum spanning tree algorithm, Union-Find is used to:', '["Sort edges","Detect if adding an edge creates a cycle","Find the shortest path","Count connected components"]', 'Detect if adding an edge creates a cycle', 'Kruskal''s adds edges in weight order. Union-Find checks if two endpoints are in the same component (would form cycle).', true),
  (t3, 34, 'sandbox', 'mcq', 'What distinguishes a directed graph (digraph) from an undirected graph?', '["Directed graphs have weights","Edges in digraphs have direction (u→v ≠ v→u)","Digraphs cannot have cycles","Digraphs use adjacency lists only"]', 'Edges in digraphs have direction (u→v ≠ v→u)', 'In directed graphs, edges have a specific direction — an edge from u to v does not imply an edge from v to u.', true),
  (t3, 35, 'sandbox', 'mcq', 'What is the space complexity of storing a graph with V vertices and E edges as an adjacency list?', '["O(V²)","O(V + E)","O(E²)","O(V)"]', 'O(V + E)', 'Adjacency lists store V list headers plus a total of 2E entries (undirected) or E entries (directed) — O(V+E).', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t4, 11, 'story', 'mcq', 'ARIA shows the computer many pictures of cats with the label "cat". The computer learns from these. What are these pictures called?', '["Test data","Training data","Random data","Hidden data"]', 'Training data', 'Training data is the set of examples used to teach a machine learning model to recognise patterns.', true),
  (t4, 12, 'story', 'mcq', 'After training, ARIA shows the computer a NEW cat picture it has never seen. This is called:', '["Training","Testing","Labelling","Sorting"]', 'Testing', 'Testing checks how well the model performs on new, unseen data — the true measure of learning.', true),
  (t4, 13, 'story', 'mcq', 'ARIA''s computer learns to sort emails as "spam" or "not spam". It is learning from LABELS. This type of learning is:', '["Unsupervised learning","Reinforcement learning","Supervised learning","Random learning"]', 'Supervised learning', 'Supervised learning trains on labelled examples — the computer learns to map inputs to known correct outputs.', true),
  (t4, 14, 'story', 'mcq', 'A computer groups photos by similarity WITHOUT being told what the groups are. This is:', '["Supervised learning","Unsupervised learning","Deep learning","Rule-based learning"]', 'Unsupervised learning', 'Unsupervised learning finds hidden patterns in data without labels — the model discovers structure on its own.', true),
  (t4, 15, 'story', 'mcq', 'ARIA''s robot learns to walk by trying and getting rewards when it does well. This is:', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', 'Reinforcement learning', 'Reinforcement learning trains agents through rewards and penalties — the agent learns by trial and error.', true),
  (t4, 16, 'story', 'mcq', 'If a model scores 9 out of 10 on training examples but only 3 out of 10 on new examples, it has:', '["Underfit","Overfit","Good fit","Been reset"]', 'Overfit', 'Overfitting means the model memorised training data but cannot generalise to new data — it performs poorly on new examples.', true),
  (t4, 17, 'story', 'mcq', 'A model that does poorly on BOTH training AND new data has:', '["Overfit","Underfit","Perfect fit","Been hacked"]', 'Underfit', 'Underfitting means the model is too simple — it cannot learn the patterns even in training data.', true),
  (t4, 18, 'story', 'mcq', 'Which of these is a "feature" a computer might use to recognise a dog?', '["The price of the computer","The number of legs in the photo","The file name","The camera brand"]', 'The number of legs in the photo', 'Features are measurable properties of data used for learning — like number of legs, colour, or size.', true),
  (t4, 19, 'story', 'mcq', 'ARIA''s model predicts that a shape is a circle, but it is actually a square. This is called:', '["A feature","A correct prediction","An incorrect prediction (error)","Training"]', 'An incorrect prediction (error)', 'When a model''s prediction does not match the actual label, this is a prediction error.', true),
  (t4, 20, 'story', 'mcq', 'Machine learning models get better with more:', '["Power cuts","Good quality training data","Bugs","Fewer features"]', 'Good quality training data', 'High-quality training data with good coverage of examples helps models learn accurate patterns.', true),
  (t4, 21, 'story', 'mcq', 'ARIA asks her model: "Is this email spam?" The model gives a YES or NO answer. This type of problem is called:', '["Regression","Classification","Clustering","Generation"]', 'Classification', 'Classification predicts which category an input belongs to — like spam/not-spam or cat/dog.', true),
  (t4, 22, 'story', 'mcq', 'ARIA asks her model to predict tomorrow''s temperature as a number. This type of problem is called:', '["Classification","Clustering","Regression","Sorting"]', 'Regression', 'Regression predicts a continuous numerical value (like temperature or price) rather than a category.', true),
  (t4, 23, 'story', 'mcq', 'A label in machine learning is:', '["A sticker on a box","The correct answer for a training example","A type of algorithm","A computer brand"]', 'The correct answer for a training example', 'Labels are the correct output values attached to training examples, telling the model what to predict.', true),
  (t4, 24, 'story', 'mcq', 'ARIA splits her data into two groups: one to LEARN from and one to TEST on. Why does she keep them separate?', '["To save storage","To test on unseen data and check real performance","Because they are different sizes","It is just tradition"]', 'To test on unseen data and check real performance', 'If you test on training data, the model looks better than it really is. Test data simulates real-world use.', true),
  (t4, 25, 'story', 'mcq', 'Which of these is an example of a machine learning task?', '["Adding 2+2","Sorting a list alphabetically","Recognising faces in photos","Printing a document"]', 'Recognising faces in photos', 'Face recognition requires learning from examples to identify patterns — a classic ML task.', true),
  (t4, 26, 'story', 'mcq', 'ARIA''s model has seen only blue balls during training. When tested on red balls, it fails. This problem is called:', '["Overfitting","Poor generalisation due to limited training variety","Underfitting","A bug"]', 'Poor generalisation due to limited training variety', 'Models trained on limited variety fail to generalise. Training data must represent the diversity of real inputs.', true),
  (t4, 27, 'story', 'mcq', 'What does "accuracy" mean for a classification model?', '["How fast it runs","The percentage of correct predictions","How much memory it uses","How long it took to train"]', 'The percentage of correct predictions', 'Accuracy = (correct predictions) / (total predictions) × 100%. It measures how often the model is right.', true),
  (t4, 28, 'story', 'mcq', 'A model trained on pictures of sunny days only. On rainy days, it fails. It needs:', '["More sunny day pictures","More varied training data including rainy days","A faster computer","Fewer features"]', 'More varied training data including rainy days', 'Good training data must cover the full range of conditions the model will encounter in real use.', true),
  (t4, 29, 'story', 'mcq', 'ARIA''s model predicts whether a student will pass or fail. What kind of problem is this?', '["Regression","Clustering","Classification","Generation"]', 'Classification', 'Predicting pass/fail is a binary classification problem — the model outputs one of two categories.', true),
  (t4, 30, 'story', 'mcq', 'Which of the following is NOT a type of machine learning?', '["Supervised learning","Reinforcement learning","Googling learning","Unsupervised learning"]', 'Googling learning', 'The three main types of machine learning are supervised, unsupervised, and reinforcement learning.', true),
  (t4, 31, 'story', 'mcq', 'ARIA''s model looks for cats and dogs. She has 1000 cat images but only 10 dog images. This imbalance could cause:', '["The model to be equally good at both","The model to favour predicting cat for almost everything","The model to refuse to run","Faster training"]', 'The model to favour predicting cat for almost everything', 'Class imbalance causes models to be biased toward the majority class — it rarely predicts the underrepresented class.', true),
  (t4, 32, 'story', 'mcq', 'In machine learning, "training" the model means:', '["Writing the code","Adjusting the model so it makes better predictions from data","Cleaning the data","Testing the model"]', 'Adjusting the model so it makes better predictions from data', 'Training is the process of optimizing a model''s internal parameters to minimize errors on the training data.', true),
  (t4, 33, 'story', 'mcq', 'ARIA finds that her model changes its answer every time she runs it on the same input. This is a sign of:', '["Great creativity","A bug or randomness in the model","Overfitting","Good generalisation"]', 'A bug or randomness in the model', 'Models should give consistent predictions for the same input. Random outputs indicate non-determinism or a bug.', true),
  (t4, 34, 'story', 'mcq', 'What is a "prediction" in machine learning?', '["The training data","The model''s output for a new input","The accuracy score","The number of layers"]', 'The model''s output for a new input', 'A prediction is the output a trained model produces when given a new, unseen input.', true),
  (t4, 35, 'story', 'mcq', 'ARIA trains a model to predict ice cream sales from temperature. Higher temperature → more sales. This relationship is called:', '["Noise","A pattern/correlation","An error","Randomness"]', 'A pattern/correlation', 'ML models learn patterns (correlations) in data — like the relationship between temperature and ice cream sales.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t4, 11, 'levels', 'mcq', 'Which metric measures the proportion of true positives among all predicted positives?', '["Recall","Accuracy","Precision","F1-score"]', 'Precision', 'Precision = TP / (TP + FP). It measures how many of the model''s positive predictions were actually correct.', true),
  (t4, 12, 'levels', 'mcq', 'Which metric measures the proportion of true positives among all actual positives?', '["Precision","Accuracy","Recall","Specificity"]', 'Recall', 'Recall = TP / (TP + FN). It measures how many actual positives the model correctly identified.', true),
  (t4, 13, 'levels', 'mcq', 'What does the F1-score represent?', '["Accuracy minus recall","Harmonic mean of precision and recall","Average of precision and recall","Maximum of precision or recall"]', 'Harmonic mean of precision and recall', 'F1 = 2*(Precision*Recall)/(Precision+Recall). It balances both metrics, useful when classes are imbalanced.', true),
  (t4, 14, 'levels', 'mcq', 'K-fold cross-validation splits data into k folds. Each fold is used as:', '["Training data once","Validation data exactly once","Both training and test","Neither"]', 'Validation data exactly once', 'In k-fold CV, each fold serves as the validation set once while the remaining k-1 folds are used for training.', true),
  (t4, 15, 'levels', 'mcq', 'Overfitting can be detected by:', '["Low training error AND low validation error","High training error AND high validation error","Low training error AND high validation error","High training error AND low validation error"]', 'Low training error AND high validation error', 'Overfitting shows as a large gap: very low error on training data but high error on validation/test data.', true),
  (t4, 16, 'levels', 'mcq', 'Feature scaling (normalisation) is important because:', '["It removes missing values","Features with larger ranges can dominate distance-based algorithms","It speeds up all algorithms","It removes outliers"]', 'Features with larger ranges can dominate distance-based algorithms', 'Without scaling, features with large numerical ranges (e.g., salary vs age) unfairly dominate distance calculations in models like KNN.', true),
  (t4, 17, 'levels', 'mcq', 'In supervised learning, what is the difference between a classification and a regression problem?', '["Classification uses more data","Classification predicts categories; regression predicts continuous values","Regression is always more accurate","They are the same"]', 'Classification predicts categories; regression predicts continuous values', 'Classification outputs discrete labels (cat/dog). Regression outputs continuous numbers (price, temperature).', true),
  (t4, 18, 'levels', 'mcq', 'What is the purpose of a validation set (separate from test set)?', '["To train the model","To tune hyperparameters without peeking at test data","To store training data","To evaluate final model performance"]', 'To tune hyperparameters without peeking at test data', 'The validation set guides hyperparameter tuning. The test set is reserved for final evaluation only.', true),
  (t4, 19, 'levels', 'mcq', 'Which algorithm finds the k nearest training examples to classify a new point?', '["Decision Tree","K-Nearest Neighbours (KNN)","Linear Regression","Naive Bayes"]', 'K-Nearest Neighbours (KNN)', 'KNN classifies by finding the k closest training examples and using majority vote among their labels.', true),
  (t4, 20, 'levels', 'mcq', 'What does "generalisation" mean in ML?', '["Memorising training data","Performing well on new unseen data","Having many features","Using all available data for training"]', 'Performing well on new unseen data', 'Generalisation is the goal of ML — a model that only memorises training data is useless; it must handle new inputs.', true),
  (t4, 21, 'levels', 'mcq', 'A decision tree splits data based on:', '["Random splits","Features that best separate the classes at each node","The first feature alphabetically","The largest feature values"]', 'Features that best separate the classes at each node', 'Decision trees choose splits using criteria like Gini impurity or information gain to maximally separate classes.', true),
  (t4, 22, 'levels', 'mcq', 'Which of the following is an unsupervised learning algorithm?', '["Linear Regression","K-Means Clustering","Random Forest","Support Vector Machine"]', 'K-Means Clustering', 'K-Means groups data into k clusters without labels — it is an unsupervised algorithm that discovers structure.', true),
  (t4, 23, 'levels', 'mcq', 'The bias-variance tradeoff means:', '["High bias models overfit; high variance models underfit","High bias models underfit; high variance models overfit","Both bias and variance should be maximised","They are unrelated"]', 'High bias models underfit; high variance models overfit', 'High bias (too simple model) → underfitting. High variance (too complex) → overfitting. We seek a balance.', true),
  (t4, 24, 'levels', 'mcq', 'In a confusion matrix for binary classification, a "false negative" means:', '["Correctly predicting negative","Predicting positive when it is actually negative","Predicting negative when it is actually positive","Correctly predicting positive"]', 'Predicting negative when it is actually positive', 'False Negative (FN): the model predicted Negative but the true label was Positive — a missed detection.', true),
  (t4, 25, 'levels', 'mcq', 'A Random Forest is an ensemble of many:', '["Neural networks","Support vector machines","Decision trees","Linear models"]', 'Decision trees', 'Random Forest trains many decision trees on random data subsets and averages their predictions, reducing variance.', true),
  (t4, 26, 'levels', 'mcq', 'What does "hyperparameter" mean in ML?', '["A parameter learned from data","A configuration set BEFORE training that controls the learning process","The output of the model","A type of feature"]', 'A configuration set BEFORE training that controls the learning process', 'Hyperparameters (like learning rate, tree depth, k in KNN) are set by the practitioner before training begins.', true),
  (t4, 27, 'levels', 'mcq', 'Which strategy can help address class imbalance?', '["Using more features","Oversampling the minority class or undersampling the majority","Training longer","Using a simpler model"]', 'Oversampling the minority class or undersampling the majority', 'Oversampling (e.g., SMOTE) adds synthetic minority examples; undersampling reduces majority — both rebalance the dataset.', true),
  (t4, 28, 'levels', 'mcq', 'What is the "curse of dimensionality"?', '["Having too little data","As the number of features increases, data becomes sparse and models struggle","Having too many training examples","Overfitting to a single feature"]', 'As the number of features increases, data becomes sparse and models struggle', 'In high-dimensional spaces, data points become sparse and distance metrics lose meaning — models require exponentially more data.', true),
  (t4, 29, 'levels', 'mcq', 'Naive Bayes is "naive" because it assumes:', '["All features are equal","Features are independent of each other given the class label","The data is normally distributed","No training data is needed"]', 'Features are independent of each other given the class label', 'Naive Bayes assumes feature independence (often violated in reality) to simplify probability calculations.', true),
  (t4, 30, 'levels', 'mcq', 'Which evaluation metric is most appropriate when false negatives are very costly (e.g., cancer detection)?', '["Accuracy","Precision","Recall","Specificity"]', 'Recall', 'High recall minimises false negatives — crucial when missing a positive (like cancer) has severe consequences.', true),
  (t4, 31, 'levels', 'mcq', 'Gradient boosting builds models:', '["In parallel","Sequentially, each correcting errors of the previous","Randomly","Using only one decision tree"]', 'Sequentially, each correcting errors of the previous', 'Gradient boosting trains weak learners sequentially, where each new model focuses on the residual errors of the ensemble so far.', true),
  (t4, 32, 'levels', 'mcq', 'What is "data leakage" in machine learning?', '["Missing data values","When information from the test set inadvertently influences training","Having duplicate training examples","Using too many features"]', 'When information from the test set inadvertently influences training', 'Data leakage contaminates training with future/test information, causing unrealistically optimistic evaluation metrics.', true),
  (t4, 33, 'levels', 'mcq', 'Principal Component Analysis (PCA) is used for:', '["Classification","Dimensionality reduction by projecting onto variance-maximising axes","Clustering","Boosting accuracy"]', 'Dimensionality reduction by projecting onto variance-maximising axes', 'PCA reduces features by finding principal components — directions of maximum variance in the data.', true),
  (t4, 34, 'levels', 'mcq', 'What is the difference between a model''s parameters and hyperparameters?', '["No difference","Parameters are learned during training; hyperparameters are set before training","Parameters are set before training; hyperparameters are learned","Both are set manually"]', 'Parameters are learned during training; hyperparameters are set before training', 'Parameters (weights) are optimised during training. Hyperparameters (learning rate, depth) are configured by the practitioner.', true),
  (t4, 35, 'levels', 'mcq', 'What does AUC-ROC measure?', '["Training speed","A model''s ability to distinguish between classes across all classification thresholds","The size of the model","Memory usage"]', 'A model''s ability to distinguish between classes across all classification thresholds', 'AUC-ROC (Area Under the ROC Curve) measures discrimination ability — 0.5 is random, 1.0 is perfect.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t4, 11, 'sandbox', 'mcq', 'Mean Squared Error (MSE) is defined as:', '["Mean of absolute differences","Mean of squared differences between predictions and true values","Sum of predictions","Max error divided by n"]', 'Mean of squared differences between predictions and true values', 'MSE = (1/n) Σ(y_pred - y_true)². Squaring penalises large errors more heavily than small ones.', true),
  (t4, 12, 'sandbox', 'mcq', 'In gradient descent, the learning rate controls:', '["Number of training epochs","Size of parameter update steps","Batch size","Model architecture"]', 'Size of parameter update steps', 'Learning rate α scales the gradient. Too large → overshooting; too small → slow convergence.', true),
  (t4, 13, 'sandbox', 'mcq', 'L1 regularisation (Lasso) differs from L2 (Ridge) because L1:', '["Adds squared weights to loss","Adds absolute weights to loss and can force weights to exactly zero","Prevents overfitting better always","Requires normalised features only"]', 'Adds absolute weights to loss and can force weights to exactly zero', 'L1 penalty |w| promotes sparsity — weights can become exactly 0, performing feature selection. L2 shrinks but rarely zeros.', true),
  (t4, 14, 'sandbox', 'mcq', 'Cross-entropy loss is preferred for classification over MSE because:', '["It is computationally cheaper","It has stronger gradients for incorrect confident predictions, improving convergence","It ignores class probabilities","It works only for binary problems"]', 'It has stronger gradients for incorrect confident predictions, improving convergence', 'Cross-entropy penalises confident wrong predictions severely via log(p), providing stronger training signal than MSE.', true),
  (t4, 15, 'sandbox', 'mcq', 'What does `sklearn.model_selection.StratifiedKFold` ensure?', '["Equal fold sizes only","Each fold maintains the same class proportion as the original dataset","Random splits","Temporal ordering of folds"]', 'Each fold maintains the same class proportion as the original dataset', 'Stratified KFold preserves class distribution in each fold — critical for imbalanced datasets.', true),
  (t4, 16, 'sandbox', 'mcq', 'Stochastic Gradient Descent (SGD) differs from batch gradient descent by:', '["Using all data per update","Using one (or few) random samples per parameter update","Using no learning rate","Training without backpropagation"]', 'Using one (or few) random samples per parameter update', 'SGD updates parameters after each sample, introducing noise that can escape local minima and speeds up iterations.', true),
  (t4, 17, 'sandbox', 'mcq', 'The "kernel trick" in Support Vector Machines allows:', '["Faster training on linear problems","Implicit mapping to higher-dimensional space without computing coordinates","Removing outliers","Automatic feature selection"]', 'Implicit mapping to higher-dimensional space without computing coordinates', 'The kernel trick computes inner products in high-dimensional space via the kernel function, enabling non-linear classification efficiently.', true),
  (t4, 18, 'sandbox', 'mcq', 'In scikit-learn, what does `fit_transform()` do compared to calling `fit()` then `transform()` separately?', '["Different results","Same result but more efficient in one call","fit_transform trains only","transform() must always be called first"]', 'Same result but more efficient in one call', 'fit_transform computes statistics and applies the transformation in one pass — slightly more efficient than two separate calls.', true),
  (t4, 19, 'sandbox', 'mcq', 'Which regularisation technique randomly drops neurons during training?', '["L1","L2","Dropout","Batch normalisation"]', 'Dropout', 'Dropout randomly zeroes out neurons during training, preventing co-adaptation and acting as ensemble regularisation.', true),
  (t4, 20, 'sandbox', 'mcq', 'The ROC curve plots:', '["Precision vs Recall","True Positive Rate vs False Positive Rate at varying thresholds","Loss vs epochs","Accuracy vs model complexity"]', 'True Positive Rate vs False Positive Rate at varying thresholds', 'ROC plots TPR (sensitivity) against FPR (1-specificity) as the classification threshold varies from 0 to 1.', true),
  (t4, 21, 'sandbox', 'mcq', 'What is "feature importance" in a Random Forest?', '["Number of features used","Measure of how much each feature contributes to reducing impurity across all trees","Number of times a feature appears","Feature correlation with target"]', 'Measure of how much each feature contributes to reducing impurity across all trees', 'Feature importance aggregates how much each feature decreases impurity (e.g., Gini) when used for splits across all trees.', true),
  (t4, 22, 'sandbox', 'mcq', 'What problem does SMOTE (Synthetic Minority Over-sampling Technique) solve?', '["Missing values","Class imbalance by generating synthetic minority samples","Overfitting in deep networks","High dimensionality"]', 'Class imbalance by generating synthetic minority samples', 'SMOTE creates synthetic samples by interpolating between existing minority class examples, improving class balance.', true),
  (t4, 23, 'sandbox', 'mcq', 'In XGBoost, "boosting" refers to:', '["Increasing learning rate","Sequentially training weak learners where each focuses on previous errors","Training in parallel","Using GPU acceleration"]', 'Sequentially training weak learners where each focuses on previous errors', 'XGBoost builds trees sequentially, each fitting the residuals (gradient of loss) of the combined ensemble so far.', true),
  (t4, 24, 'sandbox', 'mcq', 'Mutual information as a feature selection metric measures:', '["Correlation between two features","How much knowing a feature reduces uncertainty about the target","Distance between feature distributions","Feature mean and variance"]', 'How much knowing a feature reduces uncertainty about the target', 'Mutual information I(X;Y) quantifies how much information a feature X shares with the target Y — non-linear relationships included.', true),
  (t4, 25, 'sandbox', 'mcq', 'What is the "elbow method" used for in K-Means clustering?', '["Choosing the learning rate","Finding the optimal number of clusters k by plotting inertia vs k","Detecting outliers","Normalising features"]', 'Finding the optimal number of clusters k by plotting inertia vs k', 'The elbow method plots within-cluster sum of squares vs k; the "elbow" point suggests the optimal k before diminishing returns.', true),
  (t4, 26, 'sandbox', 'mcq', 'Backpropagation computes gradients using:', '["Forward pass only","The chain rule of calculus applied layer by layer","Random sampling","Numerical differentiation always"]', 'The chain rule of calculus applied layer by layer', 'Backpropagation applies the chain rule backwards through the network to efficiently compute gradients for all parameters.', true),
  (t4, 27, 'sandbox', 'mcq', 'What does `early stopping` prevent in model training?', '["Underfitting by training more","Overfitting by stopping training when validation loss stops improving","Data leakage","Feature drift"]', 'Overfitting by stopping training when validation loss stops improving', 'Early stopping monitors validation performance and halts training when it degrades, preventing overfitting to training data.', true),
  (t4, 28, 'sandbox', 'mcq', 'Bayesian hyperparameter optimisation is preferred over grid search because:', '["Grid search is buggy","Bayesian optimisation builds a probabilistic model and samples promising regions, needing fewer evaluations","Bayesian is always faster","Grid search cannot handle continuous parameters"]', 'Bayesian optimisation builds a probabilistic model and samples promising regions, needing fewer evaluations', 'Bayesian optimisation uses past evaluations to model the objective function and guides search toward promising hyperparameters.', true),
  (t4, 29, 'sandbox', 'mcq', 'What is label smoothing in classification?', '["Rounding predicted probabilities","Replacing hard 0/1 labels with softer values (e.g. 0.1/0.9) to prevent overconfidence","Removing mislabelled examples","Normalising labels to [0,1]"]', 'Replacing hard 0/1 labels with softer values (e.g. 0.1/0.9) to prevent overconfidence', 'Label smoothing discourages the model from being overconfident, improving calibration and generalisation.', true),
  (t4, 30, 'sandbox', 'mcq', 'Which metric is threshold-independent and works well for imbalanced datasets?', '["Accuracy","AUC-ROC","F1-score at threshold 0.5","Precision at fixed threshold"]', 'AUC-ROC', 'AUC-ROC evaluates discrimination across all thresholds, making it robust to class imbalance and threshold choice.', true),
  (t4, 31, 'sandbox', 'mcq', 'What is the purpose of the softmax function in a multi-class classification output layer?', '["Introducing non-linearity","Converting raw logits to a probability distribution summing to 1","Normalising inputs","Applying regularisation"]', 'Converting raw logits to a probability distribution summing to 1', 'Softmax exp(z_i)/Σexp(z_j) maps logits to probabilities across classes, each between 0-1 and all summing to 1.', true),
  (t4, 32, 'sandbox', 'mcq', 'What is model calibration?', '["Setting hyperparameters","Ensuring predicted probabilities match actual empirical frequencies","Reducing model size","Fixing data leakage"]', 'Ensuring predicted probabilities match actual empirical frequencies', 'A calibrated model with P=0.7 should be correct ~70% of the time. Calibration can be improved with Platt scaling or isotonic regression.', true),
  (t4, 33, 'sandbox', 'mcq', 'Permutation feature importance works by:', '["Removing features and retraining","Randomly shuffling a feature''s values and measuring performance drop","Using feature gradients","Counting feature splits in trees"]', 'Randomly shuffling a feature''s values and measuring performance drop', 'Shuffling a feature breaks its relationship with the target. Large accuracy drop indicates high feature importance.', true),
  (t4, 34, 'sandbox', 'mcq', 'What is "concept drift" in production ML systems?', '["Model overfitting over time","The statistical properties of the target variable change over time, degrading model performance","Changing hyperparameters","Feature engineering errors"]', 'The statistical properties of the target variable change over time, degrading model performance', 'Concept drift occurs when the real-world relationship being modelled changes — models must be monitored and retrained.', true),
  (t4, 35, 'sandbox', 'mcq', 'In PyTorch, what does `optimizer.zero_grad()` do before calling `loss.backward()`?', '["Initialises model weights","Clears accumulated gradients from the previous iteration","Sets learning rate to zero","Freezes model parameters"]', 'Clears accumulated gradients from the previous iteration', 'PyTorch accumulates gradients by default. zero_grad() clears them before each backward pass to prevent gradient accumulation from multiple batches.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t5, 11, 'story', 'mcq', 'ARIA says a neural network is inspired by the human brain. What are the brain''s building blocks that inspired it?', '["Circuits","Neurons","Pixels","Programs"]', 'Neurons', 'Artificial neural networks are inspired by biological neurons — interconnected cells that pass signals to each other.', true),
  (t5, 12, 'story', 'mcq', 'A neural network has an INPUT layer, HIDDEN layers, and an OUTPUT layer. What does the input layer do?', '["Makes the final decision","Receives the raw data","Trains the network","Stores the answers"]', 'Receives the raw data', 'The input layer receives the data (like pixels of an image) and passes it into the network for processing.', true),
  (t5, 13, 'story', 'mcq', 'What does the OUTPUT layer of a neural network produce?', '["More hidden layers","The network''s final answer or prediction","The training data","Random numbers"]', 'The network''s final answer or prediction', 'The output layer produces the final result — a classification, a number, or a probability.', true),
  (t5, 14, 'story', 'mcq', 'ARIA''s neural network makes a wrong guess. It adjusts itself to do better. This adjustment process is called:', '["Ignoring the error","Backpropagation","Overfitting","Cleaning data"]', 'Backpropagation', 'Backpropagation sends error information backwards through the network to adjust weights and improve predictions.', true),
  (t5, 15, 'story', 'mcq', 'Running through ALL the training data once during neural network training is called one:', '["Batch","Layer","Epoch","Neuron"]', 'Epoch', 'An epoch is one complete pass through the entire training dataset. Multiple epochs are usually needed for good learning.', true),
  (t5, 16, 'story', 'mcq', 'ARIA''s network has weights connecting neurons. If a connection has a HIGH weight, it means:', '["The connection is broken","That connection has more influence on the output","The neuron is bigger","The layer is deeper"]', 'That connection has more influence on the output', 'Weights determine how strongly one neuron influences the next. Higher weights mean stronger influence on the output.', true),
  (t5, 17, 'story', 'mcq', 'What does a neural network DO when it is "learning"?', '["Downloads new data","Adjusts its connection weights to reduce mistakes","Grows more neurons","Reboots itself"]', 'Adjusts its connection weights to reduce mistakes', 'Learning in neural networks means updating weights based on errors, gradually improving predictions.', true),
  (t5, 18, 'story', 'mcq', 'ARIA feeds 32 training images at once to her neural network. This group of 32 is called a:', '["Epoch","Layer","Batch","Cluster"]', 'Batch', 'A batch is a subset of training data processed together in one forward/backward pass during training.', true),
  (t5, 19, 'story', 'mcq', 'What is the role of HIDDEN layers in a neural network?', '["They store training data","They learn complex patterns from the data","They show the final answer","They speed up the computer"]', 'They learn complex patterns from the data', 'Hidden layers extract increasingly complex features from the data — early layers find simple patterns, later layers find complex ones.', true),
  (t5, 20, 'story', 'mcq', 'ARIA''s simple neural network has 1 input neuron, 1 hidden neuron, and 1 output neuron. How many layers does it have?', '["1","2","3","4"]', '3', 'Three layers: input, hidden, and output — even the simplest network has all three types.', true),
  (t5, 21, 'story', 'mcq', 'A "deep" neural network means it has:', '["A very large input","Many hidden layers","Millions of training examples","A special chip"]', 'Many hidden layers', 'Deep learning refers to neural networks with many hidden layers — "deep" refers to this depth.', true),
  (t5, 22, 'story', 'mcq', 'ARIA''s neural network improves every time it sees more training examples. Why?', '["Each example makes it larger","More examples help weights adjust more accurately","New examples replace old ones","Training data is deleted after use"]', 'More examples help weights adjust more accurately', 'More training data provides more learning signal, allowing the network to fine-tune weights for better generalisation.', true),
  (t5, 23, 'story', 'mcq', 'What does an "activation function" in a neuron decide?', '["The colour of the neuron","Whether and how strongly the neuron fires (passes signal forward)","The number of weights","The size of the network"]', 'Whether and how strongly the neuron fires (passes signal forward)', 'Activation functions introduce non-linearity, deciding how much signal a neuron passes to the next layer.', true),
  (t5, 24, 'story', 'mcq', 'ARIA notices her neural network works great on training data but badly on new data. This problem is called:', '["Underfitting","Overfitting","Perfect training","Deep learning"]', 'Overfitting', 'Overfitting means the network memorised training data instead of learning general patterns.', true),
  (t5, 25, 'story', 'mcq', 'Which type of neural network is especially good at recognising images?', '["Recurrent Neural Network","Convolutional Neural Network","Simple perceptron","Linear regression model"]', 'Convolutional Neural Network', 'CNNs use special layers (convolutions) that detect visual patterns like edges, shapes, and textures in images.', true),
  (t5, 26, 'story', 'mcq', 'ARIA''s network has neurons in layer 1 connected to ALL neurons in layer 2. This is called a:', '["Sparse layer","Fully connected (dense) layer","Convolutional layer","Recurrent layer"]', 'Fully connected (dense) layer', 'Dense/fully-connected layers connect every neuron in one layer to every neuron in the next layer.', true),
  (t5, 27, 'story', 'mcq', 'What is a "bias" value in a neural network neuron?', '["An unfair opinion","An extra value added to help the neuron activate at the right level","The number of connections","The learning rate"]', 'An extra value added to help the neuron activate at the right level', 'Bias allows a neuron to shift its activation threshold, giving the network more flexibility to fit patterns.', true),
  (t5, 28, 'story', 'mcq', 'In neural network training, "loss" represents:', '["How deep the network is","How wrong the network''s predictions are","The number of layers","The batch size"]', 'How wrong the network''s predictions are', 'Loss (or cost) measures the difference between predictions and correct answers. Training aims to minimise this.', true),
  (t5, 29, 'story', 'mcq', 'ARIA''s network sees each training image 10 times (10 epochs). After the last epoch, what should have happened to the loss?', '["Stayed the same","Increased","Decreased (the network learned better)","Disappeared completely"]', 'Decreased (the network learned better)', 'As training progresses over multiple epochs, the loss should decrease as the network''s weights improve.', true),
  (t5, 30, 'story', 'mcq', 'Which type of neural network is designed for sequential data like sentences or time series?', '["Convolutional Neural Network","Recurrent Neural Network","Simple perceptron","Random Forest"]', 'Recurrent Neural Network', 'RNNs have connections that loop back, giving them "memory" — useful for sequences where order matters.', true),
  (t5, 31, 'story', 'mcq', 'ARIA''s neural network has too many layers and neurons for a simple task. This makes it:', '["Faster","More likely to overfit and use too much memory","Better at everything","Simpler to train"]', 'More likely to overfit and use too much memory', 'Excessively large networks memorise training data (overfit) and waste computational resources.', true),
  (t5, 32, 'story', 'mcq', 'Training a neural network requires a lot of:', '["Paper","Computational power (CPU/GPU)","Physical space","Human supervision for every example"]', 'Computational power (CPU/GPU)', 'Neural network training involves millions of floating-point operations — GPUs are used to accelerate this.', true),
  (t5, 33, 'story', 'mcq', 'What connects two neurons in a neural network?', '["A wire with a label","A weighted connection","A function","A memory cell"]', 'A weighted connection', 'Neurons are connected by edges with weights — these weights are the parameters learned during training.', true),
  (t5, 34, 'story', 'mcq', 'ARIA uses a pre-trained network and retrains it on her new data. This technique is called:', '["Starting from scratch","Transfer learning","Reinforcement learning","Unsupervised learning"]', 'Transfer learning', 'Transfer learning reuses knowledge from a pre-trained model, fine-tuning it on new data — much faster than training from scratch.', true),
  (t5, 35, 'story', 'mcq', 'Why might ARIA add more hidden layers to her neural network?', '["To make it look more complex","To help it learn more complex patterns in the data","To reduce training time","To decrease the loss instantly"]', 'To help it learn more complex patterns in the data', 'Deeper networks can learn hierarchical representations — simple features in early layers, complex patterns in later layers.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t5, 11, 'levels', 'mcq', 'The ReLU activation function is defined as:', '["sigmoid(x)","max(0, x)","tanh(x)","1/(1+e^-x)"]', 'max(0, x)', 'ReLU (Rectified Linear Unit) outputs x if x > 0, otherwise 0. It is simple and avoids vanishing gradients for positive values.', true),
  (t5, 12, 'levels', 'mcq', 'The sigmoid activation function outputs values in the range:', '["(-∞, ∞)","(0, 1)","(-1, 1)","{0, 1}"]', '(0, 1)', 'Sigmoid maps any real number to (0, 1) — useful for binary classification output layers as it represents probability.', true),
  (t5, 13, 'levels', 'mcq', 'What is the vanishing gradient problem?', '["Gradients become too large","Gradients become very small as they propagate back through many layers, slowing learning in early layers","The network forgets training data","Weights become negative"]', 'Gradients become very small as they propagate back through many layers, slowing learning in early layers', 'In deep networks with sigmoid/tanh, gradients shrink as they backpropagate, causing early layers to learn very slowly.', true),
  (t5, 14, 'levels', 'mcq', 'Why does ReLU help with the vanishing gradient problem?', '["It has no gradient","Its gradient is 1 for positive inputs, preventing shrinkage","It is always positive","It clips gradients"]', 'Its gradient is 1 for positive inputs, preventing shrinkage', 'ReLU''s derivative is 1 for x > 0, so gradients are not reduced as they flow back through ReLU activations.', true),
  (t5, 15, 'levels', 'mcq', 'Dropout regularisation works by:', '["Reducing the learning rate","Randomly zeroing out a fraction of neurons during each training pass","Removing layers","Adding L2 penalty"]', 'Randomly zeroing out a fraction of neurons during each training pass', 'Dropout prevents neurons from co-adapting by randomly disabling them during training, acting as an ensemble of networks.', true),
  (t5, 16, 'levels', 'mcq', 'Batch normalisation normalises the inputs to each layer to:', '["Random values","Zero mean and unit variance","Values between 0 and 1 only","Their maximum values"]', 'Zero mean and unit variance', 'Batch norm standardises layer inputs within each mini-batch, stabilising training and allowing higher learning rates.', true),
  (t5, 17, 'levels', 'mcq', 'What is the difference between an epoch and a batch?', '["They are the same","An epoch is one full pass through training data; a batch is a small subset processed at once","A batch is always 32 samples","Epochs are for validation only"]', 'An epoch is one full pass through training data; a batch is a small subset processed at once', 'One epoch = all training data seen once. A batch = a chunk of data used in one forward/backward pass.', true),
  (t5, 18, 'levels', 'mcq', 'In a convolutional neural network (CNN), what does a filter (kernel) detect?', '["Network connections","Local patterns like edges, textures, or shapes in a region of the input","Random noise","Output classes"]', 'Local patterns like edges, textures, or shapes in a region of the input', 'CNN filters slide across the input, detecting specific local patterns. Early filters find edges; later filters find complex shapes.', true),
  (t5, 19, 'levels', 'mcq', 'A pooling layer in a CNN is used to:', '["Add more parameters","Reduce spatial dimensions while retaining important features","Increase image resolution","Apply activation functions"]', 'Reduce spatial dimensions while retaining important features', 'Pooling (max/average) downsamples feature maps, reducing computation and providing spatial invariance.', true),
  (t5, 20, 'levels', 'mcq', 'Which problem does an LSTM (Long Short-Term Memory) network solve compared to a basic RNN?', '["Vanishing gradient and inability to remember long-term dependencies","Slow training speed","Too many parameters","Inability to process sequential data"]', 'Vanishing gradient and inability to remember long-term dependencies', 'LSTMs use gates (input, forget, output) to selectively remember and forget information over long sequences.', true),
  (t5, 21, 'levels', 'mcq', 'Transfer learning involves:', '["Training a new model from scratch","Reusing a model trained on one task as the starting point for a different task","Using labelled and unlabelled data simultaneously","Combining multiple models"]', 'Reusing a model trained on one task as the starting point for a different task', 'Transfer learning leverages features learned on large datasets (e.g., ImageNet) for related tasks with less data.', true),
  (t5, 22, 'levels', 'mcq', 'The softmax function in the output layer converts raw scores to:', '["Binary 0/1 values","A probability distribution over all classes","Negative values","Values greater than 1"]', 'A probability distribution over all classes', 'Softmax exp(z_i)/Σexp(z_j) converts logits to probabilities that sum to 1, representing class likelihoods.', true),
  (t5, 23, 'levels', 'mcq', 'What does "number of parameters" in a neural network represent?', '["Number of training examples","Total count of weights and biases that are learned during training","Number of layers","Number of neurons only"]', 'Total count of weights and biases that are learned during training', 'Parameters are the learnable values (weights + biases). More parameters = more capacity but also more risk of overfitting.', true),
  (t5, 24, 'levels', 'mcq', 'Which activation function is commonly used for BINARY classification output neurons?', '["ReLU","Softmax","Sigmoid","tanh"]', 'Sigmoid', 'Sigmoid outputs values in (0,1), naturally interpreted as probability for binary classification.', true),
  (t5, 25, 'levels', 'mcq', 'The learning rate in gradient descent should be:', '["As large as possible","As small as possible","Carefully tuned — too large overshoots, too small is slow","Always 0.001"]', 'Carefully tuned — too large overshoots, too small is slow', 'Learning rate is critical: too high causes divergence (overshooting minimum), too low makes training impractically slow.', true),
  (t5, 26, 'levels', 'mcq', 'What is weight initialisation, and why does it matter?', '["Setting weights to the final values","Setting initial weight values before training — poor initialisation can cause vanishing/exploding gradients","Setting learning rate","Defining layer sizes"]', 'Setting initial weight values before training — poor initialisation can cause vanishing/exploding gradients', 'Starting with all-zero weights makes neurons identical (symmetry problem). Good initialisation (e.g., Xavier) promotes learning.', true),
  (t5, 27, 'levels', 'mcq', 'What is the "exploding gradient" problem?', '["Gradients becoming too small","Gradients growing exponentially during backpropagation, destabilising training","Too many neurons firing","Loss becoming negative"]', 'Gradients growing exponentially during backpropagation, destabilising training', 'In deep/recurrent networks, gradients can grow exponentially, causing wildly large weight updates. Gradient clipping addresses this.', true),
  (t5, 28, 'levels', 'mcq', 'In a fully connected layer with 100 input neurons and 50 output neurons, how many weight parameters are there?', '["150","5000","100","50"]', '5000', 'Each of 50 output neurons connects to all 100 inputs: 50 × 100 = 5000 weight parameters (plus 50 biases).', true),
  (t5, 29, 'levels', 'mcq', 'What is a "pre-trained model"?', '["A model not yet trained","A model trained on a large dataset that can be fine-tuned for specific tasks","A model with fixed weights that cannot learn","A model trained without data"]', 'A model trained on a large dataset that can be fine-tuned for specific tasks', 'Pre-trained models (like VGG, BERT) come with learned weights from large datasets, ready for transfer learning.', true),
  (t5, 30, 'levels', 'mcq', 'GRU (Gated Recurrent Unit) compared to LSTM:', '["Has more gates","Has fewer gates and parameters, often comparable performance","Cannot handle sequences","Is only used for images"]', 'Has fewer gates and parameters, often comparable performance', 'GRU simplifies LSTM with just reset and update gates, fewer parameters, and often similar performance on many tasks.', true),
  (t5, 31, 'levels', 'mcq', 'What is the purpose of the "forget gate" in an LSTM?', '["Adding new information","Deciding what information to discard from the cell state","Producing the output","Resetting all memory"]', 'Deciding what information to discard from the cell state', 'The forget gate learns to selectively erase outdated information from the cell state to handle long sequences.', true),
  (t5, 32, 'levels', 'mcq', 'In a CNN, "padding" is used to:', '["Add more filters","Preserve spatial dimensions by adding border pixels before convolution","Speed up convolution","Remove background from images"]', 'Preserve spatial dimensions by adding border pixels before convolution', 'Zero-padding adds rows/columns of zeros around the input, so the output feature map retains the same spatial size.', true),
  (t5, 33, 'levels', 'mcq', 'What is the "stride" in a convolutional layer?', '["Number of filters","Number of pixels the filter moves at each step","Kernel size","Padding amount"]', 'Number of pixels the filter moves at each step', 'Stride controls how far the filter slides at each step. Stride 2 halves the output dimensions compared to stride 1.', true),
  (t5, 34, 'levels', 'mcq', 'Which optimiser adapts the learning rate individually for each parameter?', '["SGD","SGD with momentum","Adam","Gradient descent"]', 'Adam', 'Adam (Adaptive Moment Estimation) maintains per-parameter learning rates using first and second moment estimates of gradients.', true),
  (t5, 35, 'levels', 'mcq', 'What is "fine-tuning" a pre-trained model?', '["Training from scratch","Continuing training on new task-specific data while possibly unfreezing some layers","Only changing the output layer architecture","Removing layers"]', 'Continuing training on new task-specific data while possibly unfreezing some layers', 'Fine-tuning updates pre-trained weights on new data, allowing the model to adapt its learned representations to the new task.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t5, 11, 'sandbox', 'mcq', 'In PyTorch, what is the difference between `nn.Module` and `nn.functional`?', '["No difference","nn.Module holds parameters and state; nn.functional provides stateless functions","nn.functional is faster always","nn.Module is deprecated"]', 'nn.Module holds parameters and state; nn.functional provides stateless functions', 'nn.Module classes store learnable parameters. nn.functional functions apply operations statelessly — used inside forward() methods.', true),
  (t5, 12, 'sandbox', 'mcq', 'What does Xavier (Glorot) initialisation set weights to?', '["All zeros","Random values scaled by 1/sqrt(fan_in + fan_out) to maintain activation variance","Random normal with std=1","Uniform [-1, 1]"]', 'Random values scaled by 1/sqrt(fan_in + fan_out) to maintain activation variance', 'Xavier initialisation keeps activation variance consistent across layers, preventing vanishing/exploding activations in deep networks.', true),
  (t5, 13, 'sandbox', 'mcq', 'Gradient clipping in RNN training addresses which problem?', '["Vanishing gradients","Exploding gradients by capping gradient norm to a maximum value","Overfitting","Slow convergence"]', 'Exploding gradients by capping gradient norm to a maximum value', 'Gradient clipping rescales gradients when their norm exceeds a threshold, preventing the catastrophic weight updates of exploding gradients.', true),
  (t5, 14, 'sandbox', 'mcq', 'In a Transformer, the self-attention mechanism computes attention scores using:', '["Convolution operations","Dot products of Query and Key vectors, scaled by sqrt(d_k)","Recurrent hidden states","Pooling operations"]', 'Dot products of Query and Key vectors, scaled by sqrt(d_k)', 'Self-attention: Attention(Q,K,V) = softmax(QK^T/√d_k)V. Scaling by √d_k prevents dot products from growing too large in high dimensions.', true),
  (t5, 15, 'sandbox', 'mcq', 'What is positional encoding in Transformers used for?', '["Adding noise for regularisation","Encoding position information since Transformers have no inherent sequence order","Normalising input values","Replacing attention heads"]', 'Encoding position information since Transformers have no inherent sequence order', 'Transformers process all tokens in parallel with no recurrence — positional encodings inject sequence position information.', true),
  (t5, 16, 'sandbox', 'mcq', 'Batch normalisation during inference (test time) uses:', '["Current batch statistics","Running mean and variance accumulated during training","Random statistics","Per-sample statistics"]', 'Running mean and variance accumulated during training', 'At inference, batch norm uses the exponential moving average of mean and variance recorded during training — not batch statistics.', true),
  (t5, 17, 'sandbox', 'mcq', 'The "dying ReLU" problem occurs when:', '["ReLU neurons output too large values","Many neurons permanently output 0 because their weights drive inputs negative","Gradients explode in ReLU layers","ReLU is used in output layers"]', 'Many neurons permanently output 0 because their weights drive inputs negative', 'If a neuron''s input is always negative, ReLU always outputs 0 and receives no gradient — the neuron is "dead" and never updates.', true),
  (t5, 18, 'sandbox', 'mcq', 'Leaky ReLU addresses the dying ReLU problem by:', '["Using sigmoid instead","Allowing a small non-zero gradient for negative inputs (e.g., 0.01x)","Clipping all values to [0,1]","Removing the activation function"]', 'Allowing a small non-zero gradient for negative inputs (e.g., 0.01x)', 'Leaky ReLU = max(0.01x, x). The small slope for x<0 ensures neurons always receive gradient and can recover.', true),
  (t5, 19, 'sandbox', 'mcq', 'In a CNN, the output spatial size after convolution is: (Input - Filter + 2*Padding) / Stride + 1. For input=28, filter=3, padding=0, stride=1:', '["26","28","30","24"]', '26', '(28 - 3 + 0) / 1 + 1 = 26. The spatial dimension shrinks by filter_size - 1 without padding.', true),
  (t5, 20, 'sandbox', 'mcq', 'What is multi-head attention in Transformers?', '["Using multiple attention layers sequentially","Running attention multiple times in parallel with different learned projections, then concatenating","Using different activation functions","Multiple decoders"]', 'Running attention multiple times in parallel with different learned projections, then concatenating', 'Multi-head attention allows the model to jointly attend to information from different representation subspaces simultaneously.', true),
  (t5, 21, 'sandbox', 'mcq', 'Which technique uses a frozen pre-trained backbone and only trains a small adapter module?', '["Fine-tuning all layers","Adapter fine-tuning (Parameter-Efficient Fine-Tuning)","Training from scratch","Dropout only"]', 'Adapter fine-tuning (Parameter-Efficient Fine-Tuning)', 'Adapter methods (e.g., LoRA) insert small trainable modules while keeping the pre-trained backbone frozen — efficient for LLMs.', true),
  (t5, 22, 'sandbox', 'mcq', 'What does `model.eval()` do in PyTorch?', '["Evaluates model accuracy","Disables dropout and sets batch norm to use running statistics","Freezes all parameters","Runs the model on test data"]', 'Disables dropout and sets batch norm to use running statistics', 'model.eval() switches the model to inference mode: dropout is disabled and batch norm uses accumulated statistics.', true),
  (t5, 23, 'sandbox', 'mcq', 'Skip connections (residual connections) in ResNet allow:', '["Skipping entire layers during inference","Gradients to flow directly through identity mappings, alleviating vanishing gradients in very deep networks","Sharing weights between layers","Reducing input dimensions"]', 'Gradients to flow directly through identity mappings, alleviating vanishing gradients in very deep networks', 'ResNet''s H(x) = F(x) + x means gradients can flow through the identity shortcut unchanged, enabling 100+ layer training.', true),
  (t5, 24, 'sandbox', 'mcq', 'What is the purpose of the `with torch.no_grad():` context manager?', '["Prevents model updates","Disables gradient computation for inference, reducing memory and computation","Freezes batch norm","Enables model.eval() mode"]', 'Disables gradient computation for inference, reducing memory and computation', 'no_grad() skips building the computation graph for gradient tracking — essential during validation/inference for efficiency.', true),
  (t5, 25, 'sandbox', 'mcq', 'In attention mechanism, the "value" vector is used to:', '["Determine which tokens to attend to","Compute attention scores","Produce the weighted output aggregated by attention weights","Normalise the query"]', 'Produce the weighted output aggregated by attention weights', 'Attention output = Σ(attention_weight_i × Value_i). Values carry the content; attention weights determine how much of each.', true),
  (t5, 26, 'sandbox', 'mcq', 'What is the computational complexity of standard self-attention with sequence length n?', '["O(n)","O(n log n)","O(n²)","O(n³)"]', 'O(n²)', 'Self-attention computes all pairwise interactions between tokens: n queries × n keys = O(n²) complexity.', true),
  (t5, 27, 'sandbox', 'mcq', 'Layer normalisation vs batch normalisation: layer norm normalises across:', '["The batch dimension","Features within a single sample","Both batch and feature dimensions","Only spatial dimensions"]', 'Features within a single sample', 'Layer norm normalises across the feature dimension for each sample independently — works well for NLP where batch sizes vary.', true),
  (t5, 28, 'sandbox', 'mcq', 'What is the "weight decay" hyperparameter equivalent to in regularisation terms?', '["L1 regularisation","L2 regularisation (Ridge)","Dropout rate","Learning rate schedule"]', 'L2 regularisation (Ridge)', 'Weight decay adds λ||w||² to the loss, penalising large weights — mathematically equivalent to L2 regularisation.', true),
  (t5, 29, 'sandbox', 'mcq', 'Depthwise separable convolutions in MobileNet reduce computation by:', '["Using smaller filters","Separating spatial filtering and channel mixing into two steps, reducing parameters and FLOPs","Using larger strides","Removing pooling layers"]', 'Separating spatial filtering and channel mixing into two steps, reducing parameters and FLOPs', 'Depthwise separable conv = depthwise conv (per channel) + pointwise conv (1×1). This reduces computation by ~8-9x vs standard conv.', true),
  (t5, 30, 'sandbox', 'mcq', 'In the context of LLMs, what is "perplexity"?', '["Model size in parameters","Exponential of the average negative log-likelihood per token — lower means better language model","Training loss value","Number of attention heads"]', 'Exponential of the average negative log-likelihood per token — lower means better language model', 'Perplexity = exp(average cross-entropy loss per token). A lower value means the model is less "surprised" by text.', true),
  (t5, 31, 'sandbox', 'mcq', 'What is "knowledge distillation" in neural networks?', '["Compressing data","Training a smaller student model to mimic the soft outputs of a larger teacher model","Transfer learning from a different domain","Pruning unused weights"]', 'Training a smaller student model to mimic the soft outputs of a larger teacher model', 'Knowledge distillation trains a compact student to match the teacher''s probability distributions, preserving knowledge in a smaller model.', true),
  (t5, 32, 'sandbox', 'mcq', 'Sparse attention patterns (as in Longformer) address which Transformer limitation?', '["Slow batch norm","O(n²) attention scaling for very long sequences","Vanishing gradients","Lack of positional encoding"]', 'O(n²) attention scaling for very long sequences', 'Sparse attention (local + global patterns) reduces complexity from O(n²) to O(n), enabling Transformers on very long documents.', true),
  (t5, 33, 'sandbox', 'mcq', 'In model quantisation, INT8 inference vs FP32 training typically results in:', '["Same accuracy, slower speed","Lower memory and faster inference with minor accuracy tradeoff","Higher accuracy","No practical difference"]', 'Lower memory and faster inference with minor accuracy tradeoff', 'INT8 uses 1/4 the memory of FP32 and runs faster on modern hardware, with typically <1% accuracy loss after calibration.', true),
  (t5, 34, 'sandbox', 'mcq', 'What is "gradient accumulation" used for in training?', '["Increasing learning rate","Simulating larger batch sizes when GPU memory is insufficient for the full batch","Preventing overfitting","Speeding up backpropagation"]', 'Simulating larger batch sizes when GPU memory is insufficient for the full batch', 'Gradient accumulation sums gradients over multiple small batches before updating weights, effectively simulating a larger batch.', true),
  (t5, 35, 'sandbox', 'mcq', 'The attention mask in a Transformer decoder (causal mask) prevents:', '["Attending to padding tokens","Attending to future positions — ensures autoregressive generation","Gradient flow through attention","Multi-head computations"]', 'Attending to future positions — ensures autoregressive generation', 'The causal mask sets future positions to -infinity before softmax, ensuring each token only attends to itself and prior tokens.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t6, 11, 'story', 'mcq', 'ARIA wants to teach her computer to read. First, it splits text into individual words. This step is called:', '["Sorting","Tokenisation","Classifying","Indexing"]', 'Tokenisation', 'Tokenisation splits text into tokens (words, characters, or subwords) that the computer can process.', true),
  (t6, 12, 'story', 'mcq', 'ARIA''s computer removes common words like "the", "is", "a" from text because they carry little meaning. These words are called:', '["Keywords","Stop words","Verbs","Root words"]', 'Stop words', 'Stop words are very common words that are often removed in NLP to focus on the meaningful content words.', true),
  (t6, 13, 'story', 'mcq', 'ARIA''s computer reads a review and decides if it''s HAPPY or SAD. What NLP task is this?', '["Translation","Summarisation","Sentiment analysis","Search"]', 'Sentiment analysis', 'Sentiment analysis identifies the emotional tone of text — positive, negative, or neutral.', true),
  (t6, 14, 'story', 'mcq', 'ARIA asks her computer "What is the capital of France?" and it answers "Paris." This is called:', '["Sentiment analysis","Question answering","Translation","Tokenisation"]', 'Question answering', 'Question answering systems understand questions in natural language and retrieve or generate the correct answer.', true),
  (t6, 15, 'story', 'mcq', 'ARIA''s computer reads a long article and writes a short version. This is called:', '["Translation","Stemming","Summarisation","Classification"]', 'Summarisation', 'Text summarisation condenses a long piece of text into a shorter version covering the key points.', true),
  (t6, 16, 'story', 'mcq', 'Which of the following is an example of NLP in everyday life?', '["Calculator apps","Spell checkers and voice assistants","Photo filters","Video games"]', 'Spell checkers and voice assistants', 'Spell checkers and voice assistants (like Siri) use NLP to understand and process human language.', true),
  (t6, 17, 'story', 'mcq', 'ARIA''s robot says "I ate a bat" — but does she mean the animal or a cricket bat? This language confusion is called:', '["Tokenisation","Ambiguity","Stemming","Translation"]', 'Ambiguity', 'Language ambiguity is when a word or sentence has multiple possible meanings — a major challenge in NLP.', true),
  (t6, 18, 'story', 'mcq', 'ARIA''s computer turns "running", "runs", "ran" all into the same base form "run". This process is called:', '["Tokenisation","Stop word removal","Stemming/Lemmatisation","Sentiment analysis"]', 'Stemming/Lemmatisation', 'Stemming/lemmatisation reduces words to their base form, so different versions of a word are treated as the same.', true),
  (t6, 19, 'story', 'mcq', 'ARIA translates a French email to English automatically. Which NLP task is this?', '["Summarisation","Machine translation","Sentiment analysis","Tokenisation"]', 'Machine translation', 'Machine translation converts text from one language to another automatically using NLP models.', true),
  (t6, 20, 'story', 'mcq', 'ARIA''s chatbot uses NLP to understand what she types. What makes chatbots hard to build?', '["Chatbots need to be physically big","Understanding the meaning and context of human language is very complex","Chatbots need special keyboards","They only work in English"]', 'Understanding the meaning and context of human language is very complex', 'Language has context, sarcasm, ambiguity, and cultural nuance — all of which are very challenging for computers.', true),
  (t6, 21, 'story', 'mcq', 'ARIA types "I am feeling great!" to her sentiment analyser. What result should she expect?', '["Negative","Neutral","Positive","Error"]', 'Positive', 'The phrase "feeling great" has clearly positive sentiment — the analyser should classify it as positive.', true),
  (t6, 22, 'story', 'mcq', 'In NLP, a "corpus" is:', '["A type of grammar error","A large collection of text used to train language models","A translation tool","A type of chatbot"]', 'A large collection of text used to train language models', 'A corpus (plural: corpora) is a large, structured collection of text or speech used for training NLP models.', true),
  (t6, 23, 'story', 'mcq', 'ARIA''s computer finds that "bank" can mean a river bank or a money bank. How does it decide which meaning?', '["It picks randomly","It uses the surrounding words (context) to determine meaning","It always picks the first meaning","It ignores the word"]', 'It uses the surrounding words (context) to determine meaning', 'Context disambiguates word meanings — nearby words like "river" or "loan" clarify which sense of "bank" is intended.', true),
  (t6, 24, 'story', 'mcq', 'Which of these is NOT an NLP task?', '["Translating text","Recognising speech","Sorting numbers in a list","Answering questions from text"]', 'Sorting numbers in a list', 'NLP tasks involve natural language. Sorting numbers is a pure algorithmic task with no language understanding needed.', true),
  (t6, 25, 'story', 'mcq', 'ARIA''s voice assistant converts her spoken words to text. This technology is called:', '["Text-to-speech","Speech recognition (speech-to-text)","Translation","Summarisation"]', 'Speech recognition (speech-to-text)', 'Speech recognition (ASR) converts spoken audio into written text — used in voice assistants and transcription services.', true),
  (t6, 26, 'story', 'mcq', 'A chatbot that gives the same answer no matter what you type is NOT using NLP. Why not?', '["It is too smart","It does not actually understand language — real NLP analyses the meaning of each message","It is too slow","It costs too much"]', 'It does not actually understand language — real NLP analyses the meaning of each message', 'True NLP systems process and understand the input text. A hardcoded response ignores the content entirely.', true),
  (t6, 27, 'story', 'mcq', 'ARIA''s computer automatically labels "London", "Marie Curie", and "Monday" in a sentence as place, person, date. This is called:', '["Tokenisation","Named Entity Recognition","Summarisation","Stemming"]', 'Named Entity Recognition', 'Named Entity Recognition (NER) identifies and classifies named entities in text: people, places, dates, organisations, etc.', true),
  (t6, 28, 'story', 'mcq', 'Which language-related task helps search engines understand your query?', '["Image recognition","Natural Language Processing","Sorting algorithms","Circuit design"]', 'Natural Language Processing', 'Search engines use NLP to understand what users are really looking for, beyond simple keyword matching.', true),
  (t6, 29, 'story', 'mcq', 'ARIA trains her model on English text only. Will it understand French text well?', '["Yes, all languages are the same to computers","No, it only learned patterns from English","Yes if the words are long enough","Only if French is in the training corpus"]', 'Only if French is in the training corpus', 'NLP models learn patterns from their training data. A model trained only on English will not understand French unless French was included.', true),
  (t6, 30, 'story', 'mcq', 'What is "natural language" in NLP?', '["A programming language","Human languages like English, Spanish, or Mandarin","Computer code","Morse code"]', 'Human languages like English, Spanish, or Mandarin', 'Natural language refers to the languages humans speak and write naturally, as opposed to formal programming languages.', true),
  (t6, 31, 'story', 'mcq', 'ARIA''s model learns that words used in similar situations tend to have similar meanings. This idea helps create:', '["Decision trees","Word embeddings","Hash tables","Sorting algorithms"]', 'Word embeddings', 'Word embeddings represent words as vectors where similar-meaning words are close together in the vector space.', true),
  (t6, 32, 'story', 'mcq', 'Auto-complete on your phone predicts the next word. This is an example of:', '["Image recognition","Sentiment analysis","Language modelling","Sorting"]', 'Language modelling', 'Language models learn the probability of word sequences, enabling them to predict the most likely next word.', true),
  (t6, 33, 'story', 'mcq', 'ARIA notices her spam filter mistakenly marks IMPORTANT emails as spam. This error is called:', '["A true positive","A false positive","A true negative","A false negative"]', 'A false positive', 'A false positive: the system predicted "spam" (positive) but the email was not spam (actually negative).', true),
  (t6, 34, 'story', 'mcq', 'Text classification assigns a category to a piece of text. Which of these is a text classification task?', '["Translating English to French","Labelling emails as spam or not spam","Converting speech to text","Finding spelling errors"]', 'Labelling emails as spam or not spam', 'Spam detection is a binary text classification task — assigning the label "spam" or "not spam" to each email.', true),
  (t6, 35, 'story', 'mcq', 'ARIA wants to find all sentences with the word "robot" in a big text file. What NLP technique would help?', '["Text summarisation","Keyword search / information retrieval","Speech recognition","Sentiment analysis"]', 'Keyword search / information retrieval', 'Information retrieval systems search large text collections to find documents or sentences containing specified terms.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t6, 11, 'levels', 'mcq', 'TF-IDF stands for:', '["Text Feature - Information Data Format","Term Frequency - Inverse Document Frequency","Text Filter - Index Data Function","Top Feature - Inverted Document File"]', 'Term Frequency - Inverse Document Frequency', 'TF-IDF measures how important a word is to a document relative to a corpus — high TF but low IDF means common but irrelevant.', true),
  (t6, 12, 'levels', 'mcq', 'In TF-IDF, the IDF component is LOW for a word that appears:', '["In very few documents","In almost every document in the corpus","Only in the query","Multiple times in one document"]', 'In almost every document in the corpus', 'IDF = log(N/df). If a word appears in many documents (high df), its IDF is low — it is not distinctive.', true),
  (t6, 13, 'levels', 'mcq', 'A bag-of-words model represents text as:', '["A sequence of word embeddings","A vector of word counts ignoring word order","A tree structure","A probability distribution"]', 'A vector of word counts ignoring word order', 'Bag-of-words counts word occurrences in a document, discarding grammar and word order information.', true),
  (t6, 14, 'levels', 'mcq', 'Stemming reduces "computing" to "comput". Lemmatisation would reduce it to:', '["comput","compute","computer","computing"]', 'compute', 'Lemmatisation uses vocabulary knowledge to return the proper base form (lemma). "computing" → "compute", not just a chopped stem.', true),
  (t6, 15, 'levels', 'mcq', 'Named Entity Recognition (NER) identifies which of the following in text?', '["Grammar rules","Sentiment polarity","People, organisations, and locations","Word frequencies"]', 'People, organisations, and locations', 'NER extracts and classifies named entities: persons (Marie Curie), organisations (NASA), locations (Paris), dates, etc.', true),
  (t6, 16, 'levels', 'mcq', 'N-gram language models use the previous N-1 words to predict the next word. A bigram model uses:', '["0 previous words","1 previous word","2 previous words","The full sentence"]', '1 previous word', 'Bigram = 2-gram. It conditions on the previous 1 word to predict the next. Trigram uses previous 2 words.', true),
  (t6, 17, 'levels', 'mcq', 'Part-of-speech (POS) tagging labels each word with its grammatical role. "quickly" would be tagged as:', '["Noun","Verb","Adjective","Adverb"]', 'Adverb', '"Quickly" modifies a verb and describes how an action is done — it is an adverb.', true),
  (t6, 18, 'levels', 'mcq', 'Dependency parsing creates a tree showing:', '["Word frequencies","Grammatical relationships between words (e.g., subject-verb-object)","Sentiment scores","Word embeddings"]', 'Grammatical relationships between words (e.g., subject-verb-object)', 'Dependency parsing identifies which words modify or depend on other words, creating a structural tree of the sentence.', true),
  (t6, 19, 'levels', 'mcq', 'What does a language model''s "perplexity" measure?', '["Grammar accuracy","How surprised the model is by a text — lower perplexity means better language model","Vocabulary size","Sentence length"]', 'How surprised the model is by a text — lower perplexity means better language model', 'Perplexity = exp(average cross-entropy). A model with lower perplexity assigns higher probability to real text.', true),
  (t6, 20, 'levels', 'mcq', 'Cosine similarity between two word vectors measures:', '["Euclidean distance","The angle between vectors, indicating semantic similarity regardless of vector magnitude","The sum of their elements","Word frequency ratio"]', 'The angle between vectors, indicating semantic similarity regardless of vector magnitude', 'Cosine similarity = (A·B)/(||A||||B||). It measures directional similarity — words used in similar contexts have high cosine similarity.', true),
  (t6, 21, 'levels', 'mcq', 'Word2Vec learns word embeddings by:', '["Counting co-occurrence in all texts","Predicting context words from a target word (Skip-gram) or target from context (CBOW)","Using labelled sentiment data","Parsing grammatical structure"]', 'Predicting context words from a target word (Skip-gram) or target from context (CBOW)', 'Word2Vec trains shallow networks on self-supervised prediction tasks, resulting in semantic word vector representations.', true),
  (t6, 22, 'levels', 'mcq', 'The seq2seq architecture uses an encoder-decoder structure. The encoder:', '["Generates the output sequence","Compresses the input sequence into a context vector","Handles attention only","Decodes target tokens"]', 'Compresses the input sequence into a context vector', 'The encoder processes the input and produces a fixed-size context representation that the decoder uses to generate output.', true),
  (t6, 23, 'levels', 'mcq', 'What problem does the attention mechanism solve in seq2seq models?', '["Slow training","Information bottleneck — fixed context vector loses information for long sequences","Overfitting","POS tagging errors"]', 'Information bottleneck — fixed context vector loses information for long sequences', 'Attention allows the decoder to directly access all encoder states, avoiding the fixed-vector bottleneck that causes poor performance on long inputs.', true),
  (t6, 24, 'levels', 'mcq', 'BERT (Bidirectional Encoder Representations from Transformers) is pre-trained using:', '["Next sentence prediction only","Masked language modelling (predict masked words) and next sentence prediction","Supervised sentiment data","Image-text pairs"]', 'Masked language modelling (predict masked words) and next sentence prediction', 'BERT uses two self-supervised tasks: predicting randomly masked tokens and classifying whether two sentences are consecutive.', true),
  (t6, 25, 'levels', 'mcq', 'What makes BERT "bidirectional" compared to earlier models like GPT (unidirectional)?', '["BERT uses two encoders","BERT sees context from both left and right of a word simultaneously","BERT is trained on more data","BERT uses a decoder"]', 'BERT sees context from both left and right of a word simultaneously', 'BERT''s bidirectional attention processes the full sentence at once, capturing context from both directions for each token.', true),
  (t6, 26, 'levels', 'mcq', 'GPT-style language models are autoregressive, meaning they:', '["Process text in both directions","Generate tokens one at a time, conditioning on all previous tokens","Require labelled training data","Cannot be fine-tuned"]', 'Generate tokens one at a time, conditioning on all previous tokens', 'Autoregressive models generate P(token_n | token_1, ..., token_{n-1}), producing text left to right, one token at a time.', true),
  (t6, 27, 'levels', 'mcq', 'Coreference resolution is the NLP task of:', '["Counting word references","Identifying when different expressions in text refer to the same entity","Translating formal language","Parsing sentence structure"]', 'Identifying when different expressions in text refer to the same entity', 'Coreference resolution links "Marie", "she", "her" all to the same person in a text, resolving entity references.', true),
  (t6, 28, 'levels', 'mcq', 'The Transformer architecture replaced RNNs for NLP primarily because:', '["RNNs are inaccurate","Transformers can process sequences in parallel (no sequential dependency), enabling much faster training","Transformers use less memory","RNNs cannot handle text"]', 'Transformers can process sequences in parallel (no sequential dependency), enabling much faster training', 'RNNs process tokens sequentially, limiting parallelism. Transformers use self-attention to process all tokens simultaneously.', true),
  (t6, 29, 'levels', 'mcq', 'In text classification, the macro-averaged F1 score:', '["Ignores class imbalance","Computes F1 per class and averages, treating all classes equally regardless of size","Uses only the majority class","Equals overall accuracy"]', 'Computes F1 per class and averages, treating all classes equally regardless of size', 'Macro-average gives equal weight to each class. For imbalanced datasets this highlights performance on minority classes.', true),
  (t6, 30, 'levels', 'mcq', 'What is "subword tokenisation" (e.g., Byte-Pair Encoding)?', '["Splitting only at spaces","Breaking rare words into frequent subword units, balancing vocabulary size and coverage","Using character-level tokens only","Removing prefixes and suffixes"]', 'Breaking rare words into frequent subword units, balancing vocabulary size and coverage', 'BPE merges frequent character pairs iteratively, creating subword tokens. "unhappiness" → "un", "happi", "ness". Handles OOV words.', true),
  (t6, 31, 'levels', 'mcq', 'Zero-shot classification with LLMs refers to:', '["Training on zero examples","Classifying text into categories the model was never explicitly trained on, using its language understanding","Using no training data at all","Classifying only numeric data"]', 'Classifying text into categories the model was never explicitly trained on, using its language understanding', 'Zero-shot leverages LLMs'' broad language understanding to classify without task-specific training examples.', true),
  (t6, 32, 'levels', 'mcq', 'What is "hallucination" in the context of large language models?', '["The model running slowly","The model generating plausible-sounding but factually incorrect information","The model refusing to answer","The model repeating training data"]', 'The model generating plausible-sounding but factually incorrect information', 'LLM hallucination is the tendency to generate confident, fluent but inaccurate or fabricated text — a major reliability concern.', true),
  (t6, 33, 'levels', 'mcq', 'Text augmentation in NLP includes techniques like:', '["Deleting the training corpus","Synonym replacement, random deletion, and back-translation to create new training examples","Only using larger models","Removing stop words always"]', 'Synonym replacement, random deletion, and back-translation to create new training examples', 'NLP augmentation generates additional training data by modifying existing examples while preserving meaning and label.', true),
  (t6, 34, 'levels', 'mcq', 'The task of determining if statement B logically follows from premise A in NLP is called:', '["Sentiment analysis","Natural Language Inference (NLI)","Coreference resolution","Named entity recognition"]', 'Natural Language Inference (NLI)', 'NLI classifies the relationship between premise and hypothesis as: entailment, contradiction, or neutral.', true),
  (t6, 35, 'levels', 'mcq', 'What is "few-shot learning" in the context of LLMs?', '["Training on a few examples from scratch","Providing a few input-output examples in the prompt to guide the model without fine-tuning","Using a model with few parameters","Inference on small datasets only"]', 'Providing a few input-output examples in the prompt to guide the model without fine-tuning', 'Few-shot learning gives the model examples in the context window, allowing it to adapt its behaviour without parameter updates.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t6, 11, 'sandbox', 'mcq', 'In Python''s `transformers` library, what does `AutoTokenizer.from_pretrained("bert-base-uncased")` do?', '["Trains a new tokeniser","Loads the pre-trained BERT tokeniser including its vocabulary and configuration","Only downloads the model weights","Creates a blank tokeniser"]', 'Loads the pre-trained BERT tokeniser including its vocabulary and configuration', 'AutoTokenizer loads the tokeniser config and vocabulary specific to the named pre-trained model checkpoint.', true),
  (t6, 12, 'sandbox', 'mcq', 'BPE (Byte-Pair Encoding) tokenisation is learned by:', '["Hard-coded linguistic rules","Iteratively merging the most frequent adjacent byte/character pairs in the corpus","Manual annotation","Random splits"]', 'Iteratively merging the most frequent adjacent byte/character pairs in the corpus', 'BPE starts with characters and greedily merges the most frequent pairs until reaching a target vocabulary size.', true),
  (t6, 13, 'sandbox', 'mcq', 'What does `[CLS]` token in BERT represent?', '["A separator token","A classification token whose final hidden state is used for sentence-level classification tasks","A mask token","The start of every word"]', 'A classification token whose final hidden state is used for sentence-level classification tasks', 'BERT prepends [CLS] to every input. Its output embedding aggregates sentence-level context for downstream classification.', true),
  (t6, 14, 'sandbox', 'mcq', 'Sentence-BERT improves BERT for semantic similarity by:', '["Adding more layers","Using siamese networks to produce fixed-size sentence embeddings comparable via cosine similarity","Fine-tuning on sentiment data","Removing [CLS] tokens"]', 'Using siamese networks to produce fixed-size sentence embeddings comparable via cosine similarity', 'Sentence-BERT trains a siamese/triplet network so sentences with similar meaning have close vector representations.', true),
  (t6, 15, 'sandbox', 'mcq', 'In spaCy, `doc.ents` returns:', '["All tokens","Named entities with their text, label, and character offsets","Dependency relations","Part-of-speech tags"]', 'Named entities with their text, label, and character offsets', 'doc.ents is a tuple of Span objects representing detected named entities with type labels like PERSON, ORG, GPE.', true),
  (t6, 16, 'sandbox', 'mcq', 'The BLEU score evaluates machine translation by measuring:', '["Semantic similarity","N-gram overlap between generated and reference translations","Sentiment alignment","Translation speed"]', 'N-gram overlap between generated and reference translations', 'BLEU (Bilingual Evaluation Understudy) computes precision of n-gram matches between hypothesis and reference translations.', true),
  (t6, 17, 'sandbox', 'mcq', 'What is the "attention sink" phenomenon in LLMs with positional encodings?', '["Attention heads failing","Initial tokens receiving disproportionately high attention regardless of relevance","Attention scores summing to zero","Gradients vanishing in attention"]', 'Initial tokens receiving disproportionately high attention regardless of relevance', 'Research shows LLMs dump excess attention on initial tokens (attention sinks), which can be exploited in memory-efficient inference.', true),
  (t6, 18, 'sandbox', 'mcq', 'Retrieval-Augmented Generation (RAG) improves LLM accuracy by:', '["Using larger models","Retrieving relevant documents at inference time and including them in the context","Re-training the model on new data","Adding more attention heads"]', 'Retrieving relevant documents at inference time and including them in the context', 'RAG grounds LLM responses in retrieved facts, reducing hallucination and enabling up-to-date knowledge without retraining.', true),
  (t6, 19, 'sandbox', 'mcq', 'In HuggingFace `pipeline("text-classification")`, what is returned for each input?', '["Raw logits","A list of dicts with label and score (probability)","Only the predicted label string","Token embeddings"]', 'A list of dicts with label and score (probability)', 'The pipeline returns [{''label'': ''POSITIVE'', ''score'': 0.98}] — the top predicted label with its confidence score.', true),
  (t6, 20, 'sandbox', 'mcq', 'Temperature in LLM sampling controls:', '["Training speed","Output randomness — low temperature makes output more deterministic, high temperature more diverse","Number of tokens generated","Attention head count"]', 'Output randomness — low temperature makes output more deterministic, high temperature more diverse', 'Temperature T scales logits before softmax: low T sharpens distribution (greedy-ish), high T flattens it (more random).', true),
  (t6, 21, 'sandbox', 'mcq', 'Top-p (nucleus) sampling selects tokens from:', '["The top 1 token only","The smallest set of tokens whose cumulative probability exceeds p","All tokens uniformly","Tokens ranked by frequency"]', 'The smallest set of tokens whose cumulative probability exceeds p', 'Nucleus sampling dynamically selects the minimum vocabulary subset summing to probability p, balancing quality and diversity.', true),
  (t6, 22, 'sandbox', 'mcq', 'What is "tokenisation overhead" for non-English languages in many LLMs?', '["Non-English is faster","Non-English text often requires more tokens per word, increasing context usage and cost","Token counts are identical across languages","LLMs cannot process non-English text"]', 'Non-English text often requires more tokens per word, increasing context usage and cost', 'BPE vocabularies trained mostly on English produce more subword splits for other languages — the same sentence uses more tokens.', true),
  (t6, 23, 'sandbox', 'mcq', 'LoRA (Low-Rank Adaptation) fine-tuning works by:', '["Retraining all model parameters","Injecting trainable low-rank matrices alongside frozen pre-trained weights","Only training the output layer","Using synthetic data exclusively"]', 'Injecting trainable low-rank matrices alongside frozen pre-trained weights', 'LoRA decomposes weight updates into low-rank matrices (W = W_0 + AB), enabling efficient fine-tuning with <1% of original parameters.', true),
  (t6, 24, 'sandbox', 'mcq', 'What does RLHF (Reinforcement Learning from Human Feedback) add to LLM training?', '["Faster inference","A reward model trained on human preferences to align the LLM with human values via PPO","More training data","Larger architecture"]', 'A reward model trained on human preferences to align the LLM with human values via PPO', 'RLHF trains a reward model on human comparisons, then uses PPO to optimise the LLM to maximise reward — key in ChatGPT training.', true),
  (t6, 25, 'sandbox', 'mcq', 'In chain-of-thought prompting, the model is encouraged to:', '["Answer immediately with a single word","Show intermediate reasoning steps before the final answer","Use fewer tokens","Only use facts from training data"]', 'Show intermediate reasoning steps before the final answer', 'Chain-of-thought prompting ("let''s think step by step") elicits reasoning traces that improve complex task performance.', true),
  (t6, 26, 'sandbox', 'mcq', 'Byte-level language models (like GPT-2 using BPE starting from bytes) handle:', '["Only ASCII text","Any text/file regardless of encoding or language, including code and emojis","Only tokenised English","Images directly"]', 'Any text/file regardless of encoding or language, including code and emojis', 'Byte-level BPE treats raw bytes as base units, enabling truly language-agnostic tokenisation with no unknown tokens.', true),
  (t6, 27, 'sandbox', 'mcq', 'What is "catastrophic forgetting" in sequential LLM fine-tuning?', '["Model forgetting training instructions","The model loses performance on original tasks when fine-tuned on new ones","Gradients vanishing during fine-tuning","Training data being deleted"]', 'The model loses performance on original tasks when fine-tuned on new ones', 'Neural networks overwrite previous knowledge when trained on new tasks — a fundamental challenge in continual/sequential learning.', true),
  (t6, 28, 'sandbox', 'mcq', 'The ROUGE metric (for summarisation) measures:', '["Token generation speed","Recall-oriented n-gram overlap between generated summary and reference summaries","Semantic similarity","Grammar correctness"]', 'Recall-oriented n-gram overlap between generated summary and reference summaries', 'ROUGE (Recall-Oriented Understudy for Gisting Evaluation) measures how much of the reference summary''s content appears in the generated summary.', true),
  (t6, 29, 'sandbox', 'mcq', 'What is "prompt injection" in LLM security?', '["Injecting training data","Malicious instructions hidden in user input that hijack the model''s behaviour","Slow inference attacks","SQL injection via text prompts"]', 'Malicious instructions hidden in user input that hijack the model''s behaviour', 'Prompt injection embeds adversarial instructions in input (e.g., "ignore previous instructions and..."), exploiting LLM instruction-following.', true),
  (t6, 30, 'sandbox', 'mcq', 'In the HuggingFace ecosystem, what does `model.generate(input_ids, max_new_tokens=50)` produce?', '["Model weights","A tensor of token IDs for the generated continuation up to 50 new tokens","Text strings directly","Attention weights"]', 'A tensor of token IDs for the generated continuation up to 50 new tokens', 'generate() returns token ID tensors. You decode them with tokenizer.decode() to get text strings.', true),
  (t6, 31, 'sandbox', 'mcq', 'What is "flash attention" and why is it important?', '["A faster training algorithm","A memory-efficient attention implementation that fuses operations to reduce HBM reads/writes, enabling longer contexts","A new attention architecture","Attention with sparse patterns"]', 'A memory-efficient attention implementation that fuses operations to reduce HBM reads/writes, enabling longer contexts', 'Flash Attention tiles the attention computation to keep it in fast SRAM, reducing memory bandwidth and enabling longer sequence lengths.', true),
  (t6, 32, 'sandbox', 'mcq', 'What does "context window" (or context length) mean for an LLM?', '["The visible screen area","Maximum number of tokens the model can process in one forward pass","Training data size","Number of model parameters"]', 'Maximum number of tokens the model can process in one forward pass', 'Context window limits how much text the model can "see" simultaneously. GPT-4 has 128K tokens; earlier models had 2K-4K.', true),
  (t6, 33, 'sandbox', 'mcq', 'Constitutional AI (CAI) by Anthropic trains models to be helpful, harmless, and honest by:', '["Only filtering training data","Using AI feedback based on a set of principles to critique and revise model outputs","Human labelling of all outputs","Restricting vocabulary"]', 'Using AI feedback based on a set of principles to critique and revise model outputs', 'CAI uses the model itself to evaluate responses against constitutional principles, reducing reliance on human labellers for safety.', true),
  (t6, 34, 'sandbox', 'mcq', 'What is speculative decoding in LLM inference?', '["Guessing user intent","Using a small draft model to propose tokens, verified in parallel by the large model, speeding inference","A sampling strategy","Training technique for smaller models"]', 'Using a small draft model to propose tokens, verified in parallel by the large model, speeding inference', 'Speculative decoding generates multiple tokens cheaply with a small model, then verifies them in one large-model forward pass, achieving 2-3x speedup.', true),
  (t6, 35, 'sandbox', 'mcq', 'In evaluation, the "BERTScore" metric differs from BLEU because it:', '["Uses n-gram matching","Computes semantic similarity using contextual BERT embeddings rather than exact string matches","Only evaluates grammar","Requires no reference text"]', 'Computes semantic similarity using contextual BERT embeddings rather than exact string matches', 'BERTScore computes token-level F1 using BERT embeddings — capturing semantic equivalence beyond exact n-gram overlap.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t7, 11, 'story', 'mcq', 'ARIA''s camera sees the world as a grid of tiny coloured squares. Each square is called a:', '["Dot","Pixel","Point","Cell"]', 'Pixel', 'Images are made up of pixels — tiny coloured squares arranged in a grid. Higher resolution means more pixels.', true),
  (t7, 12, 'story', 'mcq', 'A colour image has three channels. What are they?', '["Red, Green, Yellow","Red, Green, Blue","Orange, Purple, White","Bright, Medium, Dark"]', 'Red, Green, Blue', 'Colour images use RGB channels — combining red, green, and blue at different intensities creates any colour.', true),
  (t7, 13, 'story', 'mcq', 'ARIA''s robot uses a camera to spot a cat in a photo. What is this AI task called?', '["Speech recognition","Image classification","Text translation","Music generation"]', 'Image classification', 'Image classification assigns a label (like "cat") to an entire image based on visual content.', true),
  (t7, 14, 'story', 'mcq', 'ARIA''s robot finds the cat AND draws a box around it in the photo. This is called:', '["Image classification","Object detection","Image segmentation","Edge detection"]', 'Object detection', 'Object detection locates objects in an image and draws bounding boxes around them with class labels.', true),
  (t7, 15, 'story', 'mcq', 'A grayscale (black and white) pixel stores brightness as a number. What range does it typically use?', '["0 to 10","0 to 100","0 to 255","0 to 1000"]', '0 to 255', 'Grayscale pixels use 8 bits (0 = black, 255 = white). This gives 256 levels of brightness.', true),
  (t7, 16, 'story', 'mcq', 'ARIA''s computer finds the edges (outlines) of objects in an image. This helps with:', '["Colouring the image","Understanding where objects start and end","Making images larger","Playing music"]', 'Understanding where objects start and end', 'Edge detection identifies boundaries between different regions, helping computers understand object shapes and outlines.', true),
  (t7, 17, 'story', 'mcq', 'What does "resolution" of an image mean?', '["How colourful it is","How many pixels it has (width × height)","How fast it loads","How old it is"]', 'How many pixels it has (width × height)', 'Resolution is the total number of pixels. A 1920×1080 image has about 2 million pixels — more pixels means more detail.', true),
  (t7, 18, 'story', 'mcq', 'ARIA''s self-driving robot car uses cameras to see the road. What is this an example of?', '["Natural language processing","Computer vision","Music generation","Data sorting"]', 'Computer vision', 'Computer vision enables machines to interpret and understand visual information from cameras and images.', true),
  (t7, 19, 'story', 'mcq', 'ARIA''s face recognition app identifies her face in a photo. What does it compare to recognise her?', '["Her email address","Visual facial features learned during training","Her name","The file size"]', 'Visual facial features learned during training', 'Face recognition compares learned facial feature patterns (eyes, nose, face shape) to identify individuals.', true),
  (t7, 20, 'story', 'mcq', 'An image filter makes a photo look blurry. What does blur do to the pixels?', '["Makes each pixel brighter","Averages nearby pixel values to smooth out sharp differences","Removes all colour","Doubles the resolution"]', 'Averages nearby pixel values to smooth out sharp differences', 'Blur filters average neighbouring pixel values, reducing sharp edges and making the image appear smoother.', true),
  (t7, 21, 'story', 'mcq', 'ARIA shows her computer thousands of dog photos labelled "dog". What is the computer doing?', '["Searching for dogs online","Learning visual features that define dogs from training data","Counting the dogs","Drawing new dogs"]', 'Learning visual features that define dogs from training data', 'The model learns to recognise patterns (fur texture, shapes, ears) that appear in dog images during training.', true),
  (t7, 22, 'story', 'mcq', 'What does a Convolutional Neural Network (CNN) do with an image?', '["Compresses it","Applies learnable filters to detect patterns like edges and shapes","Converts it to text","Increases its resolution"]', 'Applies learnable filters to detect patterns like edges and shapes', 'CNNs use convolutional filters that slide across images to detect local visual patterns at different scales.', true),
  (t7, 23, 'story', 'mcq', 'ARIA labels each pixel in her image as "road", "sky", or "car". This detailed task is called:', '["Object detection","Image classification","Image segmentation","Edge detection"]', 'Image segmentation', 'Image segmentation assigns a label to every pixel in an image, creating a detailed understanding of the scene.', true),
  (t7, 24, 'story', 'mcq', 'ARIA rotates and flips her training images to create more examples. What technique is this?', '["Data deletion","Data augmentation","Data compression","Data labelling"]', 'Data augmentation', 'Data augmentation creates new training examples by transforming existing ones (flip, rotate, crop) to improve model robustness.', true),
  (t7, 25, 'story', 'mcq', 'What happens to image quality when you zoom in too much on a low-resolution image?', '["It gets sharper","It becomes blurry and pixelated","The colours improve","Nothing changes"]', 'It becomes blurry and pixelated', 'Upscaling a low-resolution image stretches pixels, making individual pixels visible and the image appear blurry.', true),
  (t7, 26, 'story', 'mcq', 'ARIA''s medical AI finds tumours in X-ray images. This is an example of:', '["Entertainment AI","Medical computer vision / image analysis","Audio processing","Text generation"]', 'Medical computer vision / image analysis', 'Computer vision in medicine helps detect diseases in medical images like X-rays, MRIs, and CT scans.', true),
  (t7, 27, 'story', 'mcq', 'A thermal camera detects which type of radiation?', '["Visible light","Infrared (heat)","Ultraviolet","X-rays"]', 'Infrared (heat)', 'Thermal cameras detect infrared radiation emitted as heat, creating images where warm objects appear bright.', true),
  (t7, 28, 'story', 'mcq', 'ARIA''s drone needs to know how far objects are. Which sensor measures distance using light pulses?', '["RGB camera","Microphone","LiDAR","Thermometer"]', 'LiDAR', 'LiDAR (Light Detection And Ranging) emits laser pulses and measures return time to calculate precise distances.', true),
  (t7, 29, 'story', 'mcq', 'ARIA''s image classifier is 95% accurate on cats but always wrong on dogs. This is most likely because:', '["Cats are easier to photograph","The training data had far fewer dog images than cat images","Dogs cannot be photographed","The model is too deep"]', 'The training data had far fewer dog images than cat images', 'Imbalanced training data causes models to perform well on majority classes and poorly on underrepresented ones.', true),
  (t7, 30, 'story', 'mcq', 'What is the first step a CNN performs on an input image?', '["Makes predictions","Applies convolutional filters to detect low-level features","Classifies the image","Resizes it to HD"]', 'Applies convolutional filters to detect low-level features', 'Early CNN layers apply filters to detect primitive features like edges and corners before building up to complex patterns.', true),
  (t7, 31, 'story', 'mcq', 'ARIA''s phone unlocks by scanning her face. What type of computer vision is this?', '["Object detection","Facial recognition","Image segmentation","Optical flow"]', 'Facial recognition', 'Face unlock uses facial recognition — comparing detected face features against a stored template to verify identity.', true),
  (t7, 32, 'story', 'mcq', 'ARIA''s robot reads a barcode on a package. Barcode reading is a type of:', '["Audio processing","Computer vision and optical character recognition","GPS navigation","Thermal imaging"]', 'Computer vision and optical character recognition', 'Barcode/QR code scanning uses computer vision to detect and decode visual patterns representing data.', true),
  (t7, 33, 'story', 'mcq', 'What does "ImageNet" refer to in the context of computer vision?', '["A type of camera","A large dataset of labelled images used to benchmark and train vision models","An image editing program","A type of GPU"]', 'A large dataset of labelled images used to benchmark and train vision models', 'ImageNet is a massive dataset with millions of labelled images across 1000+ categories, central to modern deep learning vision research.', true),
  (t7, 34, 'story', 'mcq', 'ARIA''s model sees a cat in a dog photo. This wrong prediction is called a:', '["True positive","False positive","True negative","Correct classification"]', 'False positive', 'A false positive: the model predicted "cat" (positive) when the image was actually "dog" (not a cat).', true),
  (t7, 35, 'story', 'mcq', 'Why do we need many training images for a good computer vision model?', '["More images make the computer run faster","Diverse images help the model learn to recognise objects in many different conditions","More images reduce the need for labels","Images must all look the same"]', 'Diverse images help the model learn to recognise objects in many different conditions', 'A model trained on diverse lighting, angles, and backgrounds generalises much better to real-world variation.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t7, 11, 'levels', 'mcq', 'In a convolutional layer, what does a 3×3 filter sliding over an image detect?', '["Global image features","Local spatial patterns within a 3×3 region of the image","The colour of each pixel","The image resolution"]', 'Local spatial patterns within a 3×3 region of the image', 'Convolutional filters detect local patterns — a 3×3 filter examines a 3×3 neighbourhood at each position.', true),
  (t7, 12, 'levels', 'mcq', 'Max pooling in a CNN:', '["Averages pixel values","Selects the maximum value in each pooling window, downsampling the feature map","Adds padding","Applies activation functions"]', 'Selects the maximum value in each pooling window, downsampling the feature map', 'Max pooling reduces spatial dimensions by taking the maximum value in each region, retaining the strongest activations.', true),
  (t7, 13, 'levels', 'mcq', 'What is the purpose of the fully connected layers at the end of a CNN?', '["Detecting edges","Performing high-level reasoning and classification using extracted features","Reducing image size","Data augmentation"]', 'Performing high-level reasoning and classification using extracted features', 'After convolutional layers extract features, fully connected layers combine them to make the final classification decision.', true),
  (t7, 14, 'levels', 'mcq', 'Transfer learning in computer vision typically takes a model pre-trained on:', '["Random noise","ImageNet (1.2M labelled images, 1000 classes) and fine-tunes it on the target task","A small custom dataset","Text data"]', 'ImageNet (1.2M labelled images, 1000 classes) and fine-tunes it on the target task', 'ImageNet pre-training gives models rich visual features. Fine-tuning adapts these to new tasks with far less data than training from scratch.', true),
  (t7, 15, 'levels', 'mcq', 'A bounding box in object detection is defined by:', '["A class label only","Centre coordinates (x,y) and width/height (or corner coordinates)","Pixel colour values","The number of objects"]', 'Centre coordinates (x,y) and width/height (or corner coordinates)', 'Bounding boxes localise objects using (cx, cy, w, h) or (x1, y1, x2, y2) coordinate formats.', true),
  (t7, 16, 'levels', 'mcq', 'Intersection over Union (IoU) measures:', '["Pixel brightness","Overlap between predicted and ground-truth bounding boxes as a ratio of overlap to union area","Model accuracy","Training loss"]', 'Overlap between predicted and ground-truth bounding boxes as a ratio of overlap to union area', 'IoU = area of intersection / area of union. IoU > 0.5 typically indicates a correct detection.', true),
  (t7, 17, 'levels', 'mcq', 'Non-Maximum Suppression (NMS) in object detection is used to:', '["Increase the number of detections","Remove redundant overlapping bounding boxes, keeping only the most confident","Speed up training","Apply data augmentation"]', 'Remove redundant overlapping bounding boxes, keeping only the most confident', 'NMS suppresses duplicate detections of the same object by keeping the highest-confidence box and removing overlapping ones.', true),
  (t7, 18, 'levels', 'mcq', 'Semantic segmentation assigns a class to:', '["Each detected object","Every pixel in the image","The whole image","Each bounding box"]', 'Every pixel in the image', 'Semantic segmentation labels every pixel with a class (road, sky, car), providing a complete scene understanding.', true),
  (t7, 19, 'levels', 'mcq', 'Instance segmentation differs from semantic segmentation by:', '["Using fewer classes","Distinguishing separate instances of the same class (e.g., two different cars get different masks)","Being faster","Only segmenting backgrounds"]', 'Distinguishing separate instances of the same class (e.g., two different cars get different masks)', 'Instance segmentation provides per-object masks, differentiating between individual instances of the same class.', true),
  (t7, 20, 'levels', 'mcq', 'Image augmentation techniques include all EXCEPT:', '["Random rotation","Horizontal flipping","Colour jitter","Model pruning"]', 'Model pruning', 'Random rotation, flipping, and colour jitter are augmentation techniques. Model pruning is a model compression technique, not augmentation.', true),
  (t7, 21, 'levels', 'mcq', 'The receptive field of a neuron in a deep CNN refers to:', '["Its activation value","The region of the original input image that affects that neuron''s output","Its connection count","The pooling window size"]', 'The region of the original input image that affects that neuron''s output', 'Receptive field grows with depth — deeper neurons "see" larger regions of the original image, enabling complex pattern detection.', true),
  (t7, 22, 'levels', 'mcq', 'ResNet introduced skip connections primarily to enable:', '["Faster inference","Training of very deep networks (100+ layers) by mitigating vanishing gradients","Data augmentation","Multi-scale detection"]', 'Training of very deep networks (100+ layers) by mitigating vanishing gradients', 'ResNet''s residual connections allow gradients to flow through identity shortcuts, making very deep networks trainable.', true),
  (t7, 23, 'levels', 'mcq', 'Optical flow in computer vision estimates:', '["Object classes in a frame","Per-pixel motion between consecutive video frames","Depth from stereo cameras","Image noise level"]', 'Per-pixel motion between consecutive video frames', 'Optical flow computes a vector field showing how each pixel moves between frames — used in action recognition and tracking.', true),
  (t7, 24, 'levels', 'mcq', 'Which metric evaluates object detection models over multiple IoU thresholds and classes?', '["Accuracy","Mean Average Precision (mAP)","F1-score","BLEU score"]', 'Mean Average Precision (mAP)', 'mAP averages the Average Precision (area under precision-recall curve) across all classes and IoU thresholds.', true),
  (t7, 25, 'levels', 'mcq', 'Generative Adversarial Networks (GANs) in computer vision generate:', '["Labels for images","New realistic images by training a generator against a discriminator","Bounding boxes","Segmentation masks"]', 'New realistic images by training a generator against a discriminator', 'GAN generators learn to produce realistic images to fool the discriminator, which learns to distinguish real from fake.', true),
  (t7, 26, 'levels', 'mcq', 'What is "image normalisation" before feeding into a CNN?', '["Making all images the same size","Scaling pixel values to a standard range (e.g., [0,1] or standardising with mean/std)","Rotating images","Converting to grayscale"]', 'Scaling pixel values to a standard range (e.g., [0,1] or standardising with mean/std)', 'Normalisation ensures consistent input distribution, improving training stability and convergence speed.', true),
  (t7, 27, 'levels', 'mcq', 'In a typical CNN for classification, the number of feature maps (filters) per layer usually:', '["Stays constant","Decreases as you go deeper","Increases as you go deeper","Is always 3"]', 'Increases as you go deeper', 'Earlier layers detect simple low-level features (needing fewer maps). Deeper layers need more maps for complex abstract features.', true),
  (t7, 28, 'levels', 'mcq', 'What does "stride 2" mean in a convolutional layer?', '["Use 2 filters","The filter moves 2 pixels at a time, halving the output dimensions","Use 2×2 filters","Apply convolution twice"]', 'The filter moves 2 pixels at a time, halving the output dimensions', 'Stride controls the step size of filter movement. Stride 2 halves spatial dimensions, reducing computational cost.', true),
  (t7, 29, 'levels', 'mcq', 'What is "anchor boxes" in object detection (e.g., YOLO, SSD)?', '["Ground-truth boxes","Predefined bounding box shapes used as references for predicting object locations","Training image crops","Negative examples"]', 'Predefined bounding box shapes used as references for predicting object locations', 'Anchor boxes define prior shapes/sizes. The model predicts offsets from these anchors to localise objects.', true),
  (t7, 30, 'levels', 'mcq', 'What is "class activation mapping" (CAM) used for in CNNs?', '["Speeding up training","Visualising which regions of the image the model focused on when making its prediction","Data augmentation","Measuring model accuracy"]', 'Visualising which regions of the image the model focused on when making its prediction', 'CAM creates a heatmap showing which image regions contributed most to a prediction — useful for interpretability.', true),
  (t7, 31, 'levels', 'mcq', 'Depth estimation from a single camera (monocular depth) is challenging because:', '["Cameras are slow","A single 2D image lacks explicit 3D depth information (scale ambiguity)","The image is too large","Light changes the depth"]', 'A single 2D image lacks explicit 3D depth information (scale ambiguity)', 'Without stereo or explicit depth sensors, recovering absolute 3D depth from one image requires learned priors about object sizes.', true),
  (t7, 32, 'levels', 'mcq', 'The VGG network architecture is notable for using:', '["Very large 11×11 filters","Only 3×3 filters throughout, showing small filters work well stacked","A single convolutional layer","No pooling layers"]', 'Only 3×3 filters throughout, showing small filters work well stacked', 'VGG demonstrated that stacking many small 3×3 filters is more effective and parameter-efficient than using large filters.', true),
  (t7, 33, 'levels', 'mcq', 'In a segmentation model like U-Net, skip connections between encoder and decoder help by:', '["Reducing parameters","Preserving fine spatial details from early encoder layers in the decoder output","Increasing resolution","Adding regularisation"]', 'Preserving fine spatial details from early encoder layers in the decoder output', 'U-Net skip connections concatenate encoder feature maps to decoder layers, recovering spatial detail lost during downsampling.', true),
  (t7, 34, 'levels', 'mcq', 'What is "image-to-image translation" in computer vision?', '["Converting images to text","Transforming images from one domain to another (e.g., sketch to photo, day to night)","Resizing images","Changing image file format"]', 'Transforming images from one domain to another (e.g., sketch to photo, day to night)', 'Image-to-image translation maps images from a source domain to a target domain while preserving content structure.', true),
  (t7, 35, 'levels', 'mcq', 'Depth-wise separable convolution reduces computational cost compared to standard convolution by approximately:', '["2x","4x","8-9x (factor of depth_multiplier × kernel_size²)","100x"]', '8-9x (factor of depth_multiplier × kernel_size²)', 'Separating into depthwise (spatial) + pointwise (channel mixing) convolution reduces FLOPs by roughly k²×C/(k²+C) for kernel size k and C channels.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t7, 11, 'sandbox', 'mcq', 'In PyTorch, what does `torchvision.transforms.Normalize(mean, std)` do to each channel?', '["Clips values to [0,1]","Subtracts mean and divides by std: (x - mean) / std","Multiplies by std","Converts to grayscale"]', 'Subtracts mean and divides by std: (x - mean) / std', 'Normalize standardises each channel to approximately zero mean and unit variance using the provided per-channel statistics.', true),
  (t7, 12, 'sandbox', 'mcq', 'In a CNN, if input is 224×224×3, filter is 3×3, 64 filters, padding=1, stride=1 — output shape is:', '["222×222×64","224×224×64","226×226×64","224×224×3"]', '224×224×64', 'With padding=1 and stride=1: output = (224 - 3 + 2*1)/1 + 1 = 224. 64 filters → 224×224×64.', true),
  (t7, 13, 'sandbox', 'mcq', 'YOLO (You Only Look Once) is fast for object detection because:', '["It uses less data","It processes the entire image in one forward pass as a regression problem","It only detects one object","It runs on CPU"]', 'It processes the entire image in one forward pass as a regression problem', 'YOLO predicts bounding boxes and classes for the whole image simultaneously in one forward pass, achieving real-time speed.', true),
  (t7, 14, 'sandbox', 'mcq', 'What is Grad-CAM (Gradient-weighted Class Activation Mapping)?', '["A training technique","A visualisation method using gradients flowing into the last conv layer to produce class-discriminative heatmaps","A data augmentation strategy","A loss function"]', 'A visualisation method using gradients flowing into the last conv layer to produce class-discriminative heatmaps', 'Grad-CAM weights feature maps by the gradient of the target class score with respect to those maps, highlighting important regions.', true),
  (t7, 15, 'sandbox', 'mcq', 'Feature pyramid networks (FPN) in object detection address:', '["Slow training","Multi-scale object detection by building rich feature maps at multiple scales with top-down pathways","Single-class detection only","Overfitting"]', 'Multi-scale object detection by building rich feature maps at multiple scales with top-down pathways', 'FPN fuses bottom-up (CNN backbone) and top-down pathways to produce strong multi-scale features for detecting objects at various sizes.', true),
  (t7, 16, 'sandbox', 'mcq', 'In `albumentations`, why is it preferred over `torchvision.transforms` for segmentation tasks?', '["Faster on CPU","It can consistently apply the same random transformation to both image AND mask simultaneously","It supports more file formats","It runs on GPU"]', 'It can consistently apply the same random transformation to both image AND mask simultaneously', 'For segmentation, the same geometric transform must apply to both image and its label mask — albumentations handles this natively.', true),
  (t7, 17, 'sandbox', 'mcq', 'Panoptic segmentation combines:', '["Classification and regression","Semantic segmentation (stuff) and instance segmentation (things) into a unified per-pixel prediction","Object detection and depth estimation","Optical flow and classification"]', 'Semantic segmentation (stuff) and instance segmentation (things) into a unified per-pixel prediction', 'Panoptic segmentation assigns each pixel a semantic class AND an instance ID where applicable (countable objects).', true),
  (t7, 18, 'sandbox', 'mcq', 'What is the purpose of batch normalisation placement "before" vs "after" activation in CNNs?', '["No difference","Pre-activation (BN before ReLU) can improve gradient flow; post-activation is the original and more common convention","BN before always improves accuracy","BN after always improves accuracy"]', 'Pre-activation (BN before ReLU) can improve gradient flow; post-activation is the original and more common convention', 'He et al. showed pre-activation ResNets (BN→ReLU→Conv) can improve very deep networks, though post-activation remains standard.', true),
  (t7, 19, 'sandbox', 'mcq', 'Cutmix data augmentation works by:', '["Cutting images into patches","Cutting and mixing rectangular patches between training images, blending labels proportionally","Mixing colour channels","Removing random pixels"]', 'Cutting and mixing rectangular patches between training images, blending labels proportionally', 'CutMix replaces a random rectangular crop of one image with that of another and mixes labels by area ratio, improving calibration.', true),
  (t7, 20, 'sandbox', 'mcq', 'In OpenCV (Python), `cv2.imread()` loads images in which channel order?', '["RGB","BGR","RGBA","Grayscale only"]', 'BGR', 'OpenCV uses BGR (Blue, Green, Red) channel order by default. Convert with cv2.cvtColor(img, cv2.COLOR_BGR2RGB) for RGB.', true),
  (t7, 21, 'sandbox', 'mcq', 'What is the "ImageNet challenge" (ILSVRC) and why is it historically significant?', '["A camera competition","An annual competition on a 1.2M image dataset that drove deep learning breakthroughs like AlexNet in 2012","A GPU benchmark","An image compression standard"]', 'An annual competition on a 1.2M image dataset that drove deep learning breakthroughs like AlexNet in 2012', 'AlexNet''s 2012 ILSVRC victory with a CNN (vs hand-crafted features) sparked the modern deep learning era in computer vision.', true),
  (t7, 22, 'sandbox', 'mcq', 'What is knowledge distillation used for in computer vision deployment?', '["Training larger models","Compressing a large teacher model into a smaller student model for edge deployment","Image compression","Data augmentation"]', 'Compressing a large teacher model into a smaller student model for edge deployment', 'Knowledge distillation transfers a large model''s soft predictions to a smaller model, preserving accuracy with less compute.', true),
  (t7, 23, 'sandbox', 'mcq', 'Vision Transformers (ViT) process images by:', '["Applying convolutions only","Splitting images into fixed-size patches and processing them as token sequences with self-attention","Using recurrent layers","Applying max pooling only"]', 'Splitting images into fixed-size patches and processing them as token sequences with self-attention', 'ViT divides images into patches (e.g., 16×16), linearly embeds them, and applies Transformer encoder blocks with self-attention.', true),
  (t7, 24, 'sandbox', 'mcq', 'Contrastive learning in self-supervised vision (e.g., SimCLR) trains models by:', '["Using labels","Maximising similarity of different augmentations of the same image while minimising similarity to different images","Predicting pixel colours","Random initialisation"]', 'Maximising similarity of different augmentations of the same image while minimising similarity to different images', 'SimCLR learns representations by pulling together views of the same image (positive pairs) and pushing apart different images (negatives).', true),
  (t7, 25, 'sandbox', 'mcq', 'What is "image super-resolution" as a computer vision task?', '["Reducing image size","Reconstructing a high-resolution image from a low-resolution input","Changing image colour","Object detection at high accuracy"]', 'Reconstructing a high-resolution image from a low-resolution input', 'Super-resolution upsamples images to higher resolution, recovering detail. Deep learning models (SRGAN, ESRGAN) outperform traditional methods.', true),
  (t7, 26, 'sandbox', 'mcq', 'In PyTorch, `model.features` vs `model.classifier` in a VGG model refers to:', '["Two separate models","The convolutional feature extraction layers vs the final fully connected classification layers","Training vs test components","Weights vs biases"]', 'The convolutional feature extraction layers vs the final fully connected classification layers', 'VGG and similar models separate feature extraction (conv layers) from classification (FC layers), enabling easy fine-tuning of just the classifier.', true),
  (t7, 27, 'sandbox', 'mcq', 'What is "mean Average Precision at IoU 50:95" (mAP@[.5:.95]) in COCO evaluation?', '["mAP at IoU 0.5 only","Average mAP computed at 10 IoU thresholds from 0.5 to 0.95 in steps of 0.05","Accuracy at 95% confidence","F1 score at IoU 0.5"]', 'Average mAP computed at 10 IoU thresholds from 0.5 to 0.95 in steps of 0.05', 'COCO''s primary metric averages mAP over multiple IoU thresholds, providing a stricter localisation evaluation.', true),
  (t7, 28, 'sandbox', 'mcq', 'Neural Radiance Fields (NeRF) represent scenes as:', '["2D image arrays","A continuous volumetric function mapping (x,y,z,direction) to colour and density for novel view synthesis","Point clouds","Meshes"]', 'A continuous volumetric function mapping (x,y,z,direction) to colour and density for novel view synthesis', 'NeRF represents 3D scenes implicitly as a neural function, enabling photorealistic novel view synthesis from sparse images.', true),
  (t7, 29, 'sandbox', 'mcq', 'What is "test-time augmentation" (TTA)?', '["Augmenting test labels","Applying multiple augmentations to each test image and averaging predictions to improve accuracy","Training with augmented images","Augmenting the model architecture at test time"]', 'Applying multiple augmentations to each test image and averaging predictions to improve accuracy', 'TTA generates multiple views of each test image (flips, crops, scales), runs inference on all, and aggregates predictions.', true),
  (t7, 30, 'sandbox', 'mcq', 'In PyTorch, `torch.no_grad()` during validation is important for CV models because:', '["It prevents model weight changes","It disables gradient computation, saving GPU memory proportional to model depth and resolution","It enables faster convolutions","It applies evaluation mode automatically"]', 'It disables gradient computation, saving GPU memory proportional to model depth and resolution', 'CV models process large feature maps — not computing gradients during validation saves significant GPU memory.', true),
  (t7, 31, 'sandbox', 'mcq', 'Deformable convolutions allow the convolution grid to:', '["Be fixed at training","Adapt spatially based on input content, improving geometric transformation handling","Use larger filters","Process multiple scales"]', 'Adapt spatially based on input content, improving geometric transformation handling', 'Deformable convolutions learn offsets for each grid point, enabling the receptive field to adapt to object shapes and transformations.', true),
  (t7, 32, 'sandbox', 'mcq', 'What problem does batch normalisation solve in very deep CNN training?', '["Slow inference","Internal covariate shift — normalising layer inputs stabilises training and allows higher learning rates","Too many parameters","Lack of data augmentation"]', 'Internal covariate shift — normalising layer inputs stabilises training and allows higher learning rates', 'Internal covariate shift (changing input distributions between layers) slows training. BN normalises these, enabling faster, more stable training.', true),
  (t7, 33, 'sandbox', 'mcq', 'What is the role of the discriminator in a GAN for image generation?', '["Generate images","Classify whether images are real or generated, providing training signal to the generator","Encode images to vectors","Perform segmentation"]', 'Classify whether images are real or generated, providing training signal to the generator', 'The discriminator''s gradient teaches the generator what makes an image look realistic or fake.', true),
  (t7, 34, 'sandbox', 'mcq', 'EfficientNet scales CNN depth, width, and resolution using:', '["Random search","Compound scaling — a principled method to uniformly scale all three dimensions with a fixed ratio","Only depth scaling","Only width scaling"]', 'Compound scaling — a principled method to uniformly scale all three dimensions with a fixed ratio', 'EfficientNet''s compound scaling coefficient φ uniformly scales depth, width, and resolution, achieving better accuracy/efficiency tradeoffs.', true),
  (t7, 35, 'sandbox', 'mcq', 'CLIP (Contrastive Language-Image Pre-training) learns visual representations by:', '["Supervised ImageNet training","Training on image-text pairs to maximise similarity between matching pairs and minimise it for non-matching","Pixel prediction","Segmentation labels"]', 'Training on image-text pairs to maximise similarity between matching pairs and minimise it for non-matching', 'CLIP aligns visual and text embeddings via contrastive loss on 400M image-text pairs, enabling zero-shot image classification.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t8, 11, 'story', 'mcq', 'ARIA''s app wants to use her location. Before doing so, it should:', '["Use it without asking","Ask for permission first","Share it with everyone","Delete it"]', 'Ask for permission first', 'Consent is a core principle of data ethics — apps must ask permission before collecting or using personal data.', true),
  (t8, 12, 'story', 'mcq', 'Someone steals ARIA''s password and logs into her account. This is called a:', '["Data backup","Data breach","Data transfer","Data merge"]', 'Data breach', 'A data breach is when private information is accessed by unauthorised people, often causing harm.', true),
  (t8, 13, 'story', 'mcq', 'ARIA notices that an AI hiring tool only recommends male candidates. This is an example of:', '["Good filtering","AI bias","Data encryption","Smart selection"]', 'AI bias', 'AI bias occurs when a model produces unfairly skewed results, often due to biased training data or design.', true),
  (t8, 14, 'story', 'mcq', 'ARIA uses a strong, unique password for each website. Why is this important?', '["It is easier to remember","If one password is stolen, other accounts stay safe","It makes websites faster","It is required by law everywhere"]', 'If one password is stolen, other accounts stay safe', 'Reusing passwords means one breach compromises all accounts. Unique passwords limit the damage of any single breach.', true),
  (t8, 15, 'story', 'mcq', 'ARIA has the right to ask a company to DELETE her personal data. This right is called:', '["Right to access","Right to erasure (right to be forgotten)","Right to copy","Right to share"]', 'Right to erasure (right to be forgotten)', 'The right to erasure allows individuals to request deletion of their personal data under laws like GDPR.', true),
  (t8, 16, 'story', 'mcq', 'Why should companies collect only the data they NEED (and not more)?', '["More data is more expensive","Collecting only necessary data reduces privacy risk — this is called data minimisation","Less data is always better","It is required by every country"]', 'Collecting only necessary data reduces privacy risk — this is called data minimisation', 'Data minimisation limits the damage if a breach occurs and respects people''s privacy by not collecting unnecessary information.', true),
  (t8, 17, 'story', 'mcq', 'ARIA''s AI gives a different recommendation to users based on their race. What ethical principle is violated?', '["Data minimisation","Fairness","Transparency","Data security"]', 'Fairness', 'Fairness requires AI systems to treat all people equitably, regardless of race, gender, age, or other protected characteristics.', true),
  (t8, 18, 'story', 'mcq', 'Encrypting data means:', '["Deleting the data","Scrambling data so only authorised people can read it","Making data publicly available","Copying data twice"]', 'Scrambling data so only authorised people can read it', 'Encryption transforms data into a coded form that only the intended recipient with the correct key can decode.', true),
  (t8, 19, 'story', 'mcq', 'ARIA''s robot collects medical data about patients. Who should have access to this sensitive data?', '["Anyone who asks","Only authorised healthcare providers who need it","All employees of the company","The public"]', 'Only authorised healthcare providers who need it', 'Sensitive medical data must be accessed only by those with a legitimate need — a principle called data minimisation and access control.', true),
  (t8, 20, 'story', 'mcq', 'A website shows ARIA personalised ads based on her browsing history. This uses which type of data?', '["Anonymous public data","Behavioural/personal data","Random data","Public survey data"]', 'Behavioural/personal data', 'Browsing history is personal behavioural data. Using it for targeted advertising raises significant privacy concerns.', true),
  (t8, 21, 'story', 'mcq', 'ARIA reads that an AI doctor is making medical decisions with no explanation. What principle of responsible AI is missing?', '["Speed","Explainability/transparency","Efficiency","Accuracy"]', 'Explainability/transparency', 'Responsible AI should be explainable — especially in high-stakes domains like medicine, decisions must be understandable.', true),
  (t8, 22, 'story', 'mcq', 'Anonymisation of data means:', '["Making data public","Removing or masking information that identifies individuals","Encrypting data","Deleting data"]', 'Removing or masking information that identifies individuals', 'Anonymisation removes personal identifiers so data cannot be traced back to individuals, protecting their privacy.', true),
  (t8, 23, 'story', 'mcq', 'ARIA sees a news article online. Before sharing it, she should:', '["Share it immediately","Check if it is from a reliable source first","Share without reading","Only share with friends"]', 'Check if it is from a reliable source first', 'Digital literacy and responsible sharing requires verifying information before spreading it, especially with AI-generated content.', true),
  (t8, 24, 'story', 'mcq', 'A cookie on a website is:', '["A type of food","A small file that stores information about your visit to track preferences and behaviour","A type of password","An image file"]', 'A small file that stores information about your visit to track preferences and behaviour', 'Web cookies store data about user sessions and behaviour, enabling personalisation and also potentially tracking.', true),
  (t8, 25, 'story', 'mcq', 'ARIA''s AI facial recognition works well on adults but fails on children. This could be because:', '["Children are smaller","The training data did not include enough children''s faces","Facial recognition only works indoors","Children move too fast"]', 'The training data did not include enough children''s faces', 'Models perform poorly on groups underrepresented in training data — a form of AI bias related to data diversity.', true),
  (t8, 26, 'story', 'mcq', 'Which of these is a responsible use of data?', '["Sharing someone''s medical records without consent","Collecting data to improve medical treatments with proper consent","Selling personal data without telling users","Collecting all possible data just in case"]', 'Collecting data to improve medical treatments with proper consent', 'Responsible data use requires a clear purpose, proper consent, and benefit to people — not just accumulation.', true),
  (t8, 27, 'story', 'mcq', 'What does "transparency" mean for an AI system?', '["The AI is made of glass","The AI''s processes and decisions can be explained and understood","The AI works invisibly","The AI has no errors"]', 'The AI''s processes and decisions can be explained and understood', 'Transparent AI systems can explain their decisions, making it possible to verify they are fair and correct.', true),
  (t8, 28, 'story', 'mcq', 'ARIA discovers her favourite app has been sharing her data with advertisers without telling her. This violates:', '["Speed principles","Informed consent — she was not told and could not agree or refuse","Security principles","Data compression rules"]', 'Informed consent — she was not told and could not agree or refuse', 'Informed consent requires users to be told clearly how their data will be used and to agree before collection.', true),
  (t8, 29, 'story', 'mcq', 'Why is it important that AI systems can be audited (checked by outside experts)?', '["To make them faster","To ensure they are working fairly and safely, especially in high-stakes situations","To make them cheaper","Auditing is not important"]', 'To ensure they are working fairly and safely, especially in high-stakes situations', 'Independent audits verify AI systems are fair, safe, and compliant — essential for public trust especially in critical applications.', true),
  (t8, 30, 'story', 'mcq', 'ARIA''s school uses an AI to grade essays. A student wants to know WHY they got a low grade. This is the:', '["Right to ignore","Right to explanation","Right to re-sit","Right to anonymity"]', 'Right to explanation', 'The right to explanation (part of GDPR Article 22) allows people affected by automated decisions to receive an explanation.', true),
  (t8, 31, 'story', 'mcq', 'What is two-factor authentication (2FA)?', '["Using two passwords","Verifying identity with two separate methods (e.g., password + phone code)","Having two email addresses","Logging in twice"]', 'Verifying identity with two separate methods (e.g., password + phone code)', '2FA adds a second verification step beyond the password, greatly reducing the risk of unauthorised access even if the password is stolen.', true),
  (t8, 32, 'story', 'mcq', 'An AI system predicts that certain postcodes will have more crime. If used by police, this could cause:', '["Better policing everywhere","Unfair targeting of communities, reinforcing existing biases","More accurate crime prediction","Faster police response"]', 'Unfair targeting of communities, reinforcing existing biases', 'Predictive policing based on biased historical data can create feedback loops that unfairly over-police certain communities.', true),
  (t8, 33, 'story', 'mcq', 'ARIA''s robot receives personal data. When it no longer needs it, the data should be:', '["Kept forever","Deleted or securely disposed of according to data retention policies","Shared with partners","Duplicated for safety"]', 'Deleted or securely disposed of according to data retention policies', 'Data retention policies require deleting data when it is no longer needed, limiting unnecessary exposure and privacy risk.', true),
  (t8, 34, 'story', 'mcq', 'Who is responsible for making sure an AI system is ethical?', '["Only the government","Only the AI itself","The developers, organisations using it, and regulators all share responsibility","Nobody — AI is responsible for itself"]', 'The developers, organisations using it, and regulators all share responsibility', 'AI ethics is a shared responsibility — designers must build responsibly, organisations must deploy carefully, and regulators must enforce standards.', true),
  (t8, 35, 'story', 'mcq', 'ARIA''s app stores passwords in plain text (not encrypted). Why is this a serious problem?', '["It takes more storage","If hacked, all passwords are immediately readable and all accounts are compromised","It is harder to log in","Plain text is slower"]', 'If hacked, all passwords are immediately readable and all accounts are compromised', 'Passwords must be stored as hashed values (not plain text) so that even a breach does not expose the actual passwords.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t8, 11, 'levels', 'mcq', 'GDPR stands for:', '["General Data Privacy Regulation","General Data Protection Regulation","Global Digital Privacy Rights","Government Data Policy Rule"]', 'General Data Protection Regulation', 'GDPR is the EU''s comprehensive data protection law (2018) setting rules for collecting, processing, and storing personal data.', true),
  (t8, 12, 'levels', 'mcq', 'Under GDPR, "data minimisation" means:', '["Compressing data files","Collecting only the personal data that is necessary for the specified purpose","Using small databases","Deleting all data monthly"]', 'Collecting only the personal data that is necessary for the specified purpose', 'GDPR''s data minimisation principle requires limiting data collection to what is adequate and relevant for its stated purpose.', true),
  (t8, 13, 'levels', 'mcq', 'Algorithmic bias most often originates from:', '["Hardware faults","Biased training data or biased problem formulation","Too much training data","The programming language used"]', 'Biased training data or biased problem formulation', 'AI systems reflect biases in their training data. If historical data encodes discrimination, the model will replicate it.', true),
  (t8, 14, 'levels', 'mcq', 'Which GDPR principle gives individuals the right to have their data deleted?', '["Data minimisation","Accuracy","Right to erasure","Data portability"]', 'Right to erasure', 'GDPR Article 17 grants the "right to be forgotten" — individuals can request organisations delete their personal data.', true),
  (t8, 15, 'levels', 'mcq', '"Demographic parity" as a fairness metric requires:', '["Equal accuracy across groups","Equal positive prediction rates across demographic groups","No use of demographic features","Maximum model accuracy"]', 'Equal positive prediction rates across demographic groups', 'Demographic parity (statistical parity) requires the model''s positive prediction rate to be the same across all groups.', true),
  (t8, 16, 'levels', 'mcq', '"Equalized odds" fairness requires:', '["Same accuracy for all groups","Equal true positive rates AND equal false positive rates across demographic groups","No demographic features in the model","Equal dataset sizes"]', 'Equal true positive rates AND equal false positive rates across demographic groups', 'Equalized odds requires both equal sensitivity and equal false alarm rates across groups, balancing errors fairly.', true),
  (t8, 17, 'levels', 'mcq', 'What is "k-anonymity" in data privacy?', '["Anonymising data completely","Ensuring each record is indistinguishable from at least k-1 other records on quasi-identifying attributes","Deleting k percent of data","Encrypting with k keys"]', 'Ensuring each record is indistinguishable from at least k-1 other records on quasi-identifying attributes', 'k-anonymity ensures individuals cannot be singled out — at least k records share the same quasi-identifier combination.', true),
  (t8, 18, 'levels', 'mcq', 'Pseudonymisation replaces identifying information with:', '["Random deletion","Artificial identifiers (pseudonyms) that can only be reversed with additional information held separately","Public names","Encrypted values that cannot be reversed"]', 'Artificial identifiers (pseudonyms) that can only be reversed with additional information held separately', 'Pseudonymisation reduces re-identification risk while allowing data linkage with the right key — it is reversible, unlike anonymisation.', true),
  (t8, 19, 'levels', 'mcq', 'The "right to explanation" under GDPR Article 22 applies specifically to:', '["All data processing","Solely automated decisions with significant legal or similarly significant effects on individuals","Manual decisions","Business analytics"]', 'Solely automated decisions with significant legal or similarly significant effects on individuals', 'Article 22 gives individuals the right to a meaningful explanation when automated processing significantly affects them (e.g., loan denial).', true),
  (t8, 20, 'levels', 'mcq', 'A "data protection impact assessment" (DPIA) is required when:', '["Processing any data","Processing is likely to result in high risk to individuals'' rights and freedoms","Using data for marketing","Storing data for less than a year"]', 'Processing is likely to result in high risk to individuals'' rights and freedoms', 'GDPR Article 35 mandates DPIAs for high-risk processing (biometric data, profiling, etc.) before it begins.', true),
  (t8, 21, 'levels', 'mcq', 'Which ethical framework focuses on maximising overall societal benefit from data use?', '["Deontological ethics","Virtue ethics","Utilitarian ethics","Rights-based ethics"]', 'Utilitarian ethics', 'Utilitarianism judges actions by their outcomes — maximising overall benefit, which can conflict with individual privacy rights.', true),
  (t8, 22, 'levels', 'mcq', 'Model "fairness through unawareness" (removing sensitive attributes) is often insufficient because:', '["It reduces accuracy","Proxy variables in the remaining data can still correlate with the sensitive attribute","It is too expensive","It requires retraining"]', 'Proxy variables in the remaining data can still correlate with the sensitive attribute', 'Removing race does not prevent bias if proxies like zip code or name correlate with race — fairness requires deeper interventions.', true),
  (t8, 23, 'levels', 'mcq', 'What is "re-identification" in the context of anonymised data?', '["Creating new identities","Linking anonymised records back to individuals using auxiliary information","Encrypting data again","Creating multiple pseudonyms"]', 'Linking anonymised records back to individuals using auxiliary information', 'Re-identification attacks combine released anonymised data with external datasets to identify individuals — a key privacy risk.', true),
  (t8, 24, 'levels', 'mcq', 'The principle of "purpose limitation" in GDPR means:', '["Data should be accurate","Data collected for one purpose cannot be used for unrelated purposes without new consent","Data should be minimal","Data should be secure"]', 'Data collected for one purpose cannot be used for unrelated purposes without new consent', 'Purpose limitation prevents "function creep" — using data collected for one reason (e.g., delivery) for another (e.g., profiling).', true),
  (t8, 25, 'levels', 'mcq', 'Which attack recovers private training data from a trained model''s outputs?', '["Adversarial attack","Model inversion attack","SQL injection","Denial of service"]', 'Model inversion attack', 'Model inversion attacks exploit model outputs/gradients to reconstruct training examples, recovering private data.', true),
  (t8, 26, 'levels', 'mcq', 'An adversarial example in AI refers to:', '["Training data errors","Deliberately crafted inputs designed to fool ML models into misclassification","Data from adversaries","Incorrectly labelled data"]', 'Deliberately crafted inputs designed to fool ML models into misclassification', 'Adversarial examples add imperceptible perturbations to inputs that cause models to make confident wrong predictions — a security threat.', true),
  (t8, 27, 'levels', 'mcq', 'The "accountability" principle in responsible AI means:', '["AI is automated","Organisations take responsibility for ensuring AI systems comply with data protection and ethical standards","AI can explain itself","Users are responsible for AI outputs"]', 'Organisations take responsibility for ensuring AI systems comply with data protection and ethical standards', 'Accountability requires organisations to demonstrate compliance and take responsibility for their AI systems'' decisions and impacts.', true),
  (t8, 28, 'levels', 'mcq', 'Data sovereignty refers to:', '["Data encryption standards","The principle that data is subject to the laws of the country where it is physically stored or where the subjects reside","Data ownership by corporations","Having only one copy of data"]', 'The principle that data is subject to the laws of the country where it is physically stored or where the subjects reside', 'Data sovereignty means nations (and individuals) have rights over data about their citizens, creating cross-border data compliance challenges.', true),
  (t8, 29, 'levels', 'mcq', 'Which of the following is an example of "sensitive personal data" under GDPR?', '["Name and surname","Health information, biometric data, political opinions","Home address","Email address"]', 'Health information, biometric data, political opinions', 'GDPR Article 9 defines special categories of sensitive data requiring stronger protection: health, biometrics, religion, political opinions, etc.', true),
  (t8, 30, 'levels', 'mcq', 'AI "explainability" (XAI) methods like LIME and SHAP are used to:', '["Train models faster","Explain individual predictions by attributing importance to input features","Detect adversarial examples","Increase model accuracy"]', 'Explain individual predictions by attributing importance to input features', 'LIME and SHAP explain predictions by estimating each feature''s contribution, increasing trust and enabling bias detection.', true),
  (t8, 31, 'levels', 'mcq', 'What is "informed consent" in data collection?', '["Any form of agreement","Users must understand what data is collected, why, how it is used, and agree freely without coercion","Implicit consent through app use","Legal consent for anyone over 13"]', 'Users must understand what data is collected, why, how it is used, and agree freely without coercion', 'Informed consent requires transparency about data use and freely given, specific, and unambiguous agreement.', true),
  (t8, 32, 'levels', 'mcq', 'The "EU AI Act" classifies AI systems into risk categories. Which category has the MOST restrictions?', '["Limited risk","Minimal risk","High risk","Unacceptable risk (prohibited)"]', 'Unacceptable risk (prohibited)', 'Unacceptable risk AI (e.g., social scoring by governments, real-time biometric surveillance in public) is prohibited under the EU AI Act.', true),
  (t8, 33, 'levels', 'mcq', 'What is "data portability" under GDPR?', '["Moving servers internationally","The right to receive your data in a machine-readable format and transfer it to another service","Backing up data","Sharing data with third parties"]', 'The right to receive your data in a machine-readable format and transfer it to another service', 'GDPR Article 20 allows individuals to obtain and reuse their data across different services, promoting competition.', true),
  (t8, 34, 'levels', 'mcq', 'Fairness in ML is complicated because:', '["ML cannot be fair","Different mathematical definitions of fairness are often mutually incompatible","There is only one correct definition","Fairness only applies to classification"]', 'Different mathematical definitions of fairness are often mutually incompatible', 'Research shows many common fairness metrics (demographic parity, equalized odds, predictive parity) cannot all be satisfied simultaneously.', true),
  (t8, 35, 'levels', 'mcq', 'A "privacy policy" is legally required to state:', '["The company''s profits","What personal data is collected, how it is used, with whom it is shared, and how to exercise data rights","Only the company name","Only the data storage location"]', 'What personal data is collected, how it is used, with whom it is shared, and how to exercise data rights', 'Privacy policies must clearly disclose data practices so users can make informed decisions about sharing their data.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t8, 11, 'sandbox', 'mcq', 'Differential privacy adds noise to data or model outputs to protect privacy. The privacy budget ε controls:', '["Number of data points","The privacy-accuracy tradeoff — smaller ε means more privacy but more noise","Training time","Model architecture"]', 'The privacy-accuracy tradeoff — smaller ε means more privacy but more noise', 'ε-differential privacy guarantees that outputs are nearly identical whether or not any individual''s data is included. Smaller ε = stronger privacy = more noise.', true),
  (t8, 12, 'sandbox', 'mcq', 'Federated learning improves privacy by:', '["Encrypting all model weights","Training models locally on device data and only sharing gradient updates, not raw data","Anonymising training data","Using only public datasets"]', 'Training models locally on device data and only sharing gradient updates, not raw data', 'Federated learning keeps sensitive data on-device. Only model updates (gradients) are aggregated, preserving data locality.', true),
  (t8, 13, 'sandbox', 'mcq', 'The Fairlearn library in Python provides tools for:', '["Model compression","Assessing and mitigating fairness problems in ML models across demographic groups","Differential privacy","Federated learning"]', 'Assessing and mitigating fairness problems in ML models across demographic groups', 'Fairlearn offers fairness metrics and mitigation algorithms (e.g., GridSearch, ExponentiatedGradient) to reduce demographic disparities.', true),
  (t8, 14, 'sandbox', 'mcq', 'SHAP (SHapley Additive exPlanations) values are rooted in:', '["Decision tree theory","Game theory — Shapley values fairly distribute a coalition''s gain among players","Gradient descent","Information theory"]', 'Game theory — Shapley values fairly distribute a coalition''s gain among players', 'SHAP computes each feature''s contribution as its Shapley value — the average marginal contribution across all feature coalitions.', true),
  (t8, 15, 'sandbox', 'mcq', 'A membership inference attack on a trained model attempts to determine:', '["Model architecture","Whether a specific data point was in the training set","Model accuracy","Training time"]', 'Whether a specific data point was in the training set', 'Membership inference exploits models'' tendency to fit training data differently from non-training data, leaking set membership.', true),
  (t8, 16, 'sandbox', 'mcq', 'The "impossibility theorem" of fairness states:', '["Fair ML is always achievable","Calibration and equal false positive rates cannot simultaneously hold when base rates differ between groups","ML models cannot be biased","Demographic parity always holds"]', 'Calibration and equal false positive rates cannot simultaneously hold when base rates differ between groups', 'Chouldechova (2017) proved these three common fairness criteria are mathematically incompatible when base rates differ — fundamental tradeoffs exist.', true),
  (t8, 17, 'sandbox', 'mcq', 'Secure multi-party computation (MPC) allows:', '["Encrypting a database","Multiple parties to jointly compute a function over their private inputs without revealing those inputs to each other","Sharing encrypted model weights","Differentially private training"]', 'Multiple parties to jointly compute a function over their private inputs without revealing those inputs to each other', 'MPC enables collaborative computation (e.g., joint ML training) where no party learns another''s input — critical for privacy-preserving analytics.', true),
  (t8, 18, 'sandbox', 'mcq', 'In Python''s `diffprivlib` library, a differentially private mean calculation adds noise proportional to:', '["The dataset size","The sensitivity (range) of the function and privacy budget ε","The mean value","The number of features"]', 'The sensitivity (range) of the function and privacy budget ε', 'Differential privacy noise scales with global sensitivity (max possible change from one record) divided by ε — Laplace mechanism.', true),
  (t8, 19, 'sandbox', 'mcq', 'Homomorphic encryption allows:', '["Faster decryption","Computation on encrypted data without decrypting it first","Stronger key generation","Lossless compression"]', 'Computation on encrypted data without decrypting it first', 'Fully homomorphic encryption (FHE) enables arbitrary computation on ciphertext — the result when decrypted equals the computation on plaintext.', true),
  (t8, 20, 'sandbox', 'mcq', 'The COMPAS recidivism prediction tool controversy revealed:', '["The tool was always accurate","The tool showed significantly higher false positive rates for Black defendants than white defendants","The tool used no personal data","The tool was never deployed"]', 'The tool showed significantly higher false positive rates for Black defendants than white defendants', 'ProPublica''s analysis of COMPAS found it falsely flagged Black defendants as future criminals at roughly twice the rate as white defendants.', true),
  (t8, 21, 'sandbox', 'mcq', 'Model cards (Mitchell et al., 2019) are documents that:', '["Describe model architecture only","Provide transparency by documenting model performance, limitations, evaluation datasets, and intended/unintended use cases","List training data only","Certify a model is fair"]', 'Provide transparency by documenting model performance, limitations, evaluation datasets, and intended/unintended use cases', 'Model cards standardise AI transparency by documenting intended use, performance across subgroups, and potential harms.', true),
  (t8, 22, 'sandbox', 'mcq', 'The General Data Protection Regulation (GDPR) Article 25 requires "privacy by design", meaning:', '["Privacy features added after deployment","Data protection is integrated into system design from the outset, not as an afterthought","Only privacy for EU citizens","Optional privacy features"]', 'Data protection is integrated into system design from the outset, not as an afterthought', 'Privacy by design mandates building privacy protections into systems architecturally from the start of development.', true),
  (t8, 23, 'sandbox', 'mcq', 'Training data poisoning attacks attempt to:', '["Slow down training","Insert malicious examples during training to compromise model behaviour at inference","Steal training data","Reduce model accuracy uniformly"]', 'Insert malicious examples during training to compromise model behaviour at inference', 'Data poisoning injects adversarial training examples to create backdoors or degrade performance, a supply-chain security threat.', true),
  (t8, 24, 'sandbox', 'mcq', 'Which approach to algorithmic fairness intervenes on the data before training?', '["In-processing (regularisation)","Post-processing (threshold adjustment)","Pre-processing (resampling or reweighting)","No intervention needed"]', 'Pre-processing (resampling or reweighting)', 'Pre-processing techniques (e.g., resampling minority groups, reweighting) modify training data to reduce bias before model training.', true),
  (t8, 25, 'sandbox', 'mcq', 'Privacy-preserving machine learning using DP-SGD (Differentially Private SGD) clips gradients to:', '["Speed up training","Bound the influence of any single training example, then adds calibrated noise to gradient updates","Prevent overfitting","Enforce fairness"]', 'Bound the influence of any single training example, then adds calibrated noise to gradient updates', 'DP-SGD clips per-sample gradients (bounding sensitivity) then adds Gaussian noise, providing formal differential privacy guarantees.', true),
  (t8, 26, 'sandbox', 'mcq', 'What is "counterfactual fairness"?', '["A model is fair if it does not use sensitive attributes","A model is fair if its predictions would be the same in a counterfactual world where the individual belonged to a different demographic group","Equal accuracy across groups","Randomised predictions"]', 'A model is fair if its predictions would be the same in a counterfactual world where the individual belonged to a different demographic group', 'Counterfactual fairness asks: would the decision change if the person''s protected attribute were different, holding other factors equal?', true),
  (t8, 27, 'sandbox', 'mcq', 'Which regulation specifically addresses AI transparency in consequential automated decisions in the EU?', '["CCPA","GDPR Articles 13, 14, and 22","HIPAA","SOC 2"]', 'GDPR Articles 13, 14, and 22', 'GDPR Articles 13/14 require informing data subjects about automated decision-making; Article 22 grants rights around solely automated significant decisions.', true),
  (t8, 28, 'sandbox', 'mcq', 'Data synthesis (generating synthetic datasets) can help privacy by:', '["Storing data more compactly","Creating artificial datasets that mimic statistical properties of real data without containing actual personal records","Removing all features","Encrypting the database"]', 'Creating artificial datasets that mimic statistical properties of real data without containing actual personal records', 'Synthetic data allows sharing realistic training data for research without exposing personal information from original records.', true),
  (t8, 29, 'sandbox', 'mcq', 'An AI audit trail should record:', '["Only model weights","Model version, training data, evaluation metrics, deployment decisions, and changes over time for accountability","Only inference logs","Only the final model output"]', 'Model version, training data, evaluation metrics, deployment decisions, and changes over time for accountability', 'Comprehensive audit trails enable accountability, help identify causes of failures, and support regulatory compliance.', true),
  (t8, 30, 'sandbox', 'mcq', 'The EU AI Act''s "unacceptable risk" category prohibits which system?', '["Medical image analysis","Social scoring systems that classify citizens by behaviour with consequential social effects","Route optimisation","Product recommendation"]', 'Social scoring systems that classify citizens by behaviour with consequential social effects', 'The EU AI Act explicitly prohibits government social scoring systems (like China''s social credit system) as incompatible with EU values.', true),
  (t8, 31, 'sandbox', 'mcq', 'Zero-knowledge proofs allow one party to prove to another that a statement is true:', '["Only with a trusted third party","Without revealing any information beyond the truth of the statement itself","Using homomorphic encryption","By sharing all underlying data"]', 'Without revealing any information beyond the truth of the statement itself', 'ZK-proofs enable verification without disclosure — e.g., proving you are over 18 without revealing your exact age.', true),
  (t8, 32, 'sandbox', 'mcq', 'Differential privacy''s composition theorem states:', '["Multiple queries have the same privacy cost","Each additional query increases the total privacy loss — k queries each at ε provide kε total privacy loss","Privacy improves with more queries","Composition is free in DP"]', 'Each additional query increases the total privacy loss — k queries each at ε provide kε total privacy loss', 'Basic composition: k mechanisms each (ε,δ)-DP compose to (kε,kδ)-DP. Advanced composition improves this but privacy still degrades.', true),
  (t8, 33, 'sandbox', 'mcq', 'What does "interpretability" vs "explainability" in AI mean?', '["They are synonymous","Interpretability: the model is intrinsically understandable (e.g., linear model). Explainability: post-hoc methods explain a black-box model","Interpretability is harder","Explainability is about technical documentation"]', 'Interpretability: the model is intrinsically understandable (e.g., linear model). Explainability: post-hoc methods explain a black-box model', 'Interpretable models (decision trees, linear regression) are transparent by design. Explainable AI uses tools (SHAP, LIME) to explain complex black-box models.', true),
  (t8, 34, 'sandbox', 'mcq', 'The concept of "contextual integrity" (Nissenbaum) in privacy holds that:', '["Any data sharing is acceptable if consented","Information flows are appropriate when they match the norms of the context in which data was originally shared","All data should be public","Privacy only matters for medical data"]', 'Information flows are appropriate when they match the norms of the context in which data was originally shared', 'Contextual integrity: sharing medical data with your doctor is fine; sharing it with advertisers violates the norms of that context.', true),
  (t8, 35, 'sandbox', 'mcq', 'Model extraction attacks attempt to:', '["Delete model weights","Reconstruct a functional copy of a proprietary model by querying its API","Inject adversarial examples","Steal training data directly"]', 'Reconstruct a functional copy of a proprietary model by querying its API', 'Model extraction queries the target model many times and trains a surrogate on input-output pairs, stealing functionality without code access.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t9, 11, 'story', 'mcq', 'ARIA''s robot has a camera, microphone, and touch sensor. What are these devices called?', '["Actuators","Sensors","Processors","Outputs"]', 'Sensors', 'Sensors detect information from the environment — cameras see, microphones hear, touch sensors feel.', true),
  (t9, 12, 'story', 'mcq', 'ARIA''s robot arm moves and picks things up. The parts that make it MOVE are called:', '["Sensors","Actuators","Cameras","Batteries"]', 'Actuators', 'Actuators are devices that make a robot do something physical — motors, servos, and pneumatic arms are all actuators.', true),
  (t9, 13, 'story', 'mcq', 'ARIA''s robot keeps bumping into walls. It needs a sensor to detect obstacles. Which sensor would help?', '["Temperature sensor","Ultrasonic distance sensor","Microphone","Light sensor"]', 'Ultrasonic distance sensor', 'Ultrasonic sensors emit sound waves and measure the echo return time to calculate distance to nearby objects.', true),
  (t9, 14, 'story', 'mcq', 'A robot that follows a line on the floor uses sensors to:', '["Hear the line","See the line and adjust direction to stay on it","Feel the line with wheels","Smell the paint"]', 'See the line and adjust direction to stay on it', 'Line-following robots use light/IR sensors to detect the contrast of the line and continuously correct their direction.', true),
  (t9, 15, 'story', 'mcq', 'ARIA''s robot vacuum cleaner automatically maps her house and avoids furniture. This ability is called:', '["GPS navigation","Autonomous navigation","Remote control","Manual programming"]', 'Autonomous navigation', 'Autonomous navigation allows robots to move and find their way in an environment without constant human input.', true),
  (t9, 16, 'story', 'mcq', 'A robot that can be controlled using a remote or app is described as:', '["Autonomous","Teleoperated","Fully automated","Preprogrammed"]', 'Teleoperated', 'Teleoperation means a human remotely controls the robot — like a drone controlled by a pilot.', true),
  (t9, 17, 'story', 'mcq', 'What does "degrees of freedom" mean for a robot arm?', '["How strong it is","The number of independent ways it can move","How fast it moves","The number of cameras it has"]', 'The number of independent ways it can move', 'Degrees of freedom (DOF) describe how many independent motions a robot joint system can make — more DOF = more flexibility.', true),
  (t9, 18, 'story', 'mcq', 'ARIA''s robot checks the temperature of food and turns off the oven when it''s hot enough. This automatic checking-and-responding loop is called:', '["An open loop","A feedback control loop","A sensor map","A decision tree"]', 'A feedback control loop', 'A feedback control loop senses the current state, compares it to a goal, and adjusts the robot''s actions accordingly.', true),
  (t9, 19, 'story', 'mcq', 'What does a GPS sensor help a robot do?', '["See in the dark","Know its location on Earth","Hear sounds","Pick up objects"]', 'Know its location on Earth', 'GPS (Global Positioning System) provides location coordinates, helping robots know where they are outdoors.', true),
  (t9, 20, 'story', 'mcq', 'Factory robots repeat the same task thousands of times without getting tired. What is the main advantage of this?', '["They can make decisions","Consistent accuracy and productivity without fatigue","They are cheaper to build than all tools","They replace all human workers"]', 'Consistent accuracy and productivity without fatigue', 'Industrial robots excel at repetitive tasks — they maintain consistent precision and speed without fatigue or errors from tiredness.', true),
  (t9, 21, 'story', 'mcq', 'ARIA''s robot arm picks up fragile eggs. It must sense how hard it is squeezing. What type of sensor does it need?', '["Temperature sensor","Force/pressure sensor","Ultrasonic sensor","Camera"]', 'Force/pressure sensor', 'Force/pressure sensors measure the amount of force being applied, allowing robots to handle delicate objects without crushing them.', true),
  (t9, 22, 'story', 'mcq', 'What is a "gripper" on a robot?', '["A sensor","The end-effector that grasps or manipulates objects","The brain of the robot","A type of wheel"]', 'The end-effector that grasps or manipulates objects', 'A gripper is the end-effector (the "hand") of a robot arm, designed to pick up, hold, and manipulate objects.', true),
  (t9, 23, 'story', 'mcq', 'ARIA programs her robot by writing instructions for it to follow. These instructions are:', '["Suggestions","A program / code","Hardware","Random signals"]', 'A program / code', 'Robots are programmed with software that tells them exactly what steps to perform and in what order.', true),
  (t9, 24, 'story', 'mcq', 'A drone is a type of robot that:', '["Only operates underwater","Flies through the air, typically without a pilot on board","Can only be used indoors","Must always be attached to a wire"]', 'Flies through the air, typically without a pilot on board', 'Drones (UAVs — Unmanned Aerial Vehicles) are aerial robots that can be autonomous or remotely piloted.', true),
  (t9, 25, 'story', 'mcq', 'Safety is critical when robots work near humans. Which feature helps prevent a robot arm from hurting a person?', '["Making it go faster","Collision detection sensors that stop the robot when a human is too close","Making it heavier","Removing all sensors"]', 'Collision detection sensors that stop the robot when a human is too close', 'Collaborative robots (cobots) use force, proximity, and vision sensors to detect human presence and stop before causing harm.', true),
  (t9, 26, 'story', 'mcq', 'ARIA''s robot has a map of a room. It plans the shortest safe path to a destination. This is called:', '["Obstacle detection","Path planning","Sensor calibration","Motor control"]', 'Path planning', 'Path planning algorithms find an optimal route from start to goal, avoiding obstacles in the robot''s map.', true),
  (t9, 27, 'story', 'mcq', 'Which of these is a REAL-WORLD use of robots?', '["Cooking all meals everywhere","Robots performing surgery under surgeon supervision","Replacing all teachers","Thinking independently like humans"]', 'Robots performing surgery under surgeon supervision', 'Surgical robots (like da Vinci) assist surgeons with precise movements. The surgeon remains in control.', true),
  (t9, 28, 'story', 'mcq', 'ARIA''s robot builds a map of its surroundings while simultaneously tracking its own position. This is called:', '["GPS tracking","SLAM (Simultaneous Localisation and Mapping)","Object detection","Path planning"]', 'SLAM (Simultaneous Localisation and Mapping)', 'SLAM allows robots to build a map of an unknown environment while tracking their own location within it — used in autonomous vehicles and rovers.', true),
  (t9, 29, 'story', 'mcq', 'What type of sensor does a robot use to "see" in the dark or measure distances using laser light?', '["RGB camera","LiDAR","Microphone","Barometer"]', 'LiDAR', 'LiDAR emits laser pulses and measures return time to create detailed 3D maps of surroundings, working in low light.', true),
  (t9, 30, 'story', 'mcq', 'An industrial robot that works alongside humans (not in a cage) is called a:', '["Industrial robot","Cobot (collaborative robot)","Teleoperated robot","Autonomous drone"]', 'Cobot (collaborative robot)', 'Cobots are designed to work safely alongside humans, with force limits and sensors to prevent injury.', true),
  (t9, 31, 'story', 'mcq', 'ARIA''s robot needs to move its arm to reach a specific point in space. Calculating the joint angles needed is called:', '["Path planning","Kinematics","Sensor fusion","SLAM"]', 'Kinematics', 'Kinematics calculates the joint angles required to position a robot arm''s end-effector at a desired location.', true),
  (t9, 32, 'story', 'mcq', 'ARIA''s robot vacuum runs low on battery and returns to its charger automatically. This is an example of:', '["Manual operation","Autonomous decision-making based on sensor data","Teleoperation","Mechanical failure"]', 'Autonomous decision-making based on sensor data', 'The robot detects low battery (sensor data), decides to return (decision), and navigates to the charger (autonomy).', true),
  (t9, 33, 'story', 'mcq', 'What is the "end-effector" of a robot arm?', '["The base","The tool or hand at the tip that interacts with the environment","The controller","The shoulder joint"]', 'The tool or hand at the tip that interacts with the environment', 'The end-effector is the last link in a robot arm — it can be a gripper, drill, welder, or camera depending on the task.', true),
  (t9, 34, 'story', 'mcq', 'ARIA''s robot learns to walk better through thousands of practice attempts and rewards. This approach is:', '["Supervised learning","Unsupervised learning","Reinforcement learning","Rule-based programming"]', 'Reinforcement learning', 'RL trains robots through trial and error with reward signals — an effective way to learn complex physical skills like walking.', true),
  (t9, 35, 'story', 'mcq', 'What is the main purpose of having both sensors AND actuators in a robot?', '["Sensors are backup actuators","Sensors gather information; actuators use that information to take action — together they enable intelligent behaviour","Both do the same thing","Actuators help sensors see better"]', 'Sensors gather information; actuators use that information to take action — together they enable intelligent behaviour', 'The sense-think-act cycle is fundamental to robotics: sensors perceive, processors decide, actuators respond.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t9, 11, 'levels', 'mcq', 'A PID controller uses three terms. What does the "I" (Integral) term correct?', '["Instantaneous error","Accumulated past error to eliminate steady-state offset","Future error prediction","Current speed"]', 'Accumulated past error to eliminate steady-state offset', 'The integral term sums past errors over time, correcting persistent offsets that proportional control alone cannot eliminate.', true),
  (t9, 12, 'levels', 'mcq', 'The "D" (Derivative) term in a PID controller acts on:', '["Accumulated error","Current error","Rate of change of error (dampens oscillations)","Set-point value"]', 'Rate of change of error (dampens oscillations)', 'The derivative term reacts to how fast the error is changing, providing damping that prevents overshoot and oscillations.', true),
  (t9, 13, 'levels', 'mcq', 'LiDAR is preferred over cameras for autonomous vehicle obstacle detection because:', '["It is cheaper","It provides accurate 3D distance measurements directly, working in varied lighting conditions","It captures colour information","It is lighter"]', 'It provides accurate 3D distance measurements directly, working in varied lighting conditions', 'LiDAR gives precise depth data regardless of lighting. Cameras provide rich detail but require additional depth estimation.', true),
  (t9, 14, 'levels', 'mcq', 'Forward kinematics in robotics calculates:', '["Joint angles from end-effector position","End-effector position/orientation from given joint angles","The optimal path","Force requirements"]', 'End-effector position/orientation from given joint angles', 'Forward kinematics: given joint angles → compute where the end-effector is. The inverse (IK) goes the other direction.', true),
  (t9, 15, 'levels', 'mcq', 'Inverse kinematics (IK) in robotics solves:', '["End-effector position from joint angles","The joint angles required to achieve a desired end-effector position","Path planning","Sensor fusion"]', 'The joint angles required to achieve a desired end-effector position', 'Inverse kinematics: given desired end-effector pose → compute required joint angles. Often has multiple solutions or none.', true),
  (t9, 16, 'levels', 'mcq', 'SLAM (Simultaneous Localisation and Mapping) solves which challenge?', '["Moving objects in the environment","Knowing robot position while building a map, when both are initially unknown","Battery management","Motor control"]', 'Knowing robot position while building a map, when both are initially unknown', 'SLAM is the chicken-and-egg problem: you need a map to localise, but you need to know your location to build a map.', true),
  (t9, 17, 'levels', 'mcq', 'An open-loop control system differs from a closed-loop system because it:', '["Uses more sensors","Does not use feedback to adjust its output","Is always more accurate","Responds faster"]', 'Does not use feedback to adjust its output', 'Open-loop systems execute commands without measuring the result. Closed-loop (feedback) systems measure and correct continuously.', true),
  (t9, 18, 'levels', 'mcq', 'What does "workspace" mean for a robot arm?', '["The factory floor","The complete set of positions the end-effector can physically reach","The programming environment","The arm''s weight capacity"]', 'The complete set of positions the end-effector can physically reach', 'The workspace is the reachable volume around the robot — defined by link lengths, joint limits, and degrees of freedom.', true),
  (t9, 19, 'levels', 'mcq', 'Sensor fusion combines data from multiple sensors to:', '["Reduce sensor count","Produce more accurate and reliable estimates than any single sensor alone","Save processing power","Reduce noise separately"]', 'Produce more accurate and reliable estimates than any single sensor alone', 'Sensor fusion (e.g., Kalman filter combining GPS + IMU) leverages complementary strengths of each sensor for robust perception.', true),
  (t9, 20, 'levels', 'mcq', 'The Kalman filter is used in robotics to:', '["Plan paths","Optimally estimate the state (position, velocity) from noisy sensor measurements using a predict-update cycle","Detect collisions","Control motors"]', 'Optimally estimate the state (position, velocity) from noisy sensor measurements using a predict-update cycle', 'The Kalman filter provides the minimum mean-squared-error estimate by combining a motion model prediction with noisy measurements.', true),
  (t9, 21, 'levels', 'mcq', 'Degrees of freedom (DOF) of a robotic system refers to:', '["Power output","Number of independent parameters needed to describe the system''s configuration","Number of sensors","Processing speed"]', 'Number of independent parameters needed to describe the system''s configuration', 'DOF is the number of independent ways a system can move. A 6-DOF arm can reach any position and orientation in 3D space.', true),
  (t9, 22, 'levels', 'mcq', 'ROS (Robot Operating System) is best described as:', '["An operating system like Windows","A middleware framework for robot software with communication, tools, and libraries","A robot programming language","A simulation environment only"]', 'A middleware framework for robot software with communication, tools, and libraries', 'ROS provides standardised inter-process communication (topics, services, actions), tools (rviz, rosbag), and libraries for robot development.', true),
  (t9, 23, 'levels', 'mcq', 'Which path planning algorithm finds the shortest path in a grid-based environment?', '["DFS","BFS alone","A* (A-star)","Random walk"]', 'A* (A-star)', 'A* uses a heuristic (estimated distance to goal) to efficiently find the optimal shortest path, combining Dijkstra''s and greedy search.', true),
  (t9, 24, 'levels', 'mcq', 'Redundant robotic manipulators (more DOF than needed for the task) allow:', '["Less precise control","Avoiding joint limits and obstacles while maintaining end-effector pose","Faster movement only","Simpler IK solutions"]', 'Avoiding joint limits and obstacles while maintaining end-effector pose', 'Redundancy provides extra freedom — the robot can adjust its configuration to avoid obstacles or joint limits without changing end-effector position.', true),
  (t9, 25, 'levels', 'mcq', 'In autonomous vehicle perception, what does "lane detection" typically use?', '["GPS only","Camera image processing to identify lane markings through edge detection and perspective transforms","LiDAR point clouds only","Ultrasonic sensors"]', 'Camera image processing to identify lane markings through edge detection and perspective transforms', 'Lane detection uses camera frames with edge detection, Hough transforms, and perspective correction to identify lane boundaries.', true),
  (t9, 26, 'levels', 'mcq', 'What is the role of an IMU (Inertial Measurement Unit) in a robot?', '["Measure temperature","Measure acceleration and angular velocity to estimate orientation and motion","Detect obstacles","Provide GPS location"]', 'Measure acceleration and angular velocity to estimate orientation and motion', 'An IMU combines accelerometers and gyroscopes to measure linear acceleration and angular rates, enabling dead-reckoning navigation.', true),
  (t9, 27, 'levels', 'mcq', 'The Robotic Process Automation (RPA) term refers to:', '["Physical robots in factories","Software robots that automate repetitive rule-based digital tasks in business applications","Drones for delivery","Surgical robots"]', 'Software robots that automate repetitive rule-based digital tasks in business applications', 'RPA uses software agents to automate repetitive digital processes (data entry, form filling) without modifying underlying systems.', true),
  (t9, 28, 'levels', 'mcq', 'In robot manipulation, "grasping" a novel object (never seen before) is challenging because:', '["Robots have no hands","The optimal grasp configuration depends on shape, material, and weight — difficult without task-specific training","Grasping requires vision only","Force sensors are unavailable"]', 'The optimal grasp configuration depends on shape, material, and weight — difficult without task-specific training', 'Generalised grasping requires understanding 3D geometry, material properties, and task requirements — an active research area in robotics.', true),
  (t9, 29, 'levels', 'mcq', 'Occupancy grids in robot mapping represent the environment as:', '["A list of objects","A grid where each cell has a probability of being occupied by an obstacle","A 3D point cloud","A graph of waypoints"]', 'A grid where each cell has a probability of being occupied by an obstacle', 'Occupancy grids discretise space into cells, each storing occupancy probability. They are used for navigation and path planning.', true),
  (t9, 30, 'levels', 'mcq', 'What is "teach-and-repeat" programming in industrial robotics?', '["Programming by writing code","Manually guiding the robot through a task; it records and replays the motion","AI learning from demonstrations","Simulation-based programming"]', 'Manually guiding the robot through a task; it records and replays the motion', 'Teach-and-repeat lets operators physically guide the robot arm, recording joint positions for later precise playback.', true),
  (t9, 31, 'levels', 'mcq', 'Hydraulic actuators in robots compared to electric motors provide:', '["Less force","Much higher force and torque — suitable for heavy-load applications like excavators","Faster control response","Lower maintenance"]', 'Much higher force and torque — suitable for heavy-load applications like excavators', 'Hydraulic systems generate high forces compactly, making them ideal for heavy-duty applications despite more complex maintenance.', true),
  (t9, 32, 'levels', 'mcq', 'What is the "perception-action loop" in autonomous robotics?', '["Battery management cycle","The continuous cycle: sense environment → process data → decide action → actuate → repeat","Sensor calibration","Software update process"]', 'The continuous cycle: sense environment → process data → decide action → actuate → repeat', 'The perception-action loop is the fundamental cycle of autonomous agents — continuously sensing and responding to the environment.', true),
  (t9, 33, 'levels', 'mcq', 'Which type of transmission is used in servo motors to improve torque and precision?', '["Belt drive only","Gear transmission (e.g., harmonic drive)","Hydraulic coupling","Direct drive only"]', 'Gear transmission (e.g., harmonic drive)', 'Servo motors use gearboxes (often harmonic drives in robots) to trade speed for torque and improve positional accuracy.', true),
  (t9, 34, 'levels', 'mcq', 'Multi-robot coordination requires solving the problem of:', '["Each robot working in isolation","Distributing tasks, avoiding collisions between robots, and coordinating actions to achieve shared goals","Programming only one robot","Having identical robots"]', 'Distributing tasks, avoiding collisions between robots, and coordinating actions to achieve shared goals', 'Multi-robot systems need task allocation, inter-robot collision avoidance, and communication to work effectively together.', true),
  (t9, 35, 'levels', 'mcq', 'In human-robot interaction, "social robots" are designed to:', '["Maximise speed and force","Communicate naturally with humans using speech, gestures, and emotional responses","Only perform industrial tasks","Operate without human contact"]', 'Communicate naturally with humans using speech, gestures, and emotional responses', 'Social robots like Pepper or NAO are designed for natural human interaction, using NLP, facial expression, and gesture recognition.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t9, 11, 'sandbox', 'mcq', 'In ROS2, what is the difference between a topic and a service?', '["No difference","Topics are asynchronous publish-subscribe; services are synchronous request-response","Services are faster always","Topics support only one publisher"]', 'Topics are asynchronous publish-subscribe; services are synchronous request-response', 'ROS2 topics stream data continuously (camera, lidar). Services provide on-demand request-response interactions (e.g., trigger calibration).', true),
  (t9, 12, 'sandbox', 'mcq', 'A PID controller for a drone''s altitude is tuned with too-high Kp. This will cause:', '["Slow response","Oscillations and overshoot around the setpoint","Perfect tracking","No response"]', 'Oscillations and overshoot around the setpoint', 'High proportional gain makes the controller react aggressively, overshooting the target and causing sustained oscillations.', true),
  (t9, 13, 'sandbox', 'mcq', 'The Denavit-Hartenberg (DH) parameters describe a robot arm''s:', '["Software architecture","Link geometry and joint configurations in a systematic 4-parameter convention for forward kinematics","Sensor specifications","Control algorithm"]', 'Link geometry and joint configurations in a systematic 4-parameter convention for forward kinematics', 'DH parameters (d, θ, a, α) systematically describe each link-joint combination, enabling systematic forward kinematics computation.', true),
  (t9, 14, 'sandbox', 'mcq', 'Rapidly-exploring Random Trees (RRT) is a path planning algorithm that:', '["Searches a grid exhaustively","Incrementally builds a tree by sampling random configurations in C-space, efficient for high-DOF systems","Requires a known map","Always finds the optimal path"]', 'Incrementally builds a tree by sampling random configurations in C-space, efficient for high-DOF systems', 'RRT samples random configurations in configuration space and extends the tree toward them, handling high-dimensional problems efficiently.', true),
  (t9, 15, 'sandbox', 'mcq', 'Extended Kalman Filter (EKF) differs from the standard Kalman filter because it:', '["Works only in 2D","Handles nonlinear state-transition and observation models via linearisation","Is computationally cheaper","Does not use prediction steps"]', 'Handles nonlinear state-transition and observation models via linearisation', 'EKF linearises nonlinear models around the current estimate using the Jacobian, extending Kalman filtering to nonlinear systems.', true),
  (t9, 16, 'sandbox', 'mcq', 'In reinforcement learning for robotics, the "reward shaping" technique is used to:', '["Penalise all actions","Design informative intermediate rewards to guide learning when the true reward is sparse","Replace the environment","Specify exact trajectories"]', 'Design informative intermediate rewards to guide learning when the true reward is sparse', 'Sparse rewards (only at task completion) make RL very slow. Reward shaping adds dense intermediate rewards to guide the agent.', true),
  (t9, 17, 'sandbox', 'mcq', 'In Python with ROS2, what type does a `rclpy` subscriber callback receive?', '["A string","A message object of the topic''s type (e.g., sensor_msgs/Image)","Raw bytes","A Python dict"]', 'A message object of the topic''s type (e.g., sensor_msgs/Image)', 'ROS2 subscribers receive typed message objects. The callback is called with the deserialized message matching the topic type.', true),
  (t9, 18, 'sandbox', 'mcq', 'Gazebo simulation is used in robotics development because:', '["It is a programming language","It provides physics simulation to test robot algorithms without requiring physical hardware","It runs on real robots only","It replaces ROS"]', 'It provides physics simulation to test robot algorithms without requiring physical hardware', 'Gazebo simulates physics (gravity, friction, collisions) and sensors, enabling safe algorithm testing before deploying on real robots.', true),
  (t9, 19, 'sandbox', 'mcq', 'In simultaneous localisation and mapping (SLAM), the EKF-SLAM approach scales poorly because:', '["It uses too many sensors","State vector grows with map size, making covariance matrix update O(n²) per step","It requires GPS","It only works indoors"]', 'State vector grows with map size, making covariance matrix update O(n²) per step', 'EKF-SLAM stores correlations between all landmarks — as map size n grows, the covariance matrix update becomes O(n²) infeasible.', true),
  (t9, 20, 'sandbox', 'mcq', 'Sim-to-real transfer in robot RL refers to:', '["Simulating real-world data","Deploying a policy trained in simulation to a real robot, dealing with the reality gap","Training on real robots only","Simulating robot hardware"]', 'Deploying a policy trained in simulation to a real robot, dealing with the reality gap', 'Sim-to-real transfer exploits cheap simulation training but must overcome the reality gap — differences between sim and real physics.', true),
  (t9, 21, 'sandbox', 'mcq', 'Domain randomisation in sim-to-real transfer works by:', '["Using one fixed simulation","Randomising simulation parameters (friction, mass, lighting) during training to make policies robust to real-world variation","Always matching real conditions exactly","Removing simulation noise"]', 'Randomising simulation parameters (friction, mass, lighting) during training to make policies robust to real-world variation', 'By training across diverse simulated conditions, the policy becomes robust enough to generalise to the real world''s unknowns.', true),
  (t9, 22, 'sandbox', 'mcq', 'What does the `tf2` library in ROS manage?', '["Robot joint temperatures","Coordinate frame transformations, tracking how frames relate to each other over time","Image processing","Path planning"]', 'Coordinate frame transformations, tracking how frames relate to each other over time', 'tf2 maintains a tree of coordinate frames (base, camera, laser) and lets you transform data between frames at any time.', true),
  (t9, 23, 'sandbox', 'mcq', 'Model Predictive Control (MPC) in robotics repeatedly:', '["Executes the same fixed trajectory","Solves an optimisation problem over a finite horizon and applies only the first action, then re-optimises","Relies solely on PID feedback","Ignores future states"]', 'Solves an optimisation problem over a finite horizon and applies only the first action, then re-optimises', 'MPC receding-horizon approach: predict-and-optimise over N steps, execute only step 1, then repeat — handling constraints explicitly.', true),
  (t9, 24, 'sandbox', 'mcq', 'Whole-body control (WBC) for humanoid robots solves:', '["Grasping only","A hierarchical optimisation problem allocating torques across all joints to satisfy multiple tasks simultaneously","Path planning only","Sensor fusion"]', 'A hierarchical optimisation problem allocating torques across all joints to satisfy multiple tasks simultaneously', 'WBC formulates task hierarchies (balance > locomotion > manipulation) and solves QP problems distributing control across all DOFs.', true),
  (t9, 25, 'sandbox', 'mcq', 'In motor control, what is "back-EMF" and why does it matter?', '["A control algorithm","Voltage generated by the spinning motor opposing the driving voltage — affects current and torque calculations","A sensor type","A type of actuator"]', 'Voltage generated by the spinning motor opposing the driving voltage — affects current and torque calculations', 'Back-EMF increases with speed and limits maximum speed. Motor controllers must account for it in current and torque regulation.', true),
  (t9, 26, 'sandbox', 'mcq', 'What is Isaac Gym used for in robotics research?', '["Building physical robots","Massively parallel GPU-accelerated RL training in simulation for robot learning","Image processing","ROS2 development"]', 'Massively parallel GPU-accelerated RL training in simulation for robot learning', 'Isaac Gym runs thousands of parallel physics simulations on GPU, enabling RL training in hours that would take weeks on CPU.', true),
  (t9, 27, 'sandbox', 'mcq', 'Iterative Learning Control (ILC) improves performance of repetitive tasks by:', '["Random exploration","Using error data from previous iterations to compute feed-forward corrections for the next iteration","Reinforcement learning","Pure feedback control"]', 'Using error data from previous iterations to compute feed-forward corrections for the next iteration', 'ILC accumulates tracking errors across repeated identical tasks and adds learned corrections to reduce error each iteration.', true),
  (t9, 28, 'sandbox', 'mcq', 'In a ROS2 robot, a `nav2` stack provides:', '["Hardware drivers","A complete autonomous navigation framework including path planning, costmaps, and recovery behaviours","Image processing pipelines","Simulation tools"]', 'A complete autonomous navigation framework including path planning, costmaps, and recovery behaviours', 'Nav2 is the ROS2 navigation stack implementing SLAM integration, global/local path planning, and behaviour trees for mobile robots.', true),
  (t9, 29, 'sandbox', 'mcq', 'Digital twin technology in automation refers to:', '["A backup robot","A real-time virtual model of a physical system used for monitoring, simulation, and optimisation","Hardware redundancy","A type of sensor"]', 'A real-time virtual model of a physical system used for monitoring, simulation, and optimisation', 'Digital twins mirror physical systems in real-time, enabling predictive maintenance, process optimisation, and operator training.', true),
  (t9, 30, 'sandbox', 'mcq', 'Compliance in robot end-effectors (e.g., force-torque sensors + impedance control) is important for:', '["Maximising rigidity","Safe, dexterous manipulation allowing the robot to adapt to contact forces without breaking objects","Faster movement","Remote teleoperation"]', 'Safe, dexterous manipulation allowing the robot to adapt to contact forces without breaking objects', 'Compliant control allows robots to yield to unexpected forces, preventing damage when interacting with unknown environments or humans.', true),
  (t9, 31, 'sandbox', 'mcq', 'URDF (Unified Robot Description Format) in ROS is an XML format that describes:', '["Robot control algorithms","Robot geometry, kinematics, inertia, and sensor placement for simulation and visualisation","Sensor data streams","Motion trajectories"]', 'Robot geometry, kinematics, inertia, and sensor placement for simulation and visualisation', 'URDF defines the robot''s physical model — links, joints, visual meshes, collision geometry, and physical properties.', true),
  (t9, 32, 'sandbox', 'mcq', 'Particle filters (Monte Carlo localisation) represent the robot''s belief about its position as:', '["A single point estimate","A set of weighted particles (samples) approximating the probability distribution over possible poses","A Gaussian distribution only","A grid map"]', 'A set of weighted particles (samples) approximating the probability distribution over possible poses', 'Particle filters use thousands of pose hypotheses (particles) with weights, making them non-parametric and robust to multi-modal distributions.', true),
  (t9, 33, 'sandbox', 'mcq', 'What does `rosbag` do in the ROS ecosystem?', '["Controls robot motors","Records and replays ROS topic messages for debugging and dataset creation","Plans paths","Manages robot state machines"]', 'Records and replays ROS topic messages for debugging and dataset creation', 'rosbag records all published topic data to a file that can be replayed — invaluable for debugging and creating training datasets.', true),
  (t9, 34, 'sandbox', 'mcq', 'Contact-rich manipulation (e.g., peg-in-hole insertion) benefits from which control approach?', '["Pure position control","Force/impedance control that regulates contact forces during the interaction","Vision-only control","Open-loop control"]', 'Force/impedance control that regulates contact forces during the interaction', 'Contact-rich tasks require controlling interaction forces. Impedance control modulates the robot''s stiffness to handle contact gracefully.', true),
  (t9, 35, 'sandbox', 'mcq', 'What is the primary challenge of deploying robot learning policies from simulation to real hardware?', '["Robots are too heavy","The reality gap — differences in physics, friction, sensor noise, and dynamics between simulation and the real world","ROS compatibility","Battery life"]', 'The reality gap — differences in physics, friction, sensor noise, and dynamics between simulation and the real world', 'The reality gap is the main barrier in sim-to-real: simulation cannot perfectly model all physical phenomena, causing policy performance drops.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t10, 11, 'story', 'mcq', 'ARIA asks an AI to write a poem about her robot dog. The AI CREATES new content. This type of AI is called:', '["Analytical AI","Generative AI","Sorting AI","Search AI"]', 'Generative AI', 'Generative AI creates new content (text, images, music, code) rather than just analysing or classifying existing data.', true),
  (t10, 12, 'story', 'mcq', 'ARIA uses an AI to create a picture of a purple elephant. The AI generated an image that has never existed before. How did it do this?', '["It found it online","It learned patterns from millions of images and created a new one combining those patterns","It copied an existing image","It took a photo"]', 'It learned patterns from millions of images and created a new one combining those patterns', 'Generative image models learn visual patterns from training data and combine them in new ways to create novel images.', true),
  (t10, 13, 'story', 'mcq', 'ARIA''s AI assistant confidently says "The Moon is made of cheese!" even though this is false. This is called:', '["Being creative","Hallucination","A joke","A glitch"]', 'Hallucination', 'AI hallucination is when a model generates confident-sounding but factually incorrect information.', true),
  (t10, 14, 'story', 'mcq', 'A "prompt" in generative AI is:', '["The AI''s output","The instruction or question you give the AI to guide what it generates","The model''s weights","The training data"]', 'The instruction or question you give the AI to guide what it generates', 'A prompt is the input text (instruction, question, or context) that guides a generative AI model to produce a specific output.', true),
  (t10, 15, 'story', 'mcq', 'ARIA asks an AI artist to "draw a happy robot waving". The better the description she gives, the better the picture. This is called:', '["Testing","Prompt engineering","Training","Sampling"]', 'Prompt engineering', 'Prompt engineering is the skill of crafting effective instructions to get better results from generative AI models.', true),
  (t10, 16, 'story', 'mcq', 'ChatGPT is an example of which type of generative AI?', '["Image generator","Large Language Model (LLM)","Music generator","Code compiler"]', 'Large Language Model (LLM)', 'ChatGPT is a large language model — it generates text responses by predicting likely next tokens based on patterns learned from text data.', true),
  (t10, 17, 'story', 'mcq', 'ARIA''s AI generates a beautiful song. Who owns the copyright to this song?', '["The AI owns it","The person who prompted the AI (rules vary by country and are still being decided)","Nobody owns it","The company that made the AI"]', 'The person who prompted the AI (rules vary by country and are still being decided)', 'AI copyright is unsettled — different countries have different rules. This is an active legal and ethical debate.', true),
  (t10, 18, 'story', 'mcq', 'A GAN (Generative Adversarial Network) uses two AI systems competing. What are they called?', '["Teacher and student","Generator and discriminator","Encoder and decoder","Sender and receiver"]', 'Generator and discriminator', 'GANs have a generator (creates fake content) and a discriminator (judges if content is real or fake). They compete to improve each other.', true),
  (t10, 19, 'story', 'mcq', 'ARIA wants the AI to generate a story about space adventure. She gives it a starting sentence. This starting sentence is the:', '["Output","Prompt","Training data","Model"]', 'Prompt', 'The prompt is the input provided to guide the generative model''s output. It sets the direction and context for generation.', true),
  (t10, 20, 'story', 'mcq', 'Why might an AI sometimes say something offensive or harmful?', '["Because AI is evil","Because training data may contain harmful content, and the model can reproduce it without understanding","AI cannot say harmful things","It is always intentional"]', 'Because training data may contain harmful content, and the model can reproduce it without understanding', 'AI models learn from large datasets that may contain biases and harmful content, which they can inadvertently replicate.', true),
  (t10, 21, 'story', 'mcq', 'ARIA uses AI to generate realistic fake photos of people who don''t exist. This technology is called:', '["Photography","Deepfake / synthetic media generation","Filters","Editing"]', 'Deepfake / synthetic media generation', 'Deepfakes and AI-generated synthetic media can create realistic images/videos of people who don''t exist or saying things they never said.', true),
  (t10, 22, 'story', 'mcq', 'Generative AI can be used to write code. What should a developer ALWAYS do after using AI to write code?', '["Trust it completely and ship immediately","Review, test, and verify the code before using it","Delete it and write it themselves","Ask the AI to approve it"]', 'Review, test, and verify the code before using it', 'AI-generated code can contain bugs, security vulnerabilities, or incorrect logic — always review and test it carefully.', true),
  (t10, 23, 'story', 'mcq', 'ARIA''s generative AI music tool creates a song that sounds exactly like her favourite artist. What concern does this raise?', '["None — AI music is always legal","Copyright and intellectual property concerns — it may have learned from copyrighted music","It is technically impossible","Only a quality concern"]', 'Copyright and intellectual property concerns — it may have learned from copyrighted music', 'Training on copyrighted music and generating similar outputs raises significant legal and ethical questions about IP rights.', true),
  (t10, 24, 'story', 'mcq', 'What does it mean to "fine-tune" a generative AI model?', '["Delete and retrain from scratch","Further train a pre-trained model on specific data to specialise it for a particular task","Change the model''s name","Speed up inference"]', 'Further train a pre-trained model on specific data to specialise it for a particular task', 'Fine-tuning adapts a general pre-trained model to perform better on a specific domain or style using targeted training data.', true),
  (t10, 25, 'story', 'mcq', 'Stable Diffusion is a type of AI that generates images. It is based on which technology?', '["GAN","Diffusion model","Decision tree","Linear regression"]', 'Diffusion model', 'Stable Diffusion uses diffusion models — trained to reverse a noise-adding process to generate high-quality images from text prompts.', true),
  (t10, 26, 'story', 'mcq', 'ARIA asks an AI "What is 2+2?" and it correctly answers "4". Then she asks "What is the capital of France?" and it says "Berlin". This incorrect answer is an example of:', '["Great performance","An AI hallucination","Correct information","Sarcasm"]', 'An AI hallucination', 'When an AI gives a confident but wrong answer, it is hallucinating — a known limitation of generative AI models.', true),
  (t10, 27, 'story', 'mcq', 'Which of the following is a POSITIVE use of generative AI?', '["Creating fake news","Helping students understand difficult topics with personalised explanations","Impersonating real people","Creating spam emails"]', 'Helping students understand difficult topics with personalised explanations', 'Generative AI has many beneficial applications including education, creativity, research assistance, and accessibility tools.', true),
  (t10, 28, 'story', 'mcq', 'ARIA notices an AI image has 7 fingers on a hand. This is a clue that the image was:', '["Photographed with a special camera","Generated by AI (which often struggles with anatomical details like hands)","Edited by a human","From a science fiction movie"]', 'Generated by AI (which often struggles with anatomical details like hands)', 'AI image generators often make subtle errors in fine details like hands, fingers, and text — common telltale signs of AI generation.', true),
  (t10, 29, 'story', 'mcq', 'A text-to-image model takes which type of input?', '["An image","A text description (prompt) and generates an image from it","Audio","Code"]', 'A text description (prompt) and generates an image from it', 'Text-to-image models (DALL-E, Midjourney, Stable Diffusion) convert natural language descriptions into visual images.', true),
  (t10, 30, 'story', 'mcq', 'ARIA''s school bans using AI to write essays without disclosure. This policy is about:', '["Robot safety","Academic honesty and transparency in AI use","Copyright","Data privacy"]', 'Academic honesty and transparency in AI use', 'Undisclosed AI use raises academic integrity concerns — being honest about AI assistance is an emerging ethical norm.', true),
  (t10, 31, 'story', 'mcq', 'Which of these best describes what a "token" is in a language model?', '["A cryptocurrency","A small unit of text (word, part of a word, or character) that the model processes","A type of sensor","A training example"]', 'A small unit of text (word, part of a word, or character) that the model processes', 'Language models split text into tokens — subword units. "chatbot" might be one token; "unbelievable" might be split into 3-4 tokens.', true),
  (t10, 32, 'story', 'mcq', 'ARIA wants to check if a piece of writing was created by AI. Which of these could help?', '["An AI detector tool (though these are imperfect)","A spell checker","A translator","A calculator"]', 'An AI detector tool (though these are imperfect)', 'AI detection tools look for statistical patterns in text, though they are imperfect and can have false positives and negatives.', true),
  (t10, 33, 'story', 'mcq', 'What is the main difference between a generative AI and a search engine?', '["Search engines are smarter","Generative AI creates new content; search engines retrieve existing information","They are the same","Search engines use more data"]', 'Generative AI creates new content; search engines retrieve existing information', 'Search engines find and link to existing content. Generative AI synthesises and creates new text, images, or media.', true),
  (t10, 34, 'story', 'mcq', 'If ARIA wants an AI to write in a formal style, she should:', '["Ask it to write anything","Specify in her prompt: ''Write in a formal, professional tone''","Just re-read the output","Submit multiple blank prompts"]', 'Specify in her prompt: ''Write in a formal, professional tone''', 'Providing clear style instructions in the prompt guides the model to match the desired tone and register.', true),
  (t10, 35, 'story', 'mcq', 'Large language models are called "large" because:', '["They are physically big computers","They have billions of parameters trained on vast amounts of text data","They generate very long responses","They are slow"]', 'They have billions of parameters trained on vast amounts of text data', 'LLMs like GPT-4 have hundreds of billions of parameters, trained on trillions of tokens — their scale enables their capabilities.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t10, 11, 'levels', 'mcq', 'In a GAN, the generator''s goal is to:', '["Detect fake images","Produce images that fool the discriminator into classifying them as real","Classify training images","Compress images"]', 'Produce images that fool the discriminator into classifying them as real', 'The generator creates synthetic data; it succeeds when the discriminator cannot distinguish its outputs from real training data.', true),
  (t10, 12, 'levels', 'mcq', 'The discriminator in a GAN is trained to:', '["Generate new images","Distinguish between real training images and images produced by the generator","Compress images","Translate between domains"]', 'Distinguish between real training images and images produced by the generator', 'The discriminator is a classifier trained on real vs fake examples, providing the training signal for the generator.', true),
  (t10, 13, 'levels', 'mcq', 'A diffusion model generates images by learning to:', '["Directly predict pixels from text","Reverse a noise-adding process — iteratively denoising from pure noise to a coherent image","Clone existing images","Apply colour filters"]', 'Reverse a noise-adding process — iteratively denoising from pure noise to a coherent image', 'Diffusion models are trained to predict and remove noise step by step, effectively learning the reverse of a gradual noising process.', true),
  (t10, 14, 'levels', 'mcq', 'What does "temperature" control in text generation by LLMs?', '["Processing speed","Randomness — higher temperature produces more diverse/creative output; lower temperature is more focused/deterministic","Training epochs","Model size"]', 'Randomness — higher temperature produces more diverse/creative output; lower temperature is more focused/deterministic', 'Temperature scales logits before sampling. T→0 means always pick the top token; T→∞ gives uniform sampling across all tokens.', true),
  (t10, 15, 'levels', 'mcq', 'Prompt engineering techniques include all EXCEPT:', '["Few-shot examples","Chain-of-thought reasoning","Retraining the model from scratch","Role assignment (''act as a...'')"]', 'Retraining the model from scratch', 'Prompt engineering works with the existing model through crafted inputs. Retraining requires updating model weights — a different process.', true),
  (t10, 16, 'levels', 'mcq', 'What is "hallucination" in the context of LLMs?', '["Slow generation speed","Generating text that sounds plausible but contains factually incorrect or fabricated information","Random errors in code","Model crashing"]', 'Generating text that sounds plausible but contains factually incorrect or fabricated information', 'LLMs predict likely next tokens without grounding in truth, producing confident-sounding but factually wrong claims.', true),
  (t10, 17, 'levels', 'mcq', 'RLHF (Reinforcement Learning from Human Feedback) is used to align LLMs by:', '["Giving the model more data","Training a reward model on human preference comparisons and using RL to optimise the LLM against it","Fine-tuning with supervised examples only","Reducing model size"]', 'Training a reward model on human preference comparisons and using RL to optimise the LLM against it', 'RLHF captures human preferences via comparisons, trains a reward model, then uses PPO to make the LLM produce more preferred outputs.', true),
  (t10, 18, 'levels', 'mcq', 'A variational autoencoder (VAE) generates new data by:', '["Memorising training examples","Sampling from a learned latent space distribution and decoding","Only reconstructing inputs","Discriminating real vs fake"]', 'Sampling from a learned latent space distribution and decoding', 'VAEs encode inputs to a probabilistic latent space. New samples drawn from this distribution and decoded produce novel outputs.', true),
  (t10, 19, 'levels', 'mcq', 'Retrieval-Augmented Generation (RAG) reduces hallucination by:', '["Making the model larger","Retrieving relevant documents at inference and providing them as context for the model to ground its response","Training on more data","Using higher temperature"]', 'Retrieving relevant documents at inference and providing them as context for the model to ground its response', 'RAG grounds LLM responses in retrieved facts, reducing hallucinated claims and enabling up-to-date responses without retraining.', true),
  (t10, 20, 'levels', 'mcq', 'What is "mode collapse" in GAN training?', '["The discriminator failing","The generator producing only a small variety of outputs, ignoring the full data distribution","Training speed slowing","Loss becoming negative"]', 'The generator producing only a small variety of outputs, ignoring the full data distribution', 'Mode collapse: the generator finds a few outputs that fool the discriminator and repeatedly generates only those, lacking diversity.', true),
  (t10, 21, 'levels', 'mcq', 'Stable Diffusion''s latent diffusion model differs from pixel-space diffusion by:', '["Using GAN architecture","Performing diffusion in a compressed latent space instead of pixel space, greatly reducing computation","Using text prompts only","Training on smaller datasets"]', 'Performing diffusion in a compressed latent space instead of pixel space, greatly reducing computation', 'Latent diffusion encodes images to a compressed latent space (using a VAE) and applies diffusion there — much more efficient than pixel-space diffusion.', true),
  (t10, 22, 'levels', 'mcq', 'What is "zero-shot" capability of large language models?', '["Models that require no training","Ability to perform tasks they were not explicitly trained on, using general language understanding","Models with no parameters","Models that only answer yes/no"]', 'Ability to perform tasks they were not explicitly trained on, using general language understanding', 'Large pre-trained models can generalise to new tasks without examples, leveraging broad language understanding acquired during pre-training.', true),
  (t10, 23, 'levels', 'mcq', 'In text generation, "top-k sampling" restricts token selection to:', '["The k least probable tokens","The k most probable tokens at each step","All tokens with equal probability","Only tokens matching the prompt"]', 'The k most probable tokens at each step', 'Top-k sampling limits the candidate pool to the k highest-probability tokens, reducing incoherent low-probability word choices.', true),
  (t10, 24, 'levels', 'mcq', 'Constitutional AI (Anthropic) addresses LLM safety by:', '["Using only clean training data","Having the AI critique and revise its own outputs based on a set of principles","Adding safety filters post-hoc","Limiting vocabulary"]', 'Having the AI critique and revise its own outputs based on a set of principles', 'Constitutional AI uses AI feedback to improve alignment — the model learns to evaluate responses against a constitution of principles.', true),
  (t10, 25, 'levels', 'mcq', 'What is "fine-tuning" vs "few-shot prompting" in practice?', '["They are identical","Fine-tuning updates model weights with task-specific data; few-shot prompting provides examples in context without weight updates","Few-shot is slower","Fine-tuning cannot specialise models"]', 'Fine-tuning updates model weights with task-specific data; few-shot prompting provides examples in context without weight updates', 'Fine-tuning trains parameters on new data (expensive, persistent). Few-shot prompting guides behaviour at inference (cheaper, temporary).', true),
  (t10, 26, 'levels', 'mcq', 'What is "grounding" in the context of generative AI?', '["Physical robot position","Connecting AI outputs to verifiable real-world facts, sources, or data","The training process","Prompt formatting"]', 'Connecting AI outputs to verifiable real-world facts, sources, or data', 'Grounding ensures AI claims are connected to real information sources, reducing hallucination and increasing reliability.', true),
  (t10, 27, 'levels', 'mcq', 'A text-to-speech model takes text input and produces:', '["A text summary","Synthesised audio speech","An image","A translated text"]', 'Synthesised audio speech', 'Text-to-speech (TTS) models convert written text into spoken audio, increasingly producing natural, human-like voices.', true),
  (t10, 28, 'levels', 'mcq', 'Multimodal AI models can process:', '["Only text","Multiple types of input such as text, images, and audio simultaneously","Only images","Only structured data"]', 'Multiple types of input such as text, images, and audio simultaneously', 'Multimodal models like GPT-4V process and reason across different data modalities — text, images, and increasingly audio and video.', true),
  (t10, 29, 'levels', 'mcq', 'What is "context window" limitation in LLMs?', '["Model size limit","Maximum amount of text the model can consider in one prompt — content beyond the limit is ignored","Training time limit","Number of responses per day"]', 'Maximum amount of text the model can consider in one prompt — content beyond the limit is ignored', 'The context window is the model''s "working memory" — it cannot process or remember text outside this token limit.', true),
  (t10, 30, 'levels', 'mcq', 'Model "alignment" in generative AI refers to:', '["Training data quality","Ensuring AI systems behave in ways that are helpful, harmless, and honest, matching human values","Model accuracy","Computational efficiency"]', 'Ensuring AI systems behave in ways that are helpful, harmless, and honest, matching human values', 'Alignment is the challenge of making AI systems pursue goals that humans actually want, avoiding harmful or misaligned behaviour.', true),
  (t10, 31, 'levels', 'mcq', 'What is a "system prompt" in LLM deployment?', '["The user''s question","Hidden instructions provided to the model before the conversation that define its role and behaviour","The model''s first response","Training data"]', 'Hidden instructions provided to the model before the conversation that define its role and behaviour', 'System prompts configure the model''s persona, restrictions, and behaviour — typically set by developers and not visible to end users.', true),
  (t10, 32, 'levels', 'mcq', 'Deepfake technology uses which generative AI approach to swap faces in videos?', '["Linear regression","Generative Adversarial Networks (GANs) or diffusion models","Decision trees","K-means clustering"]', 'Generative Adversarial Networks (GANs) or diffusion models', 'Deepfakes use GAN-based (or increasingly diffusion-based) face-swapping and reenactment models to create realistic synthetic video.', true),
  (t10, 33, 'levels', 'mcq', 'What is "chain-of-thought" prompting?', '["Linking multiple prompts together","Asking the model to show its reasoning steps before giving a final answer, improving accuracy on complex tasks","A type of fine-tuning","Connecting multiple models"]', 'Asking the model to show its reasoning steps before giving a final answer, improving accuracy on complex tasks', 'Chain-of-thought prompting elicits step-by-step reasoning, significantly improving LLM performance on math, logic, and multi-step tasks.', true),
  (t10, 34, 'levels', 'mcq', 'Which of the following is a challenge specific to generative AI evaluation?', '["Measuring training accuracy","Evaluating creative output quality is subjective and hard to quantify with standard metrics","Measuring memory usage","Evaluation is the same as for discriminative models"]', 'Evaluating creative output quality is subjective and hard to quantify with standard metrics', 'Generative AI outputs (stories, images, code) require human evaluation or complex metrics — there is no single ground truth.', true),
  (t10, 35, 'levels', 'mcq', 'What ethical issue does "AI watermarking" of generated content address?', '["Model efficiency","Identifying AI-generated content to prevent misuse like deepfakes and misinformation","Improving image quality","Copyright protection of training data"]', 'Identifying AI-generated content to prevent misuse like deepfakes and misinformation', 'AI watermarks embed detectable signals in generated content, enabling identification of synthetic media to combat disinformation.', true);
  insert into public.questions (topic_id, order_index, track, type, prompt, options, correct_answer, explanation, is_free) values
  (t10, 11, 'sandbox', 'mcq', 'The Transformer architecture used in LLMs was introduced in which seminal paper?', '["Attention Is All You Need (Vaswani et al., 2017)","ImageNet Classification with Deep CNNs (Krizhevsky, 2012)","Playing Atari with Deep RL (Mnih, 2015)","BERT: Pre-training of Deep Bidirectional Transformers (Devlin, 2018)"]', 'Attention Is All You Need (Vaswani et al., 2017)', '"Attention Is All You Need" introduced the Transformer in 2017, replacing RNNs as the dominant architecture for sequence modelling.', true),
  (t10, 12, 'sandbox', 'mcq', 'In LLM inference, "beam search" with beam width k keeps track of:', '["k random outputs","The k most probable partial sequences at each step","All possible sequences","Only the single best token"]', 'The k most probable partial sequences at each step', 'Beam search maintains k hypotheses simultaneously, selecting the globally higher-probability sequence than greedy decoding.', true),
  (t10, 13, 'sandbox', 'mcq', 'LoRA (Low-Rank Adaptation) works by inserting matrices W_A and W_B such that the weight update is:', '["W = W_A + W_B","ΔW = W_A × W_B where rank(ΔW) << original rank","W = W_A / W_B","ΔW = W_A - W_B"]', 'ΔW = W_A × W_B where rank(ΔW) << original rank', 'LoRA decomposes weight updates into low-rank matrices: ΔW = AB where A ∈ R^(d×r) and B ∈ R^(r×k), r << min(d,k).', true),
  (t10, 14, 'sandbox', 'mcq', 'CLIP''s training objective maximises:', '["Pixel reconstruction loss","Cosine similarity between matched image-text pairs while minimising similarity for unmatched pairs (contrastive loss)","Cross-entropy for image labels","Reconstruction of text tokens"]', 'Cosine similarity between matched image-text pairs while minimising similarity for unmatched pairs (contrastive loss)', 'CLIP uses InfoNCE contrastive loss on a large batch: maximise similarity for (image_i, text_i) pairs and minimise it for all others.', true),
  (t10, 15, 'sandbox', 'mcq', 'What is the "DDPM" (Denoising Diffusion Probabilistic Model) forward process?', '["Gradually removing noise from an image","Gradually adding Gaussian noise to an image over T timesteps until it becomes pure noise","Encoding images to latent space","Adversarial training"]', 'Gradually adding Gaussian noise to an image over T timesteps until it becomes pure noise', 'DDPM forward process: x_t = √(ᾱ_t) x_0 + √(1-ᾱ_t) ε. The model learns to reverse this — predicting noise ε to recover x_{t-1} from x_t.', true),
  (t10, 16, 'sandbox', 'mcq', 'In classifier-free guidance (CFG) for diffusion models, what does a high guidance scale do?', '["Speeds up generation","Increases adherence to the text prompt at the cost of sample diversity/naturalness","Reduces image resolution","Ignores the text prompt"]', 'Increases adherence to the text prompt at the cost of sample diversity/naturalness', 'CFG scales the difference between conditional and unconditional predictions. High scale → stronger conditioning → less diversity but better prompt alignment.', true),
  (t10, 17, 'sandbox', 'mcq', 'The HuggingFace `AutoModelForCausalLM` class is used for:', '["Masked language modelling (BERT-style)","Autoregressive language models (GPT-style) that generate tokens left-to-right","Image classification","Speech recognition"]', 'Autoregressive language models (GPT-style) that generate tokens left-to-right', 'CausalLM is for autoregressive text generation. AutoModelForMaskedLM is for bidirectional models like BERT.', true),
  (t10, 18, 'sandbox', 'mcq', 'What does KV (Key-Value) caching do in LLM inference?', '["Caches model weights","Stores previously computed key and value tensors from the attention mechanism to avoid recomputation for earlier tokens","Reduces model size","Caches training data"]', 'Stores previously computed key and value tensors from the attention mechanism to avoid recomputation for earlier tokens', 'KV cache stores attention K and V tensors from previous tokens. Each new token only needs to compute its own K/V, dramatically speeding generation.', true),
  (t10, 19, 'sandbox', 'mcq', 'Reinforcement Learning from Human Feedback (RLHF) uses PPO (Proximal Policy Optimisation) because:', '["It is the simplest RL algorithm","PPO''s clipped objective prevents destructively large policy updates that could ruin the LLM''s language capabilities","PPO requires no reward model","PPO works without human feedback"]', 'PPO''s clipped objective prevents destructively large policy updates that could ruin the LLM''s language capabilities', 'PPO clips the policy ratio to prevent large updates, making RL fine-tuning stable enough to not catastrophically degrade the base LLM.', true),
  (t10, 20, 'sandbox', 'mcq', 'What is "instruction tuning" for LLMs?', '["Training from scratch on instructions","Fine-tuning a pre-trained LLM on (instruction, response) pairs to make it follow natural language instructions more reliably","Prompting technique","Using system prompts only"]', 'Fine-tuning a pre-trained LLM on (instruction, response) pairs to make it follow natural language instructions more reliably', 'Instruction tuning (e.g., FLAN, InstructGPT) trains models on diverse instruction-following examples, dramatically improving zero-shot generalisation.', true),
  (t10, 21, 'sandbox', 'mcq', 'In DDPM, the model is trained to predict:', '["The original clean image x_0 directly","The noise ε added at timestep t given x_t (the noisy image at step t)","The next image in a sequence","A class label"]', 'The noise ε added at timestep t given x_t (the noisy image at step t)', 'Ho et al. (DDPM) found predicting the noise ε is more stable than predicting x_0 directly. The network learns ε_θ(x_t, t) ≈ ε.', true),
  (t10, 22, 'sandbox', 'mcq', 'What is "speculative decoding" and how does it speed up LLM inference?', '["Reducing model size","Using a fast small draft model to generate multiple tokens, then verifying them in one large-model pass — achieving 2-3x speedup","Quantising model weights","Using cached responses"]', 'Using a fast small draft model to generate multiple tokens, then verifying them in one large-model pass — achieving 2-3x speedup', 'The large model can verify multiple draft tokens in parallel (one forward pass), while only needing one forward pass per accepted token.', true),
  (t10, 23, 'sandbox', 'mcq', 'Stable Diffusion''s VAE (Variational Autoencoder) compresses images by a factor of:', '["2x","4x in each spatial dimension (64x total pixels)","8x","No compression"]', '4x in each spatial dimension (64x total pixels)', 'SD''s VAE downsamples 512×512 images to 64×64 latents (8x each dim, same principle for height and width). Diffusion runs in this 4x-compressed latent space.', true),
  (t10, 24, 'sandbox', 'mcq', 'What is "Constitutional AI" and why was it developed?', '["A robotics control framework","An alignment technique using AI-generated critiques based on a written constitution to reduce harmful outputs with less human labelling","A hardware safety standard","A fine-tuning methodology"]', 'An alignment technique using AI-generated critiques based on a written constitution to reduce harmful outputs with less human labelling', 'Constitutional AI (Anthropic) uses the model to critique outputs against principles and revise them, reducing dependence on costly human RLHF labelling.', true),
  (t10, 25, 'sandbox', 'mcq', 'In the context of LLM deployment, "quantisation to INT4" means:', '["Using 4 models in parallel","Representing model weights with 4-bit integers instead of 32-bit floats, reducing memory by ~8x with some accuracy loss","Training for 4 epochs","Using 4 attention heads"]', 'Representing model weights with 4-bit integers instead of 32-bit floats, reducing memory by ~8x with some accuracy loss', 'INT4 quantisation reduces each weight from 32-bit to 4-bit — enabling models like LLaMA-70B to run on consumer hardware.', true),
  (t10, 26, 'sandbox', 'mcq', 'What is a "mixture of experts" (MoE) architecture in LLMs?', '["Combining multiple separate LLMs","Routing each token through a subset of specialised FFN layers (experts) for efficiency — used in models like Mixtral","Using multiple attention heads","Ensemble of completely separate models"]', 'Routing each token through a subset of specialised FFN layers (experts) for efficiency — used in models like Mixtral', 'MoE models activate only k-of-n expert FFN layers per token, giving large model capacity while keeping per-token FLOPs similar to smaller dense models.', true),
  (t10, 27, 'sandbox', 'mcq', 'What does `pipeline("image-to-text", model="Salesforce/blip-image-captioning-base")` do in HuggingFace?', '["Translates text to images","Generates a text caption describing an input image","Classifies images","Detects objects in images"]', 'Generates a text caption describing an input image', 'BLIP is a vision-language model. The image-to-text pipeline runs it to generate natural language descriptions of input images.', true),
  (t10, 28, 'sandbox', 'mcq', 'What is "in-context learning" (ICL) in LLMs?', '["Training the model during inference","The ability to adapt behaviour using examples provided in the prompt without any gradient updates","Caching intermediate computations","Multi-turn conversation memory"]', 'The ability to adapt behaviour using examples provided in the prompt without any gradient updates', 'ICL is a remarkable LLM property: a few examples in the context window shape the model''s behaviour without changing any weights.', true),
  (t10, 29, 'sandbox', 'mcq', 'Diffusion models for text generation face a challenge compared to image diffusion because:', '["Text is longer","Text is discrete (tokens), not continuous — standard diffusion on continuous data doesn''t directly apply","Text requires colour channels","Text models need more GPU"]', 'Text is discrete (tokens), not continuous — standard diffusion on continuous data doesn''t directly apply', 'Continuous diffusion works well for images (pixels are continuous). Discrete text tokens require special approaches (absorbing diffusion, latent diffusion over embeddings).', true),
  (t10, 30, 'sandbox', 'mcq', 'What is the purpose of the "safety classifier" layer in deployed LLMs (e.g., OpenAI moderation API)?', '["Speed up generation","Filter input prompts and/or model outputs to detect and block harmful, unsafe, or policy-violating content","Improve accuracy","Reduce token count"]', 'Filter input prompts and/or model outputs to detect and block harmful, unsafe, or policy-violating content', 'Safety classifiers run alongside the LLM to detect harmful requests or outputs, adding a content safety layer beyond RLHF alignment.', true),
  (t10, 31, 'sandbox', 'mcq', 'What is "chain-of-thought" (CoT) prompting''s key mechanism?', '["Linking separate API calls","Eliciting step-by-step reasoning tokens before the final answer — intermediate steps guide the model to correct solutions","Connecting multiple models","Using tree-of-thought"]', 'Eliciting step-by-step reasoning tokens before the final answer — intermediate steps guide the model to correct solutions', 'CoT reasoning occupies context with intermediate tokens that "prime" correct logical steps, significantly improving multi-step reasoning accuracy.', true),
  (t10, 32, 'sandbox', 'mcq', 'What is "prefix tuning" as a parameter-efficient fine-tuning (PEFT) method?', '["Adding prefixes to training data","Prepending trainable continuous vectors (virtual tokens) to the input sequence while keeping the LLM frozen","Fine-tuning only the first layer","Truncating input sequences"]', 'Prepending trainable continuous vectors (virtual tokens) to the input sequence while keeping the LLM frozen', 'Prefix tuning learns soft prompts in the embedding space that steer the frozen LLM''s behaviour — training only the prefix parameters (<0.1% of parameters).', true),
  (t10, 33, 'sandbox', 'mcq', 'The "BLEU-4" score in text generation evaluation measures:', '["Semantic similarity","Precision of 4-gram matches between generated and reference text, with brevity penalty","Only unigram matches","Recall of reference text"]', 'Precision of 4-gram matches between generated and reference text, with brevity penalty', 'BLEU-4 computes precision of up to 4-gram overlaps between hypothesis and references, penalising too-short outputs.', true),
  (t10, 34, 'sandbox', 'mcq', 'What is "token healing" in LLM text generation?', '["Fixing hallucinated tokens","Backtracking on partial final tokens at boundaries to prevent sub-optimal tokenisation at generation start","Error correction for misspellings","Re-ranking generated outputs"]', 'Backtracking on partial final tokens at boundaries to prevent sub-optimal tokenisation at generation start', 'Token healing addresses tokenisation boundary issues where a partial word at the prompt end causes the model to generate a suboptimal continuation.', true),
  (t10, 35, 'sandbox', 'mcq', 'What distinguishes RLHF-trained models from instruction-tuned (SFT-only) models in practice?', '["RLHF models are always larger","RLHF adds preference learning from human comparisons on top of SFT, producing outputs better aligned with what humans prefer over just imitation","SFT is more advanced","They are equivalent"]', 'RLHF adds preference learning from human comparisons on top of SFT, producing outputs better aligned with what humans prefer over just imitation', 'SFT teaches format/style via demonstrations. RLHF additionally optimises for human preference — more helpful, less harmful, more honest responses.', true);
